/* ============================================================
 * Helper: read a procfs sysctl file and return length (< 0 on error)
 * ============================================================ */
static ssize_t read_sysctl(const char *path, char *buf, size_t bufsz) {
    int fd = fut_vfs_open(path, 0, 0);
    if (fd < 0) return fd;
    ssize_t n = fut_vfs_read(fd, buf, bufsz - 1);
    fut_vfs_close(fd);
    if (n > 0) buf[n] = '\0';
    return n;
}

