/**
 * test_sockopt_linger_setown - Tests 744-747
 *
 *   Test 744: SO_LINGER setsockopt/getsockopt round-trip (l_onoff=1, l_linger=5)
 *   Test 745: SO_LINGER clear (l_onoff=0) round-trip
 *   Test 746: F_SETOWN/F_GETOWN round-trip (store and retrieve owner PID)
 *   Test 747: poll(POLLOUT) on fresh connected socketpair → immediately writable
 */
static void test_sockopt_linger_setown(void) {
    extern long sys_socket(int domain, int type, int protocol);
    extern long sys_setsockopt(int fd, int level, int optname,
                               const void *optval, unsigned int optlen);
    extern long sys_getsockopt(int fd, int level, int optname,
                               void *optval, unsigned int *optlen);
    extern long sys_fcntl(int fd, int cmd, uint64_t arg);
    extern long sys_getpid(void);
    extern long sys_socketpair(int domain, int type, int protocol, int *sv);

#define T744_SOL_SOCKET 1
#define T744_SO_LINGER  13
#define T744_F_SETOWN   8
#define T744_F_GETOWN   9
#define T744_POLLIN     0x0001
#define T744_POLLOUT    0x0004

    long s = sys_socket(1 /* AF_UNIX */, 1 /* SOCK_STREAM */, 0);
    if (s < 0) {
        fut_printf("[MISC-TEST] ✗ Tests 744-747: socket failed: %ld\n", s);
        fut_test_fail(744); fut_test_fail(745);
        fut_test_fail(746); fut_test_fail(747);
        return;
    }

    struct { int l_onoff; int l_linger; } ling, got_ling;
    unsigned int glen;

    /* Test 744: SO_LINGER l_onoff=1 l_linger=5 round-trip */
    fut_printf("[MISC-TEST] Test 744: SO_LINGER(l_onoff=1, l_linger=5) round-trip\n");
    ling.l_onoff = 1; ling.l_linger = 5;
    long r = sys_setsockopt((int)s, T744_SOL_SOCKET, T744_SO_LINGER,
                            &ling, sizeof(ling));
    if (r != 0) {
        fut_printf("[MISC-TEST] ✗ Test 744: setsockopt(SO_LINGER) returned %ld\n", r);
        fut_test_fail(744);
    } else {
        __builtin_memset(&got_ling, 0, sizeof(got_ling));
        glen = sizeof(got_ling);
        r = sys_getsockopt((int)s, T744_SOL_SOCKET, T744_SO_LINGER, &got_ling, &glen);
        if (r != 0 || got_ling.l_onoff != 1 || got_ling.l_linger != 5) {
            fut_printf("[MISC-TEST] ✗ Test 744: getsockopt l_onoff=%d l_linger=%d\n",
                       got_ling.l_onoff, got_ling.l_linger);
            fut_test_fail(744);
        } else {
            fut_printf("[MISC-TEST] ✓ Test 744: SO_LINGER(1,5) round-trip\n");
            fut_test_pass();
        }
    }

    /* Test 745: SO_LINGER clear (l_onoff=0) */
    fut_printf("[MISC-TEST] Test 745: SO_LINGER clear (l_onoff=0)\n");
    ling.l_onoff = 0; ling.l_linger = 0;
    r = sys_setsockopt((int)s, T744_SOL_SOCKET, T744_SO_LINGER,
                       &ling, sizeof(ling));
    if (r != 0) {
        fut_printf("[MISC-TEST] ✗ Test 745: setsockopt(SO_LINGER, 0) returned %ld\n", r);
        fut_test_fail(745);
    } else {
        __builtin_memset(&got_ling, 0xff, sizeof(got_ling));
        glen = sizeof(got_ling);
        r = sys_getsockopt((int)s, T744_SOL_SOCKET, T744_SO_LINGER, &got_ling, &glen);
        if (r != 0 || got_ling.l_onoff != 0 || got_ling.l_linger != 0) {
            fut_printf("[MISC-TEST] ✗ Test 745: getsockopt l_onoff=%d l_linger=%d\n",
                       got_ling.l_onoff, got_ling.l_linger);
            fut_test_fail(745);
        } else {
            fut_printf("[MISC-TEST] ✓ Test 745: SO_LINGER cleared to (0,0)\n");
            fut_test_pass();
        }
    }
    fut_vfs_close((int)s);

    /* Test 746: F_SETOWN/F_GETOWN round-trip */
    fut_printf("[MISC-TEST] Test 746: F_SETOWN/F_GETOWN round-trip\n");
    int fd = fut_vfs_open("/tmp/setown_test_746.txt", O_CREAT | O_RDWR, 0644);
    if (fd < 0) {
        fut_printf("[MISC-TEST] ✗ Test 746: open failed: %d\n", fd);
        fut_test_fail(746);
    } else {
        long pid = sys_getpid();
        r = sys_fcntl(fd, T744_F_SETOWN, (uint64_t)pid);
        if (r != 0) {
            fut_printf("[MISC-TEST] ✗ Test 746: F_SETOWN returned %ld\n", r);
            fut_test_fail(746);
        } else {
            long owner = sys_fcntl(fd, T744_F_GETOWN, 0);
            if (owner != pid) {
                fut_printf("[MISC-TEST] ✗ Test 746: F_GETOWN=%ld expected %ld\n", owner, pid);
                fut_test_fail(746);
            } else {
                fut_printf("[MISC-TEST] ✓ Test 746: F_SETOWN/F_GETOWN pid=%ld\n", owner);
                fut_test_pass();
            }
        }
        fut_vfs_close(fd);
        fut_vfs_unlink("/tmp/setown_test_746.txt");
    }

    /* Test 747: poll(POLLOUT) on fresh connected socketpair → writable immediately */
    fut_printf("[MISC-TEST] Test 747: poll(POLLOUT) on fresh socketpair → immediately writable\n");
    struct { int fd; short events; short revents; } pfd;
    int sv[2] = {-1, -1};
    r = sys_socketpair(1, 1, 0, sv);
    if (r != 0 || sv[0] < 0) {
        fut_printf("[MISC-TEST] ✗ Test 747: socketpair failed: %ld\n", r);
        fut_test_fail(747);
        return;
    }
    pfd.fd = sv[0]; pfd.events = (short)T744_POLLOUT; pfd.revents = 0;
    extern long sys_poll(struct pollfd *fds, unsigned long nfds, int timeout);
    r = sys_poll((struct pollfd *)&pfd, 1, 0 /* nowait */);
    fut_vfs_close(sv[0]); fut_vfs_close(sv[1]);
    if (r != 1 || !(pfd.revents & (short)T744_POLLOUT)) {
        fut_printf("[MISC-TEST] ✗ Test 747: poll returned %ld revents=0x%x\n",
                   r, (unsigned)pfd.revents);
        fut_test_fail(747);
    } else {
        fut_printf("[MISC-TEST] ✓ Test 747: poll(POLLOUT) socketpair immediately writable\n");
        fut_test_pass();
    }

#undef T744_SOL_SOCKET
#undef T744_SO_LINGER
#undef T744_F_SETOWN
#undef T744_F_GETOWN
#undef T744_POLLIN
#undef T744_POLLOUT
}

/**
 * test_sockopt_bool_roundtrip - Tests 740-743
 *
 *   Test 740: setsockopt(SO_REUSEADDR, 1) → getsockopt → 1
 *   Test 741: setsockopt(SO_KEEPALIVE, 1) → getsockopt → 1
 *   Test 742: setsockopt(SO_REUSEADDR, 0) clears it → getsockopt → 0
 *   Test 743: setsockopt(SO_BROADCAST, 1) → getsockopt → 1
 */
static void test_sockopt_bool_roundtrip(void) {
    extern long sys_socket(int domain, int type, int protocol);
    extern long sys_setsockopt(int fd, int level, int optname,
                               const void *optval, unsigned int optlen);
    extern long sys_getsockopt(int fd, int level, int optname,
                               void *optval, unsigned int *optlen);

#define T740_SOL_SOCKET  1
#define T740_SO_REUSEADDR 2
#define T740_SO_KEEPALIVE 9
#define T740_SO_BROADCAST 6

    long s = sys_socket(1 /* AF_UNIX */, 1 /* SOCK_STREAM */, 0);
    if (s < 0) {
        fut_printf("[MISC-TEST] ✗ Tests 740-743: socket failed: %ld\n", s);
        fut_test_fail(740); fut_test_fail(741);
        fut_test_fail(742); fut_test_fail(743);
        return;
    }

    int enable = 1, got = -1;
    unsigned int glen = sizeof(int);

    /* Test 740: SO_REUSEADDR set → get = 1 */
    fut_printf("[MISC-TEST] Test 740: setsockopt/getsockopt SO_REUSEADDR round-trip\n");
    long r = sys_setsockopt((int)s, T740_SOL_SOCKET, T740_SO_REUSEADDR,
                            &enable, sizeof(int));
    if (r != 0) {
        fut_printf("[MISC-TEST] ✗ Test 740: setsockopt(SO_REUSEADDR) returned %ld\n", r);
        fut_test_fail(740);
    } else {
        got = -1; glen = sizeof(int);
        r = sys_getsockopt((int)s, T740_SOL_SOCKET, T740_SO_REUSEADDR, &got, &glen);
        if (r != 0 || got != 1) {
            fut_printf("[MISC-TEST] ✗ Test 740: getsockopt(SO_REUSEADDR) r=%ld got=%d\n", r, got);
            fut_test_fail(740);
        } else {
            fut_printf("[MISC-TEST] ✓ Test 740: SO_REUSEADDR=1 round-trip\n");
            fut_test_pass();
        }
    }

    /* Test 741: SO_KEEPALIVE set → get = 1 */
    fut_printf("[MISC-TEST] Test 741: setsockopt/getsockopt SO_KEEPALIVE round-trip\n");
    r = sys_setsockopt((int)s, T740_SOL_SOCKET, T740_SO_KEEPALIVE,
                       &enable, sizeof(int));
    if (r != 0) {
        fut_printf("[MISC-TEST] ✗ Test 741: setsockopt(SO_KEEPALIVE) returned %ld\n", r);
        fut_test_fail(741);
    } else {
        got = -1; glen = sizeof(int);
        r = sys_getsockopt((int)s, T740_SOL_SOCKET, T740_SO_KEEPALIVE, &got, &glen);
        if (r != 0 || got != 1) {
            fut_printf("[MISC-TEST] ✗ Test 741: getsockopt(SO_KEEPALIVE) r=%ld got=%d\n", r, got);
            fut_test_fail(741);
        } else {
            fut_printf("[MISC-TEST] ✓ Test 741: SO_KEEPALIVE=1 round-trip\n");
            fut_test_pass();
        }
    }

    /* Test 742: clear SO_REUSEADDR → get = 0 */
    fut_printf("[MISC-TEST] Test 742: setsockopt(SO_REUSEADDR, 0) clears flag\n");
    int zero = 0;
    r = sys_setsockopt((int)s, T740_SOL_SOCKET, T740_SO_REUSEADDR,
                       &zero, sizeof(int));
    if (r != 0) {
        fut_printf("[MISC-TEST] ✗ Test 742: setsockopt(SO_REUSEADDR, 0) returned %ld\n", r);
        fut_test_fail(742);
    } else {
        got = -1; glen = sizeof(int);
        r = sys_getsockopt((int)s, T740_SOL_SOCKET, T740_SO_REUSEADDR, &got, &glen);
        if (r != 0 || got != 0) {
            fut_printf("[MISC-TEST] ✗ Test 742: getsockopt(SO_REUSEADDR) r=%ld got=%d (want 0)\n",
                       r, got);
            fut_test_fail(742);
        } else {
            fut_printf("[MISC-TEST] ✓ Test 742: SO_REUSEADDR cleared to 0\n");
            fut_test_pass();
        }
    }

    /* Test 743: SO_BROADCAST set → get = 1 */
    fut_printf("[MISC-TEST] Test 743: setsockopt/getsockopt SO_BROADCAST round-trip\n");
    r = sys_setsockopt((int)s, T740_SOL_SOCKET, T740_SO_BROADCAST,
                       &enable, sizeof(int));
    if (r != 0) {
        fut_printf("[MISC-TEST] ✗ Test 743: setsockopt(SO_BROADCAST) returned %ld\n", r);
        fut_test_fail(743);
    } else {
        got = -1; glen = sizeof(int);
        r = sys_getsockopt((int)s, T740_SOL_SOCKET, T740_SO_BROADCAST, &got, &glen);
        if (r != 0 || got != 1) {
            fut_printf("[MISC-TEST] ✗ Test 743: getsockopt(SO_BROADCAST) r=%ld got=%d\n", r, got);
            fut_test_fail(743);
        } else {
            fut_printf("[MISC-TEST] ✓ Test 743: SO_BROADCAST=1 round-trip\n");
            fut_test_pass();
        }
    }

    fut_vfs_close((int)s);
#undef T740_SOL_SOCKET
#undef T740_SO_REUSEADDR
#undef T740_SO_KEEPALIVE
#undef T740_SO_BROADCAST
}

/**
 * test_kill_pgrp_sig0 - Tests 748-750
 *
 *   Test 748: kill(0, 0)  → 0 (own process group exists)
 *   Test 749: kill(-pgid, 0) where pgid = getpgid(0) → 0 (group exists)
 *   Test 750: kill(-999998, 0) → ESRCH (no such process group)
 */
static void test_kill_pgrp_sig0(void) {
    extern long sys_kill(int pid, int sig);
    extern long sys_getpgid(uint64_t pid);

    /* Test 748: kill(0, 0) — signal to own process group (existence check) */
    fut_printf("[MISC-TEST] Test 748: kill(0, 0) → own process group exists\n");
    long r = sys_kill(0, 0);
    if (r != 0) {
        fut_printf("[MISC-TEST] ✗ Test 748: kill(0, 0) returned %ld (expected 0)\n", r);
        fut_test_fail(748);
    } else {
        fut_printf("[MISC-TEST] ✓ Test 748: kill(0, 0) → 0\n");
        fut_test_pass();
    }

    /* Test 749: kill(-pgid, 0) — our own pgid as negative argument */
    fut_printf("[MISC-TEST] Test 749: kill(-pgid, 0) for self pgid → 0\n");
    long pgid = sys_getpgid(0);
    if (pgid <= 0) {
        fut_printf("[MISC-TEST] ✗ Test 749: getpgid(0) returned %ld\n", pgid);
        fut_test_fail(749);
    } else {
        r = sys_kill((int)(-pgid), 0);
        if (r != 0) {
            fut_printf("[MISC-TEST] ✗ Test 749: kill(-%ld, 0) returned %ld (expected 0)\n",
                       pgid, r);
            fut_test_fail(749);
        } else {
            fut_printf("[MISC-TEST] ✓ Test 749: kill(-%ld, 0) → 0\n", pgid);
            fut_test_pass();
        }
    }

    /* Test 750: kill(-999998, 0) — nonexistent process group → ESRCH */
    fut_printf("[MISC-TEST] Test 750: kill(-999998, 0) → ESRCH\n");
    r = sys_kill(-999998, 0);
    if (r != -ESRCH) {
        fut_printf("[MISC-TEST] ✗ Test 750: kill(-999998, 0) returned %ld (expected -ESRCH=%d)\n",
                   r, -ESRCH);
        fut_test_fail(750);
    } else {
        fut_printf("[MISC-TEST] ✓ Test 750: kill(-999998, 0) → ESRCH\n");
        fut_test_pass();
    }
}

/**
 * test_prlimit_other_pid - Tests 751-753
 *
 *   Test 751: prlimit64(self_pid, RLIMIT_NOFILE, NULL, &old) → 0, limits match pid=0
 *   Test 752: prlimit64(999999, RLIMIT_NOFILE, NULL, &old)  → ESRCH
 *   Test 753: prlimit64(self_pid, RLIMIT_STACK, NULL, &old) → 0, cur/max > 0
 */
static void test_prlimit_other_pid(void) {
    extern long sys_prlimit64(int pid, int resource,
                               const void *new_limit, void *old_limit);
    extern long sys_getpid(void);

    struct { uint64_t rlim_cur; uint64_t rlim_max; } old0 = {0, 0}, oldp = {0, 0};

#define T751_RLIMIT_NOFILE 7
#define T751_RLIMIT_STACK  3

    /* Test 751: prlimit64(self_pid, RLIMIT_NOFILE) matches prlimit64(0, RLIMIT_NOFILE) */
    fut_printf("[MISC-TEST] Test 751: prlimit64(self_pid, RLIMIT_NOFILE) matches pid=0 query\n");
    long self_pid = sys_getpid();

    long r0 = sys_prlimit64(0, T751_RLIMIT_NOFILE, NULL, &old0);
    long rp = sys_prlimit64((int)self_pid, T751_RLIMIT_NOFILE, NULL, &oldp);
    if (r0 != 0 || rp != 0) {
        fut_printf("[MISC-TEST] ✗ Test 751: prlimit64 returned r0=%ld rp=%ld\n", r0, rp);
        fut_test_fail(751);
    } else if (old0.rlim_cur != oldp.rlim_cur || old0.rlim_max != oldp.rlim_max) {
        fut_printf("[MISC-TEST] ✗ Test 751: pid=0 cur=%llu max=%llu, pid=%ld cur=%llu max=%llu\n",
                   (unsigned long long)old0.rlim_cur, (unsigned long long)old0.rlim_max,
                   self_pid,
                   (unsigned long long)oldp.rlim_cur, (unsigned long long)oldp.rlim_max);
        fut_test_fail(751);
    } else {
        fut_printf("[MISC-TEST] ✓ Test 751: prlimit64(self_pid) matches pid=0: cur=%llu\n",
                   (unsigned long long)oldp.rlim_cur);
        fut_test_pass();
    }

    /* Test 752: prlimit64(nonexistent_pid) → ESRCH */
    fut_printf("[MISC-TEST] Test 752: prlimit64(999999, RLIMIT_NOFILE) → ESRCH\n");
    struct { uint64_t rlim_cur; uint64_t rlim_max; } esrch_buf = {0, 0};
    long re = sys_prlimit64(999999, T751_RLIMIT_NOFILE, NULL, &esrch_buf);
    if (re != -ESRCH) {
        fut_printf("[MISC-TEST] ✗ Test 752: prlimit64(999999) returned %ld (expected -ESRCH=%d)\n",
                   re, -ESRCH);
        fut_test_fail(752);
    } else {
        fut_printf("[MISC-TEST] ✓ Test 752: prlimit64(999999) → ESRCH\n");
        fut_test_pass();
    }

    /* Test 753: prlimit64(self_pid, RLIMIT_STACK) → sane cur/max */
    fut_printf("[MISC-TEST] Test 753: prlimit64(self_pid, RLIMIT_STACK) → sane limits\n");
    struct { uint64_t rlim_cur; uint64_t rlim_max; } stk = {0, 0};
    long rs = sys_prlimit64((int)self_pid, T751_RLIMIT_STACK, NULL, &stk);
    if (rs != 0) {
        fut_printf("[MISC-TEST] ✗ Test 753: prlimit64(RLIMIT_STACK) returned %ld\n", rs);
        fut_test_fail(753);
    } else if (stk.rlim_cur == 0 && stk.rlim_max == 0) {
        fut_printf("[MISC-TEST] ✗ Test 753: RLIMIT_STACK cur=0 max=0 (unexpected)\n");
        fut_test_fail(753);
    } else {
        fut_printf("[MISC-TEST] ✓ Test 753: RLIMIT_STACK cur=%llu max=%llu\n",
                   (unsigned long long)stk.rlim_cur, (unsigned long long)stk.rlim_max);
        fut_test_pass();
    }

#undef T751_RLIMIT_NOFILE
#undef T751_RLIMIT_STACK
}

/**
 * test_fstat_special_fds - Tests 754-757
 *
 * Verify that fstat() returns the correct Linux st_mode type bits for
 * anonymous (vnode-less) file descriptors:
 *   Test 754: fstat(pipe_read_fd)  → st_mode type = S_IFIFO  (0010000)
 *   Test 755: fstat(socket_fd)     → st_mode type = S_IFSOCK (0140000)
 *   Test 756: fstat(eventfd)       → st_mode type = S_IFCHR  (0020000)
 *   Test 757: fstat(timerfd)       → st_mode type = S_IFREG  (0100000)
 */
static void test_fstat_special_fds(void) {
    extern long sys_fstat(int fd, struct fut_stat *statbuf);
    extern long sys_pipe(int pipefd[2]);
    extern long sys_socket(int domain, int type, int protocol);
    extern long sys_eventfd2(unsigned int initval, int flags);
    extern long sys_timerfd_create(int clockid, int flags);

    struct fut_stat st;

#define T754_S_IFMT   0170000u
#define T754_S_IFIFO  0010000u
#define T754_S_IFSOCK 0140000u
#define T754_S_IFCHR  0020000u
#define T754_S_IFREG  0100000u

    /* Test 754: pipe read fd → S_IFIFO */
    fut_printf("[MISC-TEST] Test 754: fstat(pipe_read_fd) → S_IFIFO\n");
    {
        int pfd[2] = {-1, -1};
        long r = sys_pipe(pfd);
        if (r != 0 || pfd[0] < 0) {
            fut_printf("[MISC-TEST] ✗ Test 754: pipe() failed: %ld\n", r);
            fut_test_fail(754);
        } else {
            __builtin_memset(&st, 0, sizeof(st));
            r = sys_fstat(pfd[0], &st);
            sys_close(pfd[0]); sys_close(pfd[1]);
            if (r != 0) {
                fut_printf("[MISC-TEST] ✗ Test 754: fstat failed: %ld\n", r);
                fut_test_fail(754);
            } else if ((st.st_mode & T754_S_IFMT) != T754_S_IFIFO) {
                fut_printf("[MISC-TEST] ✗ Test 754: st_mode=0%o, want S_IFIFO\n", st.st_mode);
                fut_test_fail(754);
            } else {
                fut_printf("[MISC-TEST] ✓ Test 754: pipe fstat st_mode=0%o (S_IFIFO)\n",
                           st.st_mode);
                fut_test_pass();
            }
        }
    }

    /* Test 755: AF_UNIX socket fd → S_IFSOCK */
    fut_printf("[MISC-TEST] Test 755: fstat(socket_fd) → S_IFSOCK\n");
    {
        long s = sys_socket(1 /* AF_UNIX */, 1 /* SOCK_STREAM */, 0);
        if (s < 0) {
            fut_printf("[MISC-TEST] ✗ Test 755: socket() failed: %ld\n", s);
            fut_test_fail(755);
        } else {
            __builtin_memset(&st, 0, sizeof(st));
            long r = sys_fstat((int)s, &st);
            sys_close((int)s);
            if (r != 0) {
                fut_printf("[MISC-TEST] ✗ Test 755: fstat failed: %ld\n", r);
                fut_test_fail(755);
            } else if ((st.st_mode & T754_S_IFMT) != T754_S_IFSOCK) {
                fut_printf("[MISC-TEST] ✗ Test 755: st_mode=0%o, want S_IFSOCK\n", st.st_mode);
                fut_test_fail(755);
            } else {
                fut_printf("[MISC-TEST] ✓ Test 755: socket fstat st_mode=0%o (S_IFSOCK)\n",
                           st.st_mode);
                fut_test_pass();
            }
        }
    }

    /* Test 756: eventfd → S_IFCHR */
    fut_printf("[MISC-TEST] Test 756: fstat(eventfd) → S_IFCHR\n");
    {
        long efd = sys_eventfd2(0, 0);
        if (efd < 0) {
            fut_printf("[MISC-TEST] ✗ Test 756: eventfd2() failed: %ld\n", efd);
            fut_test_fail(756);
        } else {
            __builtin_memset(&st, 0, sizeof(st));
            long r = sys_fstat((int)efd, &st);
            sys_close((int)efd);
            if (r != 0) {
                fut_printf("[MISC-TEST] ✗ Test 756: fstat failed: %ld\n", r);
                fut_test_fail(756);
            } else if ((st.st_mode & T754_S_IFMT) != T754_S_IFCHR) {
                fut_printf("[MISC-TEST] ✗ Test 756: st_mode=0%o, want S_IFCHR\n", st.st_mode);
                fut_test_fail(756);
            } else {
                fut_printf("[MISC-TEST] ✓ Test 756: eventfd fstat st_mode=0%o (S_IFCHR)\n",
                           st.st_mode);
                fut_test_pass();
            }
        }
    }

    /* Test 757: timerfd → S_IFREG (anon_inode) */
    fut_printf("[MISC-TEST] Test 757: fstat(timerfd) → S_IFREG\n");
    {
        long tfd = sys_timerfd_create(1 /* CLOCK_MONOTONIC */, 0);
        if (tfd < 0) {
            fut_printf("[MISC-TEST] ✗ Test 757: timerfd_create() failed: %ld\n", tfd);
            fut_test_fail(757);
        } else {
            __builtin_memset(&st, 0, sizeof(st));
            long r = sys_fstat((int)tfd, &st);
            sys_close((int)tfd);
            if (r != 0) {
                fut_printf("[MISC-TEST] ✗ Test 757: fstat failed: %ld\n", r);
                fut_test_fail(757);
            } else if ((st.st_mode & T754_S_IFMT) != T754_S_IFREG) {
                fut_printf("[MISC-TEST] ✗ Test 757: st_mode=0%o, want S_IFREG\n", st.st_mode);
                fut_test_fail(757);
            } else {
                fut_printf("[MISC-TEST] ✓ Test 757: timerfd fstat st_mode=0%o (S_IFREG)\n",
                           st.st_mode);
                fut_test_pass();
            }
        }
    }

#undef T754_S_IFMT
#undef T754_S_IFIFO
#undef T754_S_IFSOCK
#undef T754_S_IFCHR
#undef T754_S_IFREG
}

/**
 * test_fstat_signalfd_fstatat_empty - Tests 758-760
 *
 * Test 758: fstat(signalfd) → st_mode type = S_IFREG (anon_inode, like timerfd)
 * Test 759: fstatat(pipe_read_fd, "", AT_EMPTY_PATH) → S_IFIFO (delegates to fstat)
 * Test 760: fstatat(socket_fd,   "", AT_EMPTY_PATH) → S_IFSOCK (delegates to fstat)
 */
static void test_fstat_signalfd_fstatat_empty(void) {
    extern long sys_fstat(int fd, struct fut_stat *statbuf);
    extern long sys_fstatat(int dirfd, const char *pathname,
                            struct fut_stat *statbuf, int flags);
    extern long sys_signalfd4(int ufd, const void *mask, size_t sizemask, int flags);
    extern long sys_pipe(int pipefd[2]);
    extern long sys_socket(int domain, int type, int protocol);

    struct fut_stat st;

#define T758_S_IFMT   0170000u
#define T758_S_IFREG  0100000u
#define T758_S_IFIFO  0010000u
#define T758_S_IFSOCK 0140000u
#ifndef AT_EMPTY_PATH
#define AT_EMPTY_PATH 0x1000
#endif

    /* Test 758: signalfd fstat → S_IFREG */
    fut_printf("[MISC-TEST] Test 758: fstat(signalfd) → S_IFREG\n");
    {
        uint64_t mask758 = 1u << (10 - 1); /* SIGUSR1 = 10 */
        long sfd = sys_signalfd4(-1, &mask758, sizeof(mask758), 0);
        if (sfd < 0) {
            fut_printf("[MISC-TEST] ✗ Test 758: signalfd4 failed: %ld\n", sfd);
            fut_test_fail(758);
        } else {
            __builtin_memset(&st, 0, sizeof(st));
            long r = sys_fstat((int)sfd, &st);
            sys_close((int)sfd);
            if (r != 0) {
                fut_printf("[MISC-TEST] ✗ Test 758: fstat failed: %ld\n", r);
                fut_test_fail(758);
            } else if ((st.st_mode & T758_S_IFMT) != T758_S_IFREG) {
                fut_printf("[MISC-TEST] ✗ Test 758: st_mode=0%o, want S_IFREG (0%o)\n",
                           st.st_mode, T758_S_IFREG);
                fut_test_fail(758);
            } else {
                fut_printf("[MISC-TEST] ✓ Test 758: signalfd fstat st_mode=0%o (S_IFREG)\n",
                           st.st_mode);
                fut_test_pass();
            }
        }
    }

    /* Test 759: fstatat(pipe_read_fd, "", AT_EMPTY_PATH) → S_IFIFO */
    fut_printf("[MISC-TEST] Test 759: fstatat(pipe_read_fd, \"\", AT_EMPTY_PATH) → S_IFIFO\n");
    {
        int pfd[2] = {-1, -1};
        long r = sys_pipe(pfd);
        if (r != 0 || pfd[0] < 0) {
            fut_printf("[MISC-TEST] ✗ Test 759: pipe() failed: %ld\n", r);
            fut_test_fail(759);
        } else {
            __builtin_memset(&st, 0, sizeof(st));
            r = sys_fstatat(pfd[0], "", &st, AT_EMPTY_PATH);
            sys_close(pfd[0]); sys_close(pfd[1]);
            if (r != 0) {
                fut_printf("[MISC-TEST] ✗ Test 759: fstatat AT_EMPTY_PATH failed: %ld\n", r);
                fut_test_fail(759);
            } else if ((st.st_mode & T758_S_IFMT) != T758_S_IFIFO) {
                fut_printf("[MISC-TEST] ✗ Test 759: st_mode=0%o, want S_IFIFO (0%o)\n",
                           st.st_mode, T758_S_IFIFO);
                fut_test_fail(759);
            } else {
                fut_printf("[MISC-TEST] ✓ Test 759: fstatat AT_EMPTY_PATH pipe st_mode=0%o (S_IFIFO)\n",
                           st.st_mode);
                fut_test_pass();
            }
        }
    }

    /* Test 760: fstatat(socket_fd, "", AT_EMPTY_PATH) → S_IFSOCK */
    fut_printf("[MISC-TEST] Test 760: fstatat(socket_fd, \"\", AT_EMPTY_PATH) → S_IFSOCK\n");
    {
        long s = sys_socket(1 /* AF_UNIX */, 1 /* SOCK_STREAM */, 0);
        if (s < 0) {
            fut_printf("[MISC-TEST] ✗ Test 760: socket() failed: %ld\n", s);
            fut_test_fail(760);
        } else {
            __builtin_memset(&st, 0, sizeof(st));
            long r = sys_fstatat((int)s, "", &st, AT_EMPTY_PATH);
            sys_close((int)s);
            if (r != 0) {
                fut_printf("[MISC-TEST] ✗ Test 760: fstatat AT_EMPTY_PATH failed: %ld\n", r);
                fut_test_fail(760);
            } else if ((st.st_mode & T758_S_IFMT) != T758_S_IFSOCK) {
                fut_printf("[MISC-TEST] ✗ Test 760: st_mode=0%o, want S_IFSOCK (0%o)\n",
                           st.st_mode, T758_S_IFSOCK);
                fut_test_fail(760);
            } else {
                fut_printf("[MISC-TEST] ✓ Test 760: fstatat AT_EMPTY_PATH socket st_mode=0%o (S_IFSOCK)\n",
                           st.st_mode);
                fut_test_pass();
            }
        }
    }

#undef T758_S_IFMT
#undef T758_S_IFREG
#undef T758_S_IFIFO
#undef T758_S_IFSOCK
}

/**
 * test_memfd_sealing - Tests 761-765, 1266
 *
 * Test 761: F_GET_SEALS on memfd without MFD_ALLOW_SEALING → EPERM
 * Test 762: F_ADD_SEALS on memfd without MFD_ALLOW_SEALING → EPERM;
 *           F_ADD_SEALS(F_SEAL_WRITE) on MFD_ALLOW_SEALING memfd → 0,
 *           then write → EPERM (seal enforced)
 * Test 763: F_ADD_SEALS(F_SEAL_SEAL) prevents further F_ADD_SEALS
 * Test 764: F_ADD_SEALS(F_SEAL_SHRINK) prevents ftruncate shrink
 * Test 1266: F_SEAL_FUTURE_WRITE prevents write() but allows ftruncate
 */
static void test_memfd_sealing(void) {
    extern long sys_memfd_create(const char *uname, unsigned int flags);
    extern long sys_fcntl(int fd, int cmd, uint64_t arg);
    extern long sys_ftruncate(int fd, uint64_t length);
    extern ssize_t sys_write(int fd, const void *buf, size_t count);

#define MFD_ALLOW_SEALING_761 0x0002U
#define F_GET_SEALS_761   1034
#define F_ADD_SEALS_761   1033
#define F_SEAL_SEAL_761   0x0001U
#define F_SEAL_SHRINK_761 0x0002U
#define F_SEAL_WRITE_761  0x0008U

    /* Test 761: F_GET_SEALS on non-sealing memfd → EPERM */
    fut_printf("[MISC-TEST] Test 761: F_GET_SEALS without MFD_ALLOW_SEALING → EPERM\n");
    {
        long fd = sys_memfd_create("notseal", 0 /* no MFD_ALLOW_SEALING */);
        if (fd < 0) {
            fut_printf("[MISC-TEST] ✗ Test 761: memfd_create failed: %ld\n", fd);
            fut_test_fail(761);
        } else {
            long r = sys_fcntl((int)fd, F_GET_SEALS_761, 0);
            sys_close((int)fd);
            if (r != -EPERM) {
                fut_printf("[MISC-TEST] ✗ Test 761: F_GET_SEALS returned %ld, want EPERM\n", r);
                fut_test_fail(761);
            } else {
                fut_printf("[MISC-TEST] ✓ Test 761: F_GET_SEALS without MFD_ALLOW_SEALING → EPERM\n");
                fut_test_pass();
            }
        }
    }

    /* Test 762: F_ADD_SEALS(F_SEAL_WRITE) on MFD_ALLOW_SEALING memfd enforces write denial */
    fut_printf("[MISC-TEST] Test 762: F_ADD_SEALS(F_SEAL_WRITE) prevents writes\n");
    {
        long fd = sys_memfd_create("sealtest", MFD_ALLOW_SEALING_761);
        if (fd < 0) {
            fut_printf("[MISC-TEST] ✗ Test 762: memfd_create failed: %ld\n", fd);
            fut_test_fail(762);
        } else {
            /* Initially 0 seals */
            long seals = sys_fcntl((int)fd, F_GET_SEALS_761, 0);
            if (seals != 0) {
                fut_printf("[MISC-TEST] ✗ Test 762: initial seals=%ld, want 0\n", seals);
                fut_test_fail(762);
                sys_close((int)fd);
                goto t763;
            }
            /* Add F_SEAL_WRITE */
            long r = sys_fcntl((int)fd, F_ADD_SEALS_761, (long)F_SEAL_WRITE_761);
            if (r != 0) {
                fut_printf("[MISC-TEST] ✗ Test 762: F_ADD_SEALS returned %ld\n", r);
                fut_test_fail(762);
                sys_close((int)fd);
                goto t763;
            }
            /* Write after sealing → EPERM */
            char buf[4] = "xy";
            long nw = sys_write((int)fd, buf, 2);
            sys_close((int)fd);
            if (nw != -EPERM) {
                fut_printf("[MISC-TEST] ✗ Test 762: write after F_SEAL_WRITE returned %ld, want EPERM\n", nw);
                fut_test_fail(762);
            } else {
                fut_printf("[MISC-TEST] ✓ Test 762: F_SEAL_WRITE enforced: write → EPERM\n");
                fut_test_pass();
            }
        }
    }

t763:
    /* Test 763: F_ADD_SEALS(F_SEAL_SEAL) prevents further sealing */
    fut_printf("[MISC-TEST] Test 763: F_ADD_SEALS(F_SEAL_SEAL) prevents more seals\n");
    {
        long fd = sys_memfd_create("sealtest2", MFD_ALLOW_SEALING_761);
        if (fd < 0) {
            fut_printf("[MISC-TEST] ✗ Test 763: memfd_create failed: %ld\n", fd);
            fut_test_fail(763);
        } else {
            /* Seal the seal list */
            long r = sys_fcntl((int)fd, F_ADD_SEALS_761, (long)F_SEAL_SEAL_761);
            if (r != 0) {
                fut_printf("[MISC-TEST] ✗ Test 763: F_ADD_SEALS(SEAL) returned %ld\n", r);
                fut_test_fail(763);
                sys_close((int)fd);
                goto t764;
            }
            /* Adding more seals now must fail with EPERM */
            long r2 = sys_fcntl((int)fd, F_ADD_SEALS_761, (long)F_SEAL_SHRINK_761);
            sys_close((int)fd);
            if (r2 != -EPERM) {
                fut_printf("[MISC-TEST] ✗ Test 763: F_ADD_SEALS after SEAL_SEAL returned %ld, want EPERM\n", r2);
                fut_test_fail(763);
            } else {
                fut_printf("[MISC-TEST] ✓ Test 763: F_SEAL_SEAL prevents further sealing\n");
                fut_test_pass();
            }
        }
    }

t764:
    /* Test 764: F_ADD_SEALS(F_SEAL_SHRINK) prevents truncating smaller */
    fut_printf("[MISC-TEST] Test 764: F_ADD_SEALS(F_SEAL_SHRINK) prevents shrink\n");
    {
        long fd = sys_memfd_create("sealtest3", MFD_ALLOW_SEALING_761);
        if (fd < 0) {
            fut_printf("[MISC-TEST] ✗ Test 764: memfd_create failed: %ld\n", fd);
            fut_test_fail(764);
        } else {
            /* Extend to 4096 bytes */
            sys_ftruncate((int)fd, 4096);
            /* Seal against shrinking */
            sys_fcntl((int)fd, F_ADD_SEALS_761, (long)F_SEAL_SHRINK_761);
            /* Truncate to smaller → EPERM */
            long r = sys_ftruncate((int)fd, 1024);
            /* Truncate to same size → OK */
            long r2 = sys_ftruncate((int)fd, 4096);
            sys_close((int)fd);
            if (r != -EPERM) {
                fut_printf("[MISC-TEST] ✗ Test 764: ftruncate(shrink) returned %ld, want EPERM\n", r);
                fut_test_fail(764);
            } else if (r2 != 0) {
                fut_printf("[MISC-TEST] ✗ Test 764: ftruncate(same) returned %ld, want 0\n", r2);
                fut_test_fail(764);
            } else {
                fut_printf("[MISC-TEST] ✓ Test 764: F_SEAL_SHRINK prevents shrink, allows same-size\n");
                fut_test_pass();
            }
        }
    }

    /* Test 765: F_SEAL_GROW prevents writes that would extend the memfd */
    fut_printf("[MISC-TEST] Test 765: F_ADD_SEALS(F_SEAL_GROW) prevents extending writes\n");
    {
#define F_SEAL_GROW_761 0x0004U
        long fd = sys_memfd_create("sealtest4", MFD_ALLOW_SEALING_761);
        if (fd < 0) {
            fut_printf("[MISC-TEST] ✗ Test 765: memfd_create failed: %ld\n", fd);
            fut_test_fail(765);
        } else {
            /* Extend to 4 bytes via ftruncate */
            sys_ftruncate((int)fd, 4);
            /* Seal against growth */
            sys_fcntl((int)fd, F_ADD_SEALS_761, (uint64_t)F_SEAL_GROW_761);
            /* Write within bounds → OK (offset 0, 4 bytes into 4-byte file) */
            char buf4[4] = "abcd";
            long nw_ok = sys_write((int)fd, buf4, 4);
            /* Seek past end and write → EPERM */
            /* First seek to end */
            extern int64_t sys_lseek(int fd, int64_t offset, int whence);
            sys_lseek((int)fd, 4, 0 /* SEEK_SET */);
            long nw_bad = sys_write((int)fd, buf4, 1);  /* would grow from 4→5 */
            sys_close((int)fd);
            if (nw_ok != 4) {
                fut_printf("[MISC-TEST] ✗ Test 765: in-bounds write returned %ld, want 4\n", nw_ok);
                fut_test_fail(765);
            } else if (nw_bad != -EPERM) {
                fut_printf("[MISC-TEST] ✗ Test 765: extending write returned %ld, want EPERM\n", nw_bad);
                fut_test_fail(765);
            } else {
                fut_printf("[MISC-TEST] ✓ Test 765: F_SEAL_GROW enforced: in-bounds ok, extend → EPERM\n");
                fut_test_pass();
            }
        }
#undef F_SEAL_GROW_761
    }

    /* Test 1266: F_SEAL_FUTURE_WRITE (0x0010) prevents future write() calls
     * but allows ftruncate (unlike F_SEAL_WRITE which blocks both). */
    fut_printf("[MISC-TEST] Test 1266: F_SEAL_FUTURE_WRITE prevents writes, allows ftruncate\n");
    {
#define F_SEAL_FUTURE_WRITE_1266  0x0010U
        long fd = sys_memfd_create("seal_fw_test", MFD_ALLOW_SEALING_761);
        if (fd < 0) {
            fut_printf("[MISC-TEST] ✗ Test 1266: memfd_create failed (%ld)\n", fd);
            fut_test_fail(1266);
        } else {
            /* Write initial content */
            char buf[4] = {'a', 'b', 'c', 'd'};
            sys_write((int)fd, buf, 4);

            /* Add F_SEAL_FUTURE_WRITE */
            long r = sys_fcntl((int)fd, F_ADD_SEALS_761, (long)F_SEAL_FUTURE_WRITE_1266);
            if (r != 0) {
                fut_printf("[MISC-TEST] ✗ Test 1266: F_ADD_SEALS(F_SEAL_FUTURE_WRITE) → %ld\n", r);
                fut_test_fail(1266);
            } else {
                /* Write must now be rejected */
                long nw = sys_write((int)fd, buf, 4);
                /* ftruncate to same size must succeed (FUTURE_WRITE ≠ SEAL_WRITE) */
                long tr = sys_ftruncate((int)fd, 4);
                sys_close((int)fd);
                if (nw != -EPERM) {
                    fut_printf("[MISC-TEST] ✗ Test 1266: write returned %ld (expected -EPERM)\n", nw);
                    fut_test_fail(1266);
                } else if (tr != 0) {
                    fut_printf("[MISC-TEST] ✗ Test 1266: ftruncate returned %ld (expected 0)\n", tr);
                    fut_test_fail(1266);
                } else {
                    fut_printf("[MISC-TEST] ✓ Test 1266: F_SEAL_FUTURE_WRITE: write→EPERM, ftruncate→0\n");
                    fut_test_pass();
                }
            }
        }
#undef F_SEAL_FUTURE_WRITE_1266
    }

#undef MFD_ALLOW_SEALING_761
#undef F_GET_SEALS_761
#undef F_ADD_SEALS_761
#undef F_SEAL_SEAL_761
#undef F_SEAL_SHRINK_761
#undef F_SEAL_WRITE_761
}

/**
 * test_renameat_atfdcwd - Test 734
 *
 *   Test 734: renameat(AT_FDCWD, old, AT_FDCWD, new) behaves like rename()
 */
static void test_renameat_atfdcwd(void) {
    extern long sys_renameat(int olddirfd, const char *oldpath,
                             int newdirfd, const char *newpath);
    extern long sys_access(const char *pathname, int mode);
#define AT_FDCWD_734 (-100)
#define F_OK_734 0

    fut_printf("[MISC-TEST] Test 734: renameat(AT_FDCWD, ...) → 0\n");

    const char *src = "/tmp/renameat_src_734.txt";
    const char *dst = "/tmp/renameat_dst_734.txt";

    int fd = fut_vfs_open(src, O_CREAT | O_RDWR, 0644);
    if (fd < 0) {
        fut_printf("[MISC-TEST] ✗ Test 734: create failed: %d\n", fd);
        fut_test_fail(734);
        return;
    }
    fut_vfs_write(fd, "hello", 5);
    fut_vfs_close(fd);

    fut_vfs_unlink(dst); /* remove any leftover */

    long r = sys_renameat(AT_FDCWD_734, src, AT_FDCWD_734, dst);
    if (r != 0) {
        fut_printf("[MISC-TEST] ✗ Test 734: renameat returned %ld (expected 0)\n", r);
        fut_test_fail(734);
        fut_vfs_unlink(src);
        return;
    }

    /* src must be gone, dst must exist */
    long src_gone = sys_access(src, F_OK_734);
    long dst_exists = sys_access(dst, F_OK_734);
    fut_vfs_unlink(dst);

    if (src_gone != -ENOENT || dst_exists != 0) {
        fut_printf("[MISC-TEST] ✗ Test 734: src_access=%ld dst_access=%ld\n",
                   src_gone, dst_exists);
        fut_test_fail(734);
        return;
    }
    fut_printf("[MISC-TEST] ✓ Test 734: renameat(AT_FDCWD) → 0, src gone, dst exists\n");
    fut_test_pass();
#undef AT_FDCWD_734
#undef F_OK_734
}

/**
 * test_rename_overwrite - Test 735
 *
 *   Test 735: rename() to an existing file atomically replaces it.
 *   src has "newdata", dst has "olddata". After rename, dst has "newdata".
 */
static void test_rename_overwrite(void) {
    extern long sys_rename(const char *oldpath, const char *newpath);

    fut_printf("[MISC-TEST] Test 735: rename() overwrites existing destination\n");

    const char *src = "/tmp/rename_ow_src_735.txt";
    const char *dst = "/tmp/rename_ow_dst_735.txt";

    int fd = fut_vfs_open(src, O_CREAT | O_RDWR, 0644);
    if (fd < 0) { fut_test_fail(735); return; }
    fut_vfs_write(fd, "newdata", 7);
    fut_vfs_close(fd);

    fd = fut_vfs_open(dst, O_CREAT | O_RDWR, 0644);
    if (fd < 0) { fut_vfs_unlink(src); fut_test_fail(735); return; }
    fut_vfs_write(fd, "olddata", 7);
    fut_vfs_close(fd);

    long r = sys_rename(src, dst);
    if (r != 0) {
        fut_printf("[MISC-TEST] ✗ Test 735: rename returned %ld\n", r);
        fut_vfs_unlink(src); fut_vfs_unlink(dst);
        fut_test_fail(735);
        return;
    }

    /* Read dst — should contain "newdata" */
    char buf[16] = {0};
    fd = fut_vfs_open(dst, O_RDONLY, 0);
    if (fd >= 0) {
        fut_vfs_read(fd, buf, sizeof(buf) - 1);
        fut_vfs_close(fd);
    }
    fut_vfs_unlink(dst);

    if (__builtin_memcmp(buf, "newdata", 7) != 0) {
        fut_printf("[MISC-TEST] ✗ Test 735: dst content wrong: '%s'\n", buf);
        fut_test_fail(735);
        return;
    }
    fut_printf("[MISC-TEST] ✓ Test 735: rename overwrote dst, content='%s'\n", buf);
    fut_test_pass();
}

/**
 * test_ocreat_oexcl_existing - Test 736
 *
 *   Test 736: open(O_CREAT|O_EXCL) on existing file → EEXIST
 */
static void test_ocreat_oexcl_existing(void) {
    fut_printf("[MISC-TEST] Test 736: O_CREAT|O_EXCL on existing file → EEXIST\n");

    const char *path = "/tmp/excl_test_736.txt";
    fut_vfs_unlink(path);

    /* Create the file first */
    int fd = fut_vfs_open(path, O_CREAT | O_RDWR, 0644);
    if (fd < 0) {
        fut_printf("[MISC-TEST] ✗ Test 736: initial create failed: %d\n", fd);
        fut_test_fail(736);
        return;
    }
    fut_vfs_close(fd);

    /* O_CREAT|O_EXCL on existing file must return EEXIST */
    long r = fut_vfs_open(path, O_CREAT | O_EXCL | O_RDWR, 0644);
    fut_vfs_unlink(path);

    if (r != -EEXIST) {
        fut_printf("[MISC-TEST] ✗ Test 736: O_EXCL returned %ld (expected EEXIST)\n", r);
        if (r >= 0) fut_vfs_close((int)r);
        fut_test_fail(736);
        return;
    }
    fut_printf("[MISC-TEST] ✓ Test 736: O_CREAT|O_EXCL on existing → EEXIST\n");
    fut_test_pass();
}

/**
 * test_hardlink_nlinks - Tests 737-739
 *
 *   Test 737: stat after create → st_nlink == 1
 *   Test 738: stat after link()  → st_nlink == 2
 *   Test 739: stat after unlink(link) → st_nlink == 1
 */
static void test_hardlink_nlinks(void) {
    extern long sys_link(const char *oldpath, const char *newpath);
    extern long sys_unlink(const char *path);
    extern long sys_stat(const char *path, struct fut_stat *statbuf);

    fut_printf("[MISC-TEST] Test 737: stat nlink=1 after create\n");

    const char *src = "/tmp/nlink_src_737.txt";
    const char *lnk = "/tmp/nlink_lnk_738.txt";
    fut_vfs_unlink(src);
    fut_vfs_unlink(lnk);

    int fd = fut_vfs_open(src, O_CREAT | O_RDWR, 0644);
    if (fd < 0) {
        fut_printf("[MISC-TEST] ✗ Test 737: create failed: %d\n", fd);
        fut_test_fail(737); fut_test_fail(738); fut_test_fail(739);
        return;
    }
    fut_vfs_close(fd);

    struct fut_stat st = {0};
    long r = sys_stat(src, &st);
    if (r != 0 || st.st_nlink != 1) {
        fut_printf("[MISC-TEST] ✗ Test 737: stat ret=%ld nlink=%u (expected 1)\n",
                   r, st.st_nlink);
        fut_test_fail(737); fut_test_fail(738); fut_test_fail(739);
        fut_vfs_unlink(src);
        return;
    }
    fut_printf("[MISC-TEST] ✓ Test 737: nlink=1 after create\n");
    fut_test_pass();

    /* Test 738: link() increases nlink to 2 */
    fut_printf("[MISC-TEST] Test 738: stat nlink=2 after link()\n");
    r = sys_link(src, lnk);
    if (r != 0) {
        fut_printf("[MISC-TEST] ✗ Test 738: link() returned %ld\n", r);
        fut_test_fail(738); fut_test_fail(739);
        fut_vfs_unlink(src);
        return;
    }
    __builtin_memset(&st, 0, sizeof(st));
    r = sys_stat(src, &st);
    if (r != 0 || st.st_nlink != 2) {
        fut_printf("[MISC-TEST] ✗ Test 738: stat ret=%ld nlink=%u (expected 2)\n",
                   r, st.st_nlink);
        fut_test_fail(738); fut_test_fail(739);
        fut_vfs_unlink(src); fut_vfs_unlink(lnk);
        return;
    }
    fut_printf("[MISC-TEST] ✓ Test 738: nlink=2 after link()\n");
    fut_test_pass();

    /* Test 739: unlink hard link → nlink back to 1, file still readable */
    fut_printf("[MISC-TEST] Test 739: stat nlink=1 after unlink(link)\n");
    r = sys_unlink(lnk);
    if (r != 0) {
        fut_printf("[MISC-TEST] ✗ Test 739: unlink(lnk) returned %ld\n", r);
        fut_test_fail(739);
        fut_vfs_unlink(src); fut_vfs_unlink(lnk);
        return;
    }
    __builtin_memset(&st, 0, sizeof(st));
    r = sys_stat(src, &st);
    if (r != 0 || st.st_nlink != 1) {
        fut_printf("[MISC-TEST] ✗ Test 739: stat ret=%ld nlink=%u (expected 1)\n",
                   r, st.st_nlink);
        fut_test_fail(739);
        fut_vfs_unlink(src);
        return;
    }
    fut_vfs_unlink(src);
    fut_printf("[MISC-TEST] ✓ Test 739: nlink=1 after unlink(link)\n");
    fut_test_pass();
}

