/* ============================================================
 * Tests 766-769: timerfd TFD_TIMER_ABSTIME and ppoll sigmask
 * ============================================================ */

/* itimerspec layout used by timerfd tests */
struct test_itimerspec {
    struct { int64_t tv_sec; long tv_nsec; } it_interval;
    struct { int64_t tv_sec; long tv_nsec; } it_value;
};

/*
 * Test 766: timerfd_settime(TFD_TIMER_ABSTIME, past absolute time) fires ASAP.
 *
 * Setting an absolute time in the past (tv_sec=0, tv_nsec=0 is epoch, always
 * past) must result in the timerfd becoming readable within 1 timer tick (10ms).
 * We confirm with poll(timeout=200ms) → POLLIN.
 */
static void test_timerfd_abstime_past(void) {
    fut_printf("[MISC-TEST] Test 766: timerfd TFD_TIMER_ABSTIME past → fires ASAP\n");

#define TFD_TIMER_ABSTIME_TEST 1

    long tfd = sys_timerfd_create(1 /* CLOCK_MONOTONIC */, 0);
    if (tfd < 0) {
        fut_printf("[MISC-TEST] ✗ Test 766: timerfd_create: %ld\n", tfd);
        fut_test_fail(766);
        return;
    }

    /* Absolute time = {0, 1ns} — epoch+1ns, always in the past for CLOCK_MONOTONIC.
     * Note: {0,0} disarms the timer per POSIX; must use a non-zero it_value. */
    struct test_itimerspec its = {
        .it_interval = { 0, 0 },
        .it_value    = { 0, 1 }   /* 1 nanosecond past epoch — definitely in the past */
    };
    long ret = sys_timerfd_settime((int)tfd, TFD_TIMER_ABSTIME_TEST, &its, NULL);
    if (ret != 0) {
        fut_printf("[MISC-TEST] ✗ Test 766: timerfd_settime(ABSTIME) returned %ld\n", ret);
        fut_vfs_close((int)tfd);
        fut_test_fail(766);
        return;
    }

    /* Block all signals during poll to prevent EINTR from pending test signals */
    extern long sys_sigprocmask(int how, const sigset_t *set, sigset_t *oldset);
    sigset_t full_mask, saved_mask;
    full_mask.__mask = ~0UL;
    sys_sigprocmask(2 /* SIG_SETMASK */, &full_mask, &saved_mask);

    /* poll with 200ms timeout — should fire after ≤1 tick (10ms) */
    struct pollfd pfd = { .fd = (int)tfd, .events = 0x001 /* POLLIN */, .revents = 0 };
    extern long sys_poll(struct pollfd *fds, unsigned long nfds, int timeout);
    long n = sys_poll(&pfd, 1, 200);

    sys_sigprocmask(2, &saved_mask, NULL);  /* restore */

    if (n < 1 || !(pfd.revents & 0x001)) {
        fut_printf("[MISC-TEST] ✗ Test 766: poll returned %ld revents=0x%x (expected POLLIN)\n",
                   n, pfd.revents);
        fut_vfs_close((int)tfd);
        fut_test_fail(766);
        return;
    }

    /* Read confirms expiration count ≥ 1 */
    uint64_t exp = 0;
    ssize_t nr = fut_vfs_read((int)tfd, &exp, sizeof(exp));
    fut_vfs_close((int)tfd);
    if (nr != 8 || exp < 1) {
        fut_printf("[MISC-TEST] ✗ Test 766: timerfd read nr=%zd exp=%llu\n",
                   nr, (unsigned long long)exp);
        fut_test_fail(766);
        return;
    }

    fut_printf("[MISC-TEST] ✓ Test 766: TFD_TIMER_ABSTIME past → fired, exp=%llu\n",
               (unsigned long long)exp);
    fut_test_pass();
}

/*
 * Test 767: timerfd_settime with it_value={0,0} disarms a running timer.
 *
 * Arm a timer for 5 seconds, then immediately disarm it by calling
 * timerfd_settime with it_value={0,0}.  A subsequent poll(timeout=0)
 * must return 0 events and timerfd_gettime must report it_value={0,0}.
 */
static void test_timerfd_disarm(void) {
    fut_printf("[MISC-TEST] Test 767: timerfd_settime({0,0}) disarms timer\n");

    long tfd = sys_timerfd_create(1 /* CLOCK_MONOTONIC */, 0);
    if (tfd < 0) {
        fut_printf("[MISC-TEST] ✗ Test 767: timerfd_create: %ld\n", tfd);
        fut_test_fail(767);
        return;
    }

    /* Arm for 5 seconds — far future so it won't fire */
    struct test_itimerspec arm = {
        .it_interval = { 0, 0 },
        .it_value    = { 5, 0 }
    };
    long ret = sys_timerfd_settime((int)tfd, 0, &arm, NULL);
    if (ret != 0) {
        fut_printf("[MISC-TEST] ✗ Test 767: arm returned %ld\n", ret);
        fut_vfs_close((int)tfd);
        fut_test_fail(767);
        return;
    }

    /* Disarm: it_value = {0, 0} */
    struct test_itimerspec disarm = { .it_interval = { 0, 0 }, .it_value = { 0, 0 } };
    ret = sys_timerfd_settime((int)tfd, 0, &disarm, NULL);
    if (ret != 0) {
        fut_printf("[MISC-TEST] ✗ Test 767: disarm returned %ld\n", ret);
        fut_vfs_close((int)tfd);
        fut_test_fail(767);
        return;
    }

    /* poll(timeout=0): disarmed timer must not be readable */
    struct pollfd pfd = { .fd = (int)tfd, .events = 0x001, .revents = 0 };
    extern long sys_poll(struct pollfd *fds, unsigned long nfds, int timeout);
    long n = sys_poll(&pfd, 1, 0);
    if (n != 0) {
        fut_printf("[MISC-TEST] ✗ Test 767: poll after disarm returned %ld (want 0)\n", n);
        fut_vfs_close((int)tfd);
        fut_test_fail(767);
        return;
    }

    /* timerfd_gettime must report it_value = {0, 0} */
    struct test_itimerspec cur = {0};
    ret = sys_timerfd_gettime((int)tfd, &cur);
    fut_vfs_close((int)tfd);
    if (ret != 0 || cur.it_value.tv_sec != 0 || cur.it_value.tv_nsec != 0) {
        fut_printf("[MISC-TEST] ✗ Test 767: timerfd_gettime after disarm: ret=%ld val={%lld,%ld}\n",
                   ret, (long long)cur.it_value.tv_sec, cur.it_value.tv_nsec);
        fut_test_fail(767);
        return;
    }

    fut_printf("[MISC-TEST] ✓ Test 767: timerfd disarmed, poll=0, gettime val=0\n");
    fut_test_pass();
}

/*
 * Test 768: timerfd CLOCK_REALTIME + TFD_TIMER_ABSTIME fires correctly.
 *
 * Get current CLOCK_REALTIME, add 10ms, arm a CLOCK_REALTIME timerfd with
 * that absolute deadline.  poll(200ms) must see POLLIN.
 */
static void test_timerfd_abstime_realtime(void) {
    fut_printf("[MISC-TEST] Test 768: timerfd CLOCK_REALTIME TFD_TIMER_ABSTIME fires\n");

    long tfd = sys_timerfd_create(0 /* CLOCK_REALTIME */, 0);
    if (tfd < 0) {
        fut_printf("[MISC-TEST] ✗ Test 768: timerfd_create(CLOCK_REALTIME): %ld\n", tfd);
        fut_test_fail(768);
        return;
    }

    /* Get current CLOCK_REALTIME */
    fut_timespec_t now = {0};
    long r = sys_clock_gettime(0 /* CLOCK_REALTIME */, &now);
    if (r != 0) {
        fut_printf("[MISC-TEST] ✗ Test 768: clock_gettime(REALTIME): %ld\n", r);
        fut_vfs_close((int)tfd);
        fut_test_fail(768);
        return;
    }

    /* Deadline = now + 10ms */
    long nsec = now.tv_nsec + 10000000L;
    long sec  = now.tv_sec;
    if (nsec >= 1000000000L) { nsec -= 1000000000L; sec++; }

    struct test_itimerspec its = {
        .it_interval = { 0, 0 },
        .it_value    = { sec, nsec }
    };
    long ret = sys_timerfd_settime((int)tfd, TFD_TIMER_ABSTIME_TEST, &its, NULL);
    if (ret != 0) {
        fut_printf("[MISC-TEST] ✗ Test 768: timerfd_settime(REALTIME,ABSTIME): %ld\n", ret);
        fut_vfs_close((int)tfd);
        fut_test_fail(768);
        return;
    }

    /* Block all signals during poll to prevent EINTR from pending test signals */
    extern long sys_sigprocmask(int how, const sigset_t *set, sigset_t *oldset);
    sigset_t full_mask768, saved_mask768;
    full_mask768.__mask = ~0UL;
    sys_sigprocmask(2 /* SIG_SETMASK */, &full_mask768, &saved_mask768);

    /* poll(200ms) — timer fires within 10ms after the deadline */
    struct pollfd pfd = { .fd = (int)tfd, .events = 0x001, .revents = 0 };
    extern long sys_poll(struct pollfd *fds, unsigned long nfds, int timeout);
    long n = sys_poll(&pfd, 1, 200);

    sys_sigprocmask(2, &saved_mask768, NULL);  /* restore */

    if (n < 1 || !(pfd.revents & 0x001)) {
        fut_printf("[MISC-TEST] ✗ Test 768: poll returned %ld revents=0x%x\n", n, pfd.revents);
        fut_vfs_close((int)tfd);
        fut_test_fail(768);
        return;
    }

    uint64_t exp = 0;
    ssize_t nr = fut_vfs_read((int)tfd, &exp, sizeof(exp));
    fut_vfs_close((int)tfd);
    if (nr != 8 || exp < 1) {
        fut_printf("[MISC-TEST] ✗ Test 768: timerfd read nr=%zd exp=%llu\n",
                   nr, (unsigned long long)exp);
        fut_test_fail(768);
        return;
    }

    fut_printf("[MISC-TEST] ✓ Test 768: CLOCK_REALTIME TFD_TIMER_ABSTIME fired, exp=%llu\n",
               (unsigned long long)exp);
    fut_test_pass();
}

/*
 * Test 769: ppoll() atomically installs and restores the signal mask.
 *
 * Verifies that:
 *   1. ppoll() accepts a non-NULL sigmask and applies it during the call.
 *   2. The signal mask is restored after ppoll() returns.
 *   3. ppoll() with a ready eventfd returns immediately with 1 event.
 *
 * The test does NOT rely on signal delivery interrupting the poll; it only
 * checks the mask save/restore semantics via sigprocmask round-trips.
 */
static void test_ppoll_sigmask_restore(void) {
    fut_printf("[MISC-TEST] Test 769: ppoll() sigmask install and restore\n");

    extern long sys_sigprocmask(int how, const sigset_t *set, sigset_t *oldset);
    extern long sys_ppoll(void *fds, unsigned int nfds, void *tmo_p, const void *sigmask,
                          size_t sigsetsize);
    extern long sys_eventfd2(unsigned int initval, int flags);

    /* Snapshot the current signal mask */
    sigset_t initial_mask = {0};
    long r = sys_sigprocmask(0 /* SIG_BLOCK */, NULL, &initial_mask);
    if (r != 0) {
        fut_printf("[MISC-TEST] ✗ Test 769: sigprocmask(get) returned %ld\n", r);
        fut_test_fail(769);
        return;
    }

    /* Create a ready eventfd so ppoll can return without blocking */
    long efd = sys_eventfd2(1, 0);
    if (efd < 0) {
        fut_printf("[MISC-TEST] ✗ Test 769: eventfd2 returned %ld\n", efd);
        fut_test_fail(769);
        return;
    }

    /* Build a sigmask that blocks SIGUSR2 (bit 11, signal 12) */
    sigset_t ppoll_mask = {0};
    ppoll_mask.__mask = (1UL << (12 - 1));  /* block SIGUSR2 */

    struct pollfd pfd = { .fd = (int)efd, .events = 0x001 /* POLLIN */, .revents = 0 };
    struct { int64_t tv_sec; long tv_nsec; } ts = { 0, 50000000L }; /* 50ms */

    long n = sys_ppoll(&pfd, 1, &ts, &ppoll_mask, sizeof(sigset_t));

    fut_vfs_close((int)efd);

    /* ppoll must return 1 event (eventfd was ready) */
    if (n != 1 || !(pfd.revents & 0x001)) {
        fut_printf("[MISC-TEST] ✗ Test 769: ppoll returned %ld revents=0x%x (want 1 + POLLIN)\n",
                   n, pfd.revents);
        /* Restore original mask before failing */
        sys_sigprocmask(2 /* SIG_SETMASK */, &initial_mask, NULL);
        fut_test_fail(769);
        return;
    }

    /* Signal mask must be restored to initial_mask after ppoll */
    sigset_t after_mask = {0};
    r = sys_sigprocmask(0 /* SIG_BLOCK */, NULL, &after_mask);
    if (r != 0) {
        fut_printf("[MISC-TEST] ✗ Test 769: sigprocmask(post-ppoll) returned %ld\n", r);
        fut_test_fail(769);
        return;
    }

    /* Compare signal masks */
    if (after_mask.__mask != initial_mask.__mask) {
        fut_printf("[MISC-TEST] ✗ Test 769: mask not restored: after=0x%lx initial=0x%lx\n",
                   (unsigned long)after_mask.__mask,
                   (unsigned long)initial_mask.__mask);
        /* Restore explicitly before failing */
        sys_sigprocmask(2, &initial_mask, NULL);
        fut_test_fail(769);
        return;
    }

    fut_printf("[MISC-TEST] ✓ Test 769: ppoll(sigmask): returned %ld event, mask restored\n", n);
    fut_test_pass();
}

/* ============================================================
 * Tests 770-774: FUTEX_REQUEUE, FUTEX_CMP_REQUEUE, FUTEX_WAKE_OP
 *
 * These operations implement pthread_cond_broadcast/signal in NPTL.
 * Tests cover: no-waiters paths (return 0), error paths (EAGAIN/EINVAL),
 * and WAKE_OP's mandatory atomic side-effect on *uaddr2.
 * ============================================================ */
#define FUTEX_REQUEUE_VAL       3
#define FUTEX_CMP_REQUEUE_VAL   4
#define FUTEX_WAKE_OP_VAL       5
/* FUTEX_OP(op, oparg, cmp, cmparg) encoding — matches include/sys/futex.h */
#define TEST_FUTEX_OP(op, oparg, cmp, cmparg) \
    (((op) & 0xf) | (((cmp) & 0xf) << 4) | \
     (((oparg) & 0xfff) << 8) | (((cmparg) & 0xfff) << 20))
#define FUTEX_OP_SET_VAL    0   /* *uaddr2 = oparg */
#define FUTEX_OP_CMP_EQ_VAL 0   /* old == cmparg */

static void test_futex_requeue_cmp_wake_op(void) {
    extern long sys_futex(uint32_t *uaddr, int op, uint32_t val, const void *timeout,
                          uint32_t *uaddr2, uint32_t val3);

    uint32_t lock1 = 0, lock2 = 0;
    long r;

    /* Test 770: FUTEX_REQUEUE no waiters → 0 */
    fut_printf("[MISC-TEST] Test 770: FUTEX_REQUEUE no waiters → 0\n");
    lock1 = 0; lock2 = 0;
    r = sys_futex(&lock1, FUTEX_REQUEUE_VAL, 1, NULL, &lock2, 0);
    if (r != 0) {
        fut_printf("[MISC-TEST] ✗ Test 770: FUTEX_REQUEUE expected 0, got %ld\n", r);
        fut_test_fail(770);
    } else {
        fut_printf("[MISC-TEST] ✓ Test 770: FUTEX_REQUEUE no waiters → 0\n");
        fut_test_pass();
    }

    /* Test 771: FUTEX_REQUEUE NULL uaddr2 → EINVAL */
    fut_printf("[MISC-TEST] Test 771: FUTEX_REQUEUE NULL uaddr2 → EINVAL\n");
    lock1 = 0;
    r = sys_futex(&lock1, FUTEX_REQUEUE_VAL, 1, NULL, NULL, 0);
    if (r != -EINVAL) {
        fut_printf("[MISC-TEST] ✗ Test 771: FUTEX_REQUEUE(NULL) expected -EINVAL(%d), got %ld\n",
                   -EINVAL, r);
        fut_test_fail(771);
    } else {
        fut_printf("[MISC-TEST] ✓ Test 771: FUTEX_REQUEUE NULL uaddr2 → EINVAL\n");
        fut_test_pass();
    }

    /* Test 772: FUTEX_CMP_REQUEUE val3 matches *uaddr, no waiters → 0 */
    fut_printf("[MISC-TEST] Test 772: FUTEX_CMP_REQUEUE val3 match no waiters → 0\n");
    lock1 = 42; lock2 = 0;
    r = sys_futex(&lock1, FUTEX_CMP_REQUEUE_VAL, 0, NULL, &lock2, 42u);
    if (r != 0) {
        fut_printf("[MISC-TEST] ✗ Test 772: FUTEX_CMP_REQUEUE match expected 0, got %ld\n", r);
        fut_test_fail(772);
    } else {
        fut_printf("[MISC-TEST] ✓ Test 772: FUTEX_CMP_REQUEUE val3 match → 0\n");
        fut_test_pass();
    }

    /* Test 773: FUTEX_CMP_REQUEUE val3 mismatch → EAGAIN */
    fut_printf("[MISC-TEST] Test 773: FUTEX_CMP_REQUEUE val3 mismatch → EAGAIN\n");
    lock1 = 42; lock2 = 0;
    r = sys_futex(&lock1, FUTEX_CMP_REQUEUE_VAL, 0, NULL, &lock2, 99u);
    if (r != -EAGAIN) {
        fut_printf("[MISC-TEST] ✗ Test 773: FUTEX_CMP_REQUEUE mismatch expected -EAGAIN(%d), got %ld\n",
                   -EAGAIN, r);
        fut_test_fail(773);
    } else {
        fut_printf("[MISC-TEST] ✓ Test 773: FUTEX_CMP_REQUEUE val3 mismatch → EAGAIN\n");
        fut_test_pass();
    }

    /* Test 774: FUTEX_WAKE_OP atomic SET side effect on *uaddr2
     * Encode: OP_SET oparg=55, CMP_EQ cmparg=7 → sets lock2 to 55 unconditionally.
     * With lock2 starting at 7 and cmparg=7: oldval(7)==cmparg(7), so val2 wakes also
     * attempted at uaddr2 (but no waiters → 0). Return = woken1 + woken2 = 0.
     * Key invariant: *uaddr2 must be 55 after the call regardless of waiters. */
    fut_printf("[MISC-TEST] Test 774: FUTEX_WAKE_OP atomic SET side effect\n");
    lock1 = 0;
    lock2 = 7;
    uint32_t wake_op = (uint32_t)TEST_FUTEX_OP(FUTEX_OP_SET_VAL, 55, FUTEX_OP_CMP_EQ_VAL, 7);
    r = sys_futex(&lock1, FUTEX_WAKE_OP_VAL, 0, NULL, &lock2, wake_op);
    if (r < 0) {
        fut_printf("[MISC-TEST] ✗ Test 774: FUTEX_WAKE_OP returned %ld (expected >=0)\n", r);
        fut_test_fail(774);
    } else if (lock2 != 55u) {
        fut_printf("[MISC-TEST] ✗ Test 774: lock2=%u after WAKE_OP SET(55) (expected 55)\n",
                   lock2);
        fut_test_fail(774);
    } else {
        fut_printf("[MISC-TEST] ✓ Test 774: FUTEX_WAKE_OP SET(55): lock2=%u, ret=%ld\n",
                   lock2, r);
        fut_test_pass();
    }
}

/* ============================================================
 * Tests 775-778: epoll_ctl error paths
 *
 * Linux epoll_ctl ABI:
 *   EPOLL_CTL_ADD on already-registered fd → EEXIST
 *   EPOLL_CTL_MOD on fd not registered → ENOENT
 *   EPOLL_CTL_DEL on fd not registered → ENOENT
 *   EPOLL_CTL_ADD after DEL → 0 (re-registration succeeds)
 * ============================================================ */
static void test_epoll_ctl_errors(void) {
    extern long sys_epoll_create1(int flags);
    extern long sys_epoll_ctl(int epfd, int op, int fd, void *event);
    extern long sys_eventfd2(unsigned int initval, int flags);

    /* epoll_event: events(u32) + data(u64) — packed 12 bytes */
    struct { uint32_t events; uint64_t data; } ev;

    /* Test 775: EPOLL_CTL_ADD same fd twice → EEXIST */
    fut_printf("[MISC-TEST] Test 775: epoll_ctl ADD twice → EEXIST\n");
    long epfd = sys_epoll_create1(0);
    long efd  = sys_eventfd2(0, 0);
    if (epfd < 0 || efd < 0) {
        fut_printf("[MISC-TEST] ✗ Test 775: setup failed epfd=%ld efd=%ld\n", epfd, efd);
        if (epfd >= 0) fut_vfs_close((int)epfd);
        if (efd  >= 0) fut_vfs_close((int)efd);
        fut_test_fail(775);
        goto t776;
    }
    ev.events = 0x001; /* EPOLLIN */
    ev.data   = (uint64_t)(int)efd;
    {
        long r1 = sys_epoll_ctl((int)epfd, 1 /* ADD */, (int)efd, &ev);
        long r2 = sys_epoll_ctl((int)epfd, 1 /* ADD */, (int)efd, &ev);
        if (r1 != 0 || r2 != -EEXIST) {
            fut_printf("[MISC-TEST] ✗ Test 775: first ADD=%ld (want 0) second ADD=%ld (want -EEXIST=%d)\n",
                       r1, r2, -EEXIST);
            fut_vfs_close((int)epfd); fut_vfs_close((int)efd);
            fut_test_fail(775);
        } else {
            fut_printf("[MISC-TEST] ✓ Test 775: epoll ADD×2 → 0 then EEXIST\n");
            fut_test_pass();
        }
    }
    fut_vfs_close((int)epfd);
    fut_vfs_close((int)efd);

t776:
    /* Test 776: EPOLL_CTL_DEL on fd not in epoll → ENOENT (EPOLL_CTL_DEL=2) */
    fut_printf("[MISC-TEST] Test 776: epoll_ctl DEL fd not registered → ENOENT\n");
    epfd = sys_epoll_create1(0);
    efd  = sys_eventfd2(0, 0);
    if (epfd < 0 || efd < 0) {
        fut_printf("[MISC-TEST] ✗ Test 776: setup failed epfd=%ld efd=%ld\n", epfd, efd);
        if (epfd >= 0) fut_vfs_close((int)epfd);
        if (efd  >= 0) fut_vfs_close((int)efd);
        fut_test_fail(776);
        goto t777;
    }
    {
        long r = sys_epoll_ctl((int)epfd, 2 /* DEL */, (int)efd, NULL);
        if (r != -ENOENT) {
            fut_printf("[MISC-TEST] ✗ Test 776: DEL unregistered fd=%ld (want -ENOENT=%d)\n",
                       r, -ENOENT);
            fut_test_fail(776);
        } else {
            fut_printf("[MISC-TEST] ✓ Test 776: epoll DEL unregistered → ENOENT\n");
            fut_test_pass();
        }
    }
    fut_vfs_close((int)epfd);
    fut_vfs_close((int)efd);

t777:
    /* Test 777: EPOLL_CTL_MOD on fd not in epoll → ENOENT (EPOLL_CTL_MOD=3) */
    fut_printf("[MISC-TEST] Test 777: epoll_ctl MOD fd not registered → ENOENT\n");
    epfd = sys_epoll_create1(0);
    efd  = sys_eventfd2(0, 0);
    if (epfd < 0 || efd < 0) {
        fut_printf("[MISC-TEST] ✗ Test 777: setup failed epfd=%ld efd=%ld\n", epfd, efd);
        if (epfd >= 0) fut_vfs_close((int)epfd);
        if (efd  >= 0) fut_vfs_close((int)efd);
        fut_test_fail(777);
        goto t778;
    }
    ev.events = 0x001; ev.data = (uint64_t)(int)efd;
    {
        long r = sys_epoll_ctl((int)epfd, 3 /* MOD */, (int)efd, &ev);
        if (r != -ENOENT) {
            fut_printf("[MISC-TEST] ✗ Test 777: MOD unregistered fd=%ld (want -ENOENT=%d)\n",
                       r, -ENOENT);
            fut_test_fail(777);
        } else {
            fut_printf("[MISC-TEST] ✓ Test 777: epoll MOD unregistered → ENOENT\n");
            fut_test_pass();
        }
    }
    fut_vfs_close((int)epfd);
    fut_vfs_close((int)efd);

t778:
    /* Test 778: EPOLL_CTL_DEL then re-ADD succeeds */
    fut_printf("[MISC-TEST] Test 778: epoll_ctl ADD→DEL→ADD cycle\n");
    epfd = sys_epoll_create1(0);
    efd  = sys_eventfd2(0, 0);
    if (epfd < 0 || efd < 0) {
        fut_printf("[MISC-TEST] ✗ Test 778: setup failed epfd=%ld efd=%ld\n", epfd, efd);
        if (epfd >= 0) fut_vfs_close((int)epfd);
        if (efd  >= 0) fut_vfs_close((int)efd);
        fut_test_fail(778);
        return;
    }
    ev.events = 0x001; ev.data = (uint64_t)(int)efd;
    {
        long r1 = sys_epoll_ctl((int)epfd, 1 /* ADD */, (int)efd, &ev); /* add */
        long r2 = sys_epoll_ctl((int)epfd, 2 /* DEL */, (int)efd, NULL); /* del */
        long r3 = sys_epoll_ctl((int)epfd, 1 /* ADD */, (int)efd, &ev); /* re-add */
        if (r1 != 0 || r2 != 0 || r3 != 0) {
            fut_printf("[MISC-TEST] ✗ Test 778: ADD=%ld DEL=%ld re-ADD=%ld (all want 0)\n",
                       r1, r2, r3);
            fut_test_fail(778);
        } else {
            fut_printf("[MISC-TEST] ✓ Test 778: epoll ADD→DEL→ADD cycle all succeeded\n");
            fut_test_pass();
        }
    }
    fut_vfs_close((int)epfd);
    fut_vfs_close((int)efd);
}

/* ============================================================
 * Test 779: POSIX timer fires and delivers SIGALRM to pending_signals
 *
 * Arms a 10ms POSIX timer (CLOCK_MONOTONIC, SIGALRM delivery).
 * SIGALRM is blocked so the signal accumulates in pending_signals
 * without the default terminate action running.  After sleeping 50ms
 * the pending bit must be set, confirming end-to-end timer→signal delivery.
 * ============================================================ */
static void test_posix_timer_signal_delivery(void) {
    fut_printf("[MISC-TEST] Test 779: POSIX timer fires → SIGALRM pending\n");
    extern long sys_timer_create(int clockid, struct sigevent *sevp, timer_t *timerid);
    extern long sys_timer_settime(timer_t timerid, int flags,
                                  const struct itimerspec *new_value,
                                  struct itimerspec *old_value);
    extern long sys_timer_delete(int timerid);
    extern long sys_sigprocmask(int how, const sigset_t *set, sigset_t *oldset);
    extern long sys_nanosleep(const fut_timespec_t *req, fut_timespec_t *rem);

#define SIGALRM_NR 14
    /* Block ALL signals so nanosleep won't EINTR and SIG_DFL won't terminate */
    sigset_t full_mask779, saved_mask779;
    full_mask779.__mask = ~0UL;
    long rm = sys_sigprocmask(2 /* SIG_SETMASK */, &full_mask779, &saved_mask779);
    if (rm != 0) {
        fut_printf("[MISC-TEST] ✗ Test 779: sigprocmask block failed: %ld\n", rm);
        fut_test_fail(779); return;
    }

    /* Clear any pre-existing SIGALRM pending bit from prior tests */
    fut_task_t *task779 = fut_task_current();
    uint64_t alrm_bit = (1ULL << (SIGALRM_NR - 1));
    __atomic_and_fetch(&task779->pending_signals, ~alrm_bit, __ATOMIC_RELEASE);

    /* Create POSIX timer: CLOCK_MONOTONIC, NULL sevp → SIGALRM */
    timer_t tid779 = 0;
    long rc = sys_timer_create(1 /* CLOCK_MONOTONIC */, NULL, &tid779);
    if (rc != 0) {
        fut_printf("[MISC-TEST] ✗ Test 779: timer_create failed: %ld\n", rc);
        sys_sigprocmask(2, &saved_mask779, NULL);
        fut_test_fail(779); return;
    }

    /* Arm: 10ms one-shot (1 tick at 100Hz) */
    struct itimerspec its779;
    its779.it_value.tv_sec    = 0;
    its779.it_value.tv_nsec   = 10000000;  /* 10ms */
    its779.it_interval.tv_sec = 0;
    its779.it_interval.tv_nsec = 0;
    rc = sys_timer_settime(tid779, 0, &its779, NULL);
    if (rc != 0) {
        fut_printf("[MISC-TEST] ✗ Test 779: timer_settime failed: %ld\n", rc);
        sys_timer_delete((int)tid779);
        sys_sigprocmask(2, &saved_mask779, NULL);
        fut_test_fail(779); return;
    }

    /* Sleep 50ms (5 ticks) — all signals blocked, so nanosleep won't EINTR */
    fut_timespec_t sleep779 = { .tv_sec = 0, .tv_nsec = 50000000 };
    sys_nanosleep(&sleep779, NULL);

    /* Check pending_signals for SIGALRM */
    uint64_t pending779 = __atomic_load_n(&task779->pending_signals, __ATOMIC_ACQUIRE);

    /* Cleanup: delete timer, clear SIGALRM, restore mask */
    sys_timer_delete((int)tid779);
    __atomic_and_fetch(&task779->pending_signals, ~alrm_bit, __ATOMIC_RELEASE);
    sys_sigprocmask(2, &saved_mask779, NULL);

    if (!(pending779 & alrm_bit)) {
        fut_printf("[MISC-TEST] ✗ Test 779: SIGALRM not pending after timer fire "
                   "(pending=0x%llx)\n", (unsigned long long)pending779);
        fut_test_fail(779); return;
    }
    fut_printf("[MISC-TEST] ✓ Test 779: POSIX timer fired → SIGALRM pending (0x%llx)\n",
               (unsigned long long)(pending779 & alrm_bit));
    fut_test_pass();
#undef SIGALRM_NR
}

/* ============================================================
 * Tests 780-782: munmap partial unmap (middle-page split)
 *
 * Linux ABI: munmap() on a sub-range of a VMA splits it into two
 * separate VMAs covering the regions before and after the unmapped range.
 * The split portions must remain fully accessible.
 *
 * This exercises fut_mm_unmap Case 4 ("unmap middle"), which is the path
 * used by glibc malloc when it carves pages out of large anonymous chunks.
 * ============================================================ */
static void test_munmap_middle(void) {
    extern long sys_mmap(void *addr, size_t len, int prot, int flags, int fd, long off);
    extern long sys_munmap(void *addr, size_t len);

#define MM_PROT_RW  3       /* PROT_READ|PROT_WRITE */
#define MM_MAP_PA   0x22    /* MAP_PRIVATE|MAP_ANONYMOUS */
#define PAGE        4096u

    /* Test 780: munmap middle page of 3-page mapping returns 0 */
    fut_printf("[MISC-TEST] Test 780: munmap middle page of 3-page mapping\n");
    long base = sys_mmap(NULL, 3 * PAGE, MM_PROT_RW, MM_MAP_PA, -1, 0);
    if (base < 0) {
        fut_printf("[MISC-TEST] ✗ Test 780: mmap 3 pages failed: %ld\n", base);
        fut_test_fail(780); goto t781;
    }
    /* Write sentinels to first and last pages */
    volatile uint8_t *p = (volatile uint8_t *)(uintptr_t)base;
    p[0]           = 0xAA;  /* sentinel in first page */
    p[2 * PAGE]    = 0xBB;  /* sentinel in third page */

    /* Unmap the middle page */
    long r = sys_munmap((void *)(uintptr_t)(base + PAGE), PAGE);
    if (r != 0) {
        fut_printf("[MISC-TEST] ✗ Test 780: munmap middle returned %ld (want 0)\n", r);
        sys_munmap((void *)(uintptr_t)base, 3 * PAGE);  /* best-effort cleanup */
        fut_test_fail(780); goto t781;
    }
    fut_printf("[MISC-TEST] ✓ Test 780: munmap middle page → 0\n");
    fut_test_pass();

    /* Test 781: first page sentinel preserved after middle-page unmap */
    fut_printf("[MISC-TEST] Test 781: first page still readable after middle unmap\n");
    if (p[0] != 0xAA) {
        fut_printf("[MISC-TEST] ✗ Test 781: first-page sentinel corrupted: 0x%02x\n", p[0]);
        sys_munmap((void *)(uintptr_t)base, PAGE);
        sys_munmap((void *)(uintptr_t)(base + 2 * PAGE), PAGE);
        fut_test_fail(781); goto t781_cleanup;
    }
    fut_printf("[MISC-TEST] ✓ Test 781: first page sentinel 0x%02x preserved\n", p[0]);
    fut_test_pass();

    /* Test 782: last page sentinel preserved after middle-page unmap */
    fut_printf("[MISC-TEST] Test 782: last page still readable after middle unmap\n");
    if (p[2 * PAGE] != 0xBB) {
        fut_printf("[MISC-TEST] ✗ Test 782: last-page sentinel corrupted: 0x%02x\n", p[2 * PAGE]);
        fut_test_fail(782);
    } else {
        fut_printf("[MISC-TEST] ✓ Test 782: last page sentinel 0x%02x preserved\n", p[2 * PAGE]);
        fut_test_pass();
    }

t781_cleanup:
    /* Clean up remaining first and last pages */
    sys_munmap((void *)(uintptr_t)base, PAGE);
    sys_munmap((void *)(uintptr_t)(base + 2 * PAGE), PAGE);
    goto done780;

t781:
    fut_test_fail(781);
    fut_test_fail(782);

done780:;
#undef MM_PROT_RW
#undef MM_MAP_PA
#undef PAGE
}

/* ============================================================
 * Test 783: select() updates timeout struct on Linux
 *
 * Linux-specific ABI: after select() returns (due to timeout expiry),
 * the timeval is updated to reflect elapsed time (≈ 0 remaining).
 * POSIX does not require this, but Linux always does it and bash/Python
 * rely on it.  Futura implements this in sys_select.c.
 * ============================================================ */
static void test_select_timeout_update(void) {
    fut_printf("[MISC-TEST] Test 783: select() updates timeout to remaining after expiry\n");
    extern long sys_select(int nfds, void *rfds, void *wfds, void *efds, void *timeout);

    extern long sys_sigprocmask(int how, const sigset_t *set, sigset_t *oldset);

    /* Block all signals so accumulated pending signals from prior tests don't EINTR */
    sigset_t full783, saved783;
    full783.__mask = ~0UL;
    sys_sigprocmask(2 /* SIG_SETMASK */, &full783, &saved783);

    /* Select with nfds=0 (no fds) and timeout=30ms.
     * After the call the timeval must be near 0 (Linux updates it). */
    int64_t tv[2] = { 0, 30000 };  /* tv_sec=0, tv_usec=30000 (30ms) */
    long r = sys_select(0, NULL, NULL, NULL, tv);
    sys_sigprocmask(2, &saved783, NULL);  /* restore before any fail return */
    if (r != 0) {
        fut_printf("[MISC-TEST] ✗ Test 783: select returned %ld (expected 0)\n", r);
        fut_test_fail(783); return;
    }

    /* tv[0] is tv_sec, tv[1] is tv_usec.  After timeout expiry both should
     * be 0 (or very close to 0 — we allow up to 30ms worth of ticks). */
    if (tv[0] != 0 || tv[1] > 30000) {
        fut_printf("[MISC-TEST] ✗ Test 783: timeout not updated: tv={%lld,%lld} (want ~{0,0})\n",
                   (long long)tv[0], (long long)tv[1]);
        fut_test_fail(783); return;
    }
    fut_printf("[MISC-TEST] ✓ Test 783: timeout updated to {%lld,%lld} after expiry\n",
               (long long)tv[0], (long long)tv[1]);
    fut_test_pass();
}

/* ============================================================
 * Tests 788-791: RLIMIT_FSIZE enforcement
 *
 *   788: write within RLIMIT_FSIZE → full write succeeds
 *   789: write that would exceed RLIMIT_FSIZE is truncated to limit
 *   790: write starting at or past RLIMIT_FSIZE → EFBIG
 *   791: SIGXFSZ is pending after an over-limit write (POSIX requirement)
 *
 * POSIX: if a write would cause the file size to exceed RLIMIT_FSIZE,
 * the write shall fail with EFBIG and SIGXFSZ shall be sent to the
 * process.  Writes that partially exceed the limit are truncated.
 * ============================================================ */
static void test_rlimit_fsize_enforcement(void) {
    fut_printf("[MISC-TEST] Tests 788-791: RLIMIT_FSIZE enforcement\n");
    extern long sys_prlimit64(int pid, int resource, const void *new_limit, void *old_limit);
    extern long sys_sigprocmask(int how, const sigset_t *set, sigset_t *oldset);

    fut_task_t *task788 = fut_task_current();
    if (!task788) {
        fut_test_fail(788); fut_test_fail(789); fut_test_fail(790); fut_test_fail(791);
        return;
    }

    /* Block SIGXFSZ to prevent default SIG_DFL=core/terminate action */
    sigset_t xfsz_block = { .__mask = 1ULL << (25 - 1) };  /* SIGXFSZ = signal 25 */
    sigset_t saved_mask;
    sys_sigprocmask(0 /* SIG_BLOCK */, &xfsz_block, &saved_mask);

    /* Clear any pre-existing SIGXFSZ */
    __atomic_and_fetch(&task788->pending_signals, ~(1ULL << 24), __ATOMIC_RELEASE);

    /* Save current RLIMIT_FSIZE and set soft=100 bytes, hard=RLIM64_INFINITY */
    struct { uint64_t cur; uint64_t max; } old_fsize, new_fsize;
    sys_prlimit64(0, 1 /* RLIMIT_FSIZE */, NULL, &old_fsize);
    new_fsize.cur = 100;
    new_fsize.max = old_fsize.max;
    sys_prlimit64(0, 1 /* RLIMIT_FSIZE */, &new_fsize, NULL);

    /* Open a fresh test file */
    int fd788 = fut_vfs_open("/rlimit_fsize_test.txt", 0x42 /* O_CREAT|O_RDWR */, 0644);
    if (fd788 < 0) {
        fut_printf("[MISC-TEST] ✗ Tests 788-791: open failed: %d\n", fd788);
        sys_prlimit64(0, 1, &old_fsize, NULL);
        sys_sigprocmask(2 /* SIG_SETMASK */, &saved_mask, NULL);
        fut_test_fail(788); fut_test_fail(789); fut_test_fail(790); fut_test_fail(791);
        return;
    }

    /* Test 788: write 50 bytes at offset 0 — well within limit → 50 returned */
    char buf[120];
    __builtin_memset(buf, 'A', sizeof(buf));
    ssize_t n = fut_vfs_write(fd788, buf, 50);
    if (n != 50) {
        fut_printf("[MISC-TEST] ✗ Test 788: write(50) = %zd (expected 50)\n", n);
        fut_vfs_close(fd788);
        sys_prlimit64(0, 1, &old_fsize, NULL);
        sys_sigprocmask(2, &saved_mask, NULL);
        fut_test_fail(788); fut_test_fail(789); fut_test_fail(790); fut_test_fail(791);
        return;
    }
    fut_printf("[MISC-TEST] ✓ Test 788: write(50) within RLIMIT_FSIZE=100 → 50\n");
    fut_test_pass();

    /* Advance to offset 90 by writing another 40 bytes (90 total, still within limit) */
    fut_vfs_write(fd788, buf, 40);

    /* Test 789: write 20 bytes at offset 90 — would reach 110 > 100 → truncated to 10 */
    n = fut_vfs_write(fd788, buf, 20);
    if (n != 10) {
        fut_printf("[MISC-TEST] ✗ Test 789: partial write at offset 90 = %zd (expected 10)\n", n);
        fut_vfs_close(fd788);
        sys_prlimit64(0, 1, &old_fsize, NULL);
        sys_sigprocmask(2, &saved_mask, NULL);
        fut_test_fail(789); fut_test_fail(790); fut_test_fail(791);
        return;
    }
    fut_printf("[MISC-TEST] ✓ Test 789: write(20) at offset 90 truncated to 10 (limit=100)\n");
    fut_test_pass();

    /* File offset is now 100 = fsize_limit */

    /* Test 790: write at offset 100 (== limit) → EFBIG */
    n = fut_vfs_write(fd788, buf, 1);
    if (n != -27 /* -EFBIG */) {
        fut_printf("[MISC-TEST] ✗ Test 790: write at offset 100 = %zd (expected -EFBIG=%d)\n",
                   n, -27);
        fut_vfs_close(fd788);
        sys_prlimit64(0, 1, &old_fsize, NULL);
        sys_sigprocmask(2, &saved_mask, NULL);
        fut_test_fail(790); fut_test_fail(791);
        return;
    }
    fut_printf("[MISC-TEST] ✓ Test 790: write at limit offset → EFBIG\n");
    fut_test_pass();

    fut_vfs_close(fd788);

    /* Test 791: SIGXFSZ must be pending (set by the over-limit write in test 790) */
    uint64_t pending791 = __atomic_load_n(&task788->pending_signals, __ATOMIC_ACQUIRE);
    uint64_t xfsz_bit = 1ULL << 24;  /* SIGXFSZ = signal 25, bit index 24 */
    int has_xfsz = (pending791 & xfsz_bit) != 0;

    /* Clear SIGXFSZ before restoring mask so it doesn't fire */
    __atomic_and_fetch(&task788->pending_signals, ~xfsz_bit, __ATOMIC_RELEASE);

    /* Restore rlimit and signal mask */
    sys_prlimit64(0, 1, &old_fsize, NULL);
    sys_sigprocmask(2, &saved_mask, NULL);

    if (!has_xfsz) {
        fut_printf("[MISC-TEST] ✗ Test 791: SIGXFSZ not pending after over-limit write\n");
        fut_test_fail(791);
        return;
    }
    fut_printf("[MISC-TEST] ✓ Test 791: SIGXFSZ pending after write beyond RLIMIT_FSIZE\n");
    fut_test_pass();
}

/* ============================================================
 * Tests 784-785: rt_sigtimedwait fills siginfo correctly
 *
 *   784: uinfo.si_signo  == SIGUSR1 (10) when SIGUSR1 is dequeued
 *   785: uinfo.si_code   == 0 (SI_USER) for a kill()-sourced signal
 *
 * POSIX: when uinfo is non-NULL, rt_sigtimedwait populates at least
 * si_signo and si_code.  Futura's implementation reads si_code from
 * the per-signal sig_queue_info filled by fut_signal_send().
 * ============================================================ */
static void test_sigtimedwait_uinfo(void) {
    fut_printf("[MISC-TEST] Tests 784-785: rt_sigtimedwait fills siginfo\n");
    extern long sys_rt_sigtimedwait(const uint64_t *uthese, void *uinfo,
                                     const void *uts, size_t sigsetsize);
    extern long sys_sigprocmask(int how, const sigset_t *set, sigset_t *oldset);
    extern long sys_kill(int pid, int sig);
    extern long sys_getpid(void);

    fut_task_t *task784 = fut_task_current();
    if (!task784) { fut_test_fail(784); fut_test_fail(785); return; }

    /* Block SIGUSR1 so kill() queues it without triggering the default
     * SIG_DFL terminate action (SIGUSR1 default = terminate). */
    sigset_t block784 = { .__mask = 1ULL << 9 };  /* SIGUSR1 = bit 9 */
    sigset_t saved784;
    sys_sigprocmask(0 /* SIG_BLOCK */, &block784, &saved784);

    /* Clear any pre-existing SIGUSR1 pending bit from earlier tests */
    __atomic_and_fetch(&task784->pending_signals, ~(1ULL << 9), __ATOMIC_RELEASE);

    /* Send SIGUSR1 to self — fills sig_queue_info[9] with si_code=SI_USER */
    long pid784 = sys_getpid();
    sys_kill((int)pid784, 10 /* SIGUSR1 */);

    /* 128-byte buffer matching struct kernel_siginfo:
     *   si_signo (int, offset 0), si_errno (int, offset 4), si_code (int, offset 8) */
    struct { int si_signo; int si_errno; int si_code; char pad[116]; } uinfo784;
    __builtin_memset(&uinfo784, 0xff, sizeof(uinfo784));

    uint64_t uthese784 = 1ULL << 9;  /* SIGUSR1 */
    struct { int64_t tv_sec; long tv_nsec; } ts784 = { 0, 10000000 };  /* 10ms */
    long ret784 = sys_rt_sigtimedwait(&uthese784, &uinfo784, &ts784, sizeof(uint64_t));

    /* Restore signal mask before any fail-return */
    sys_sigprocmask(2 /* SIG_SETMASK */, &saved784, NULL);

    if (ret784 != 10) {
        fut_printf("[MISC-TEST] ✗ Test 784: sigtimedwait returned %ld (expected 10)\n", ret784);
        fut_test_fail(784); fut_test_fail(785); return;
    }

    /* Test 784: si_signo (offset 0) must equal 10 (SIGUSR1) */
    if (uinfo784.si_signo != 10) {
        fut_printf("[MISC-TEST] ✗ Test 784: uinfo.si_signo=%d (expected 10)\n", uinfo784.si_signo);
        fut_test_fail(784); fut_test_fail(785); return;
    }
    fut_printf("[MISC-TEST] ✓ Test 784: sigtimedwait uinfo.si_signo=%d\n", uinfo784.si_signo);
    fut_test_pass();

    /* Test 785: si_code (offset 8) must be 0 (SI_USER — signal from kill()) */
    if (uinfo784.si_code != 0) {
        fut_printf("[MISC-TEST] ✗ Test 785: uinfo.si_code=%d (expected 0=SI_USER)\n",
                   uinfo784.si_code);
        fut_test_fail(785); return;
    }
    fut_printf("[MISC-TEST] ✓ Test 785: sigtimedwait uinfo.si_code=%d (SI_USER)\n",
               uinfo784.si_code);
    fut_test_pass();
}

/* ============================================================
 * Tests 786-787: flock LOCK_NB conflict detection
 *
 *   786: LOCK_EX|LOCK_NB returns EAGAIN when another open file
 *        description holds LOCK_SH on the same vnode.
 *   787: After LOCK_UN releases the shared lock,
 *        LOCK_EX|LOCK_NB succeeds (returns 0).
 *
 * Linux: flock() is per open-file-description.  Two separate
 * open() calls create independent OFDs; a LOCK_SH on fd1 blocks
 * LOCK_EX from fd2 even within the same process.
 * ============================================================ */
static void test_flock_nb_conflict(void) {
    fut_printf("[MISC-TEST] Tests 786-787: flock LOCK_NB conflict\n");
    extern long sys_flock(int fd, int operation);

#define T786_LOCK_SH  1
#define T786_LOCK_EX  2
#define T786_LOCK_UN  8
#define T786_LOCK_NB  4

    /* Two independent open() calls → two separate file descriptions */
    int fd1 = fut_vfs_open("/flock_nb786.txt", 0x42 /* O_CREAT|O_RDWR */, 0644);
    int fd2 = fut_vfs_open("/flock_nb786.txt", 2    /* O_RDWR         */, 0);

    if (fd1 < 0 || fd2 < 0) {
        fut_printf("[MISC-TEST] ✗ Tests 786-787: open failed fd1=%d fd2=%d\n", fd1, fd2);
        if (fd1 >= 0) fut_vfs_close(fd1);
        if (fd2 >= 0) fut_vfs_close(fd2);
        fut_test_fail(786); fut_test_fail(787); return;
    }

    /* Acquire shared lock via fd1 */
    long r = sys_flock(fd1, T786_LOCK_SH);
    if (r != 0) {
        fut_printf("[MISC-TEST] ✗ Tests 786-787: flock(fd1, LOCK_SH)=%ld\n", r);
        fut_vfs_close(fd1); fut_vfs_close(fd2);
        fut_test_fail(786); fut_test_fail(787); return;
    }

    /* Test 786: LOCK_EX|LOCK_NB via fd2 must fail with EAGAIN because
     * fd1 holds a shared lock on the same vnode */
    r = sys_flock(fd2, T786_LOCK_EX | T786_LOCK_NB);
    if (r != -EAGAIN) {
        fut_printf("[MISC-TEST] ✗ Test 786: LOCK_EX|LOCK_NB=%ld (expected -EAGAIN=%d)\n",
                   r, -EAGAIN);
        sys_flock(fd1, T786_LOCK_UN);
        fut_vfs_close(fd1); fut_vfs_close(fd2);
        fut_test_fail(786); fut_test_fail(787); return;
    }
    fut_printf("[MISC-TEST] ✓ Test 786: flock LOCK_EX|LOCK_NB → EAGAIN while LOCK_SH held\n");
    fut_test_pass();

    /* Release shared lock; LOCK_EX|LOCK_NB must now succeed */
    sys_flock(fd1, T786_LOCK_UN);

    r = sys_flock(fd2, T786_LOCK_EX | T786_LOCK_NB);
    sys_flock(fd2, T786_LOCK_UN);
    fut_vfs_close(fd1); fut_vfs_close(fd2);

    if (r != 0) {
        fut_printf("[MISC-TEST] ✗ Test 787: LOCK_EX|LOCK_NB after unlock=%ld (expected 0)\n", r);
        fut_test_fail(787); return;
    }
    fut_printf("[MISC-TEST] ✓ Test 787: flock LOCK_EX|LOCK_NB → 0 after LOCK_UN\n");
    fut_test_pass();
}

/* ============================================================
 * Tests 792-795: O_PATH fd semantics
 *
 *   792: open with O_PATH succeeds (valid fd returned)
 *   793: read() on O_PATH fd returns EBADF
 *   794: write() on O_PATH fd returns EBADF
 *   795: fstat() on O_PATH fd succeeds and returns S_IFREG mode
 *
 * POSIX/Linux: O_PATH opens a file descriptor that refers to the
 * file's path in the filesystem, not its content.  I/O operations
 * (read, write) are not permitted and must return EBADF.
 * File-metadata operations (fstat, fchdir on dirs) still work.
 * ============================================================ */
static void test_opath_semantics(void) {
    fut_printf("[MISC-TEST] Tests 792-795: O_PATH fd semantics\n");

    extern long sys_fstat(int fd, struct fut_stat *statbuf);

#define O_PATH_FLAG 010000000   /* 0x200000 */

    const char *path792 = "/tmp/test792_opath.txt";

    /* Create the file first via a normal open */
    int cfd = (int)fut_vfs_open(path792, O_CREAT | O_RDWR, 0644);
    if (cfd < 0) {
        fut_printf("[MISC-TEST] ✗ setup: open(%s) failed: %d\n", path792, cfd);
        fut_test_fail(792); fut_test_fail(793);
        fut_test_fail(794); fut_test_fail(795);
        return;
    }
    /* Write a sentinel byte so the file is non-empty */
    fut_vfs_write(cfd, "x", 1);
    fut_vfs_close(cfd);

    /* Test 792: O_PATH open succeeds */
    int fd792 = (int)fut_vfs_open(path792, O_PATH_FLAG, 0);
    if (fd792 < 0) {
        fut_printf("[MISC-TEST] ✗ Test 792: open(O_PATH) failed: %d\n", fd792);
        fut_test_fail(792); fut_test_fail(793);
        fut_test_fail(794); fut_test_fail(795);
        return;
    }
    fut_printf("[MISC-TEST] ✓ Test 792: open(O_PATH) → fd=%d\n", fd792);
    fut_test_pass();

    /* Test 793: read() on O_PATH fd → EBADF */
    char buf793[8];
    ssize_t r793 = fut_vfs_read(fd792, buf793, sizeof(buf793));
    if (r793 != -EBADF) {
        fut_printf("[MISC-TEST] ✗ Test 793: read(O_PATH fd) returned %zd (expected -EBADF=%d)\n",
                   r793, -EBADF);
        fut_vfs_close(fd792);
        fut_test_fail(793); fut_test_fail(794); fut_test_fail(795);
        return;
    }
    fut_printf("[MISC-TEST] ✓ Test 793: read(O_PATH fd) → -EBADF\n");
    fut_test_pass();

    /* Test 794: write() on O_PATH fd → EBADF */
    ssize_t w794 = fut_vfs_write(fd792, "y", 1);
    if (w794 != -EBADF) {
        fut_printf("[MISC-TEST] ✗ Test 794: write(O_PATH fd) returned %zd (expected -EBADF=%d)\n",
                   w794, -EBADF);
        fut_vfs_close(fd792);
        fut_test_fail(794); fut_test_fail(795);
        return;
    }
    fut_printf("[MISC-TEST] ✓ Test 794: write(O_PATH fd) → -EBADF\n");
    fut_test_pass();

    /* Test 795: fstat() on O_PATH fd succeeds and shows S_IFREG */
    struct fut_stat st795;
    long ret795 = sys_fstat(fd792, &st795);
    fut_vfs_close(fd792);
    if (ret795 < 0) {
        fut_printf("[MISC-TEST] ✗ Test 795: fstat(O_PATH fd) failed: %ld\n", ret795);
        fut_test_fail(795);
        return;
    }
    if (!S_ISREG(st795.st_mode)) {
        fut_printf("[MISC-TEST] ✗ Test 795: fstat st_mode=0%o not S_IFREG\n", st795.st_mode);
        fut_test_fail(795);
        return;
    }
    fut_printf("[MISC-TEST] ✓ Test 795: fstat(O_PATH fd) → st_mode=0%o (S_IFREG)\n", st795.st_mode);
    fut_test_pass();

#undef O_PATH_FLAG
}

/* ============================================================
 * Tests 796-799: ftruncate/truncate enforce RLIMIT_FSIZE
 *
 *   796: ftruncate within RLIMIT_FSIZE succeeds
 *   797: ftruncate beyond RLIMIT_FSIZE returns EFBIG + SIGXFSZ pending
 *   798: truncate() beyond RLIMIT_FSIZE returns EFBIG + SIGXFSZ pending
 *   799: shrink (ftruncate to 0) always succeeds even with tight RLIMIT_FSIZE
 *
 * POSIX: "If a write() or ftruncate() request would increase the size of
 * a file beyond the value of the soft RLIMIT_FSIZE limit for the process,
 * the request shall fail and the SIGXFSZ signal shall be generated for
 * the process."
 * ============================================================ */
static void test_ftruncate_rlimit_fsize(void) {
    fut_printf("[MISC-TEST] Tests 796-799: ftruncate/truncate RLIMIT_FSIZE enforcement\n");

    /* sys_prlimit64 already declared at file scope with void* parameters */
    extern long sys_sigprocmask(int how, const sigset_t *set, sigset_t *oldset);
    extern long sys_ftruncate(int fd, uint64_t length);
    extern long sys_truncate(const char *path, uint64_t length);

    /* Block SIGXFSZ (signal 25) to prevent default SIG_ACTION_CORE termination */
    sigset_t xfsz_block = { .__mask = 1ULL << (25 - 1) };
    sigset_t saved_mask;
    sys_sigprocmask(0 /* SIG_BLOCK */, &xfsz_block, &saved_mask);

    /* Create a test file */
    const char *path796 = "/tmp/test796_ftrunc.bin";
    int fd796 = (int)fut_vfs_open(path796, O_CREAT | O_RDWR, 0644);
    if (fd796 < 0) {
        fut_printf("[MISC-TEST] ✗ setup: open failed: %d\n", fd796);
        sys_sigprocmask(2 /* SIG_SETMASK */, &saved_mask, NULL);
        fut_test_fail(796); fut_test_fail(797);
        fut_test_fail(798); fut_test_fail(799);
        return;
    }

    /* Set RLIMIT_FSIZE = 100 bytes */
    struct rlimit64_test old_fsize = { 0, 0 }, new_fsize = { 0, 0 };
    sys_prlimit64(0, 1 /* RLIMIT_FSIZE */, NULL, &old_fsize);
    new_fsize.rlim_cur = 100;
    new_fsize.rlim_max = old_fsize.rlim_max;
    sys_prlimit64(0, 1 /* RLIMIT_FSIZE */, &new_fsize, NULL);

    fut_task_t *task796 = fut_task_current();
    uint64_t sigxfsz_bit = 1ULL << (25 - 1);

    /* Test 796: ftruncate to 50 (within limit) → 0 */
    long ret = sys_ftruncate(fd796, 50);
    if (ret != 0) {
        fut_printf("[MISC-TEST] ✗ Test 796: ftruncate(50) within limit returned %ld (expected 0)\n", ret);
        fut_vfs_close(fd796);
        sys_prlimit64(0, 1, &old_fsize, NULL);
        sys_sigprocmask(2, &saved_mask, NULL);
        fut_test_fail(796); fut_test_fail(797);
        fut_test_fail(798); fut_test_fail(799);
        return;
    }
    fut_printf("[MISC-TEST] ✓ Test 796: ftruncate(50) within RLIMIT_FSIZE=100 → 0\n");
    fut_test_pass();

    /* Test 797: ftruncate to 200 (beyond limit) → EFBIG + SIGXFSZ */
    /* Clear any pending SIGXFSZ first */
    if (task796) __atomic_and_fetch(&task796->pending_signals, ~sigxfsz_bit, __ATOMIC_RELEASE);
    ret = sys_ftruncate(fd796, 200);
    if (ret != -EFBIG) {
        fut_printf("[MISC-TEST] ✗ Test 797: ftruncate(200) returned %ld (expected -EFBIG=%d)\n",
                   ret, -EFBIG);
        fut_vfs_close(fd796);
        sys_prlimit64(0, 1, &old_fsize, NULL);
        sys_sigprocmask(2, &saved_mask, NULL);
        fut_test_fail(797); fut_test_fail(798); fut_test_fail(799);
        return;
    }
    /* Verify SIGXFSZ was queued */
    if (task796) {
        uint64_t pending = __atomic_load_n(&task796->pending_signals, __ATOMIC_ACQUIRE);
        if (!(pending & sigxfsz_bit)) {
            fut_printf("[MISC-TEST] ✗ Test 797: SIGXFSZ not pending after ftruncate beyond limit\n");
            fut_vfs_close(fd796);
            sys_prlimit64(0, 1, &old_fsize, NULL);
            sys_sigprocmask(2, &saved_mask, NULL);
            fut_test_fail(797); fut_test_fail(798); fut_test_fail(799);
            return;
        }
        __atomic_and_fetch(&task796->pending_signals, ~sigxfsz_bit, __ATOMIC_RELEASE);
    }
    fut_printf("[MISC-TEST] ✓ Test 797: ftruncate(200) beyond limit → -EFBIG + SIGXFSZ\n");
    fut_test_pass();

    fut_vfs_close(fd796);

    /* Test 798: truncate() beyond limit → EFBIG + SIGXFSZ */
    if (task796) __atomic_and_fetch(&task796->pending_signals, ~sigxfsz_bit, __ATOMIC_RELEASE);
    ret = sys_truncate(path796, 150);
    if (ret != -EFBIG) {
        fut_printf("[MISC-TEST] ✗ Test 798: truncate(150) returned %ld (expected -EFBIG=%d)\n",
                   ret, -EFBIG);
        sys_prlimit64(0, 1, &old_fsize, NULL);
        sys_sigprocmask(2, &saved_mask, NULL);
        fut_test_fail(798); fut_test_fail(799);
        return;
    }
    if (task796) {
        uint64_t pending = __atomic_load_n(&task796->pending_signals, __ATOMIC_ACQUIRE);
        if (!(pending & sigxfsz_bit)) {
            fut_printf("[MISC-TEST] ✗ Test 798: SIGXFSZ not pending after truncate beyond limit\n");
            sys_prlimit64(0, 1, &old_fsize, NULL);
            sys_sigprocmask(2, &saved_mask, NULL);
            fut_test_fail(798); fut_test_fail(799);
            return;
        }
        __atomic_and_fetch(&task796->pending_signals, ~sigxfsz_bit, __ATOMIC_RELEASE);
    }
    fut_printf("[MISC-TEST] ✓ Test 798: truncate(150) beyond limit → -EFBIG + SIGXFSZ\n");
    fut_test_pass();

    /* Test 799: ftruncate to 0 (shrink) always succeeds regardless of limit */
    int fd799 = (int)fut_vfs_open(path796, O_RDWR, 0);
    if (fd799 >= 0) {
        ret = sys_ftruncate(fd799, 0);
        fut_vfs_close(fd799);
        if (ret != 0) {
            fut_printf("[MISC-TEST] ✗ Test 799: ftruncate(0/shrink) returned %ld (expected 0)\n", ret);
            sys_prlimit64(0, 1, &old_fsize, NULL);
            sys_sigprocmask(2, &saved_mask, NULL);
            fut_test_fail(799);
            return;
        }
    }
    fut_printf("[MISC-TEST] ✓ Test 799: ftruncate(0) shrink ignores RLIMIT_FSIZE → 0\n");
    fut_test_pass();

    /* Restore rlimit and signal mask */
    sys_prlimit64(0, 1 /* RLIMIT_FSIZE */, &old_fsize, NULL);
    sys_sigprocmask(2 /* SIG_SETMASK */, &saved_mask, NULL);
}

/* ============================================================
 * test_bind_mount - Tests 804-807
 *
 *   804: mount("/tmp/bind_src", "/tmp/bind_dst", NULL, MS_BIND, NULL) → 0
 *   805: file written in bind source is readable at bind target
 *   806: file written in bind target is readable at bind source
 *   807: umount2("/tmp/bind_dst", 0) → 0
 * ============================================================ */
#define MS_BIND_TEST 4096
static void test_bind_mount(void) {
    extern long sys_mkdir(const char *path, uint32_t mode);
    extern long sys_mount(const char *source, const char *target,
                          const char *filesystemtype, unsigned long mountflags,
                          const void *data);
    extern long sys_umount2(const char *target, int flags);
    extern long sys_open(const char *path, int flags, int mode);
    extern long sys_close(int fd);
    extern ssize_t sys_write(int fd, const void *buf, size_t count);
    extern ssize_t sys_read(int fd, void *buf, size_t count);

    /* Setup: create source and destination directories */
    sys_mkdir("/tmp/bind_src", 0755);
    sys_mkdir("/tmp/bind_dst", 0755);

    /* Test 804: bind mount /tmp/bind_src → /tmp/bind_dst */
    fut_printf("[MISC-TEST] Test 804: MS_BIND mount → 0\n");
    long ret = sys_mount("/tmp/bind_src", "/tmp/bind_dst", NULL, MS_BIND_TEST, NULL);
    if (ret != 0) {
        fut_printf("[MISC-TEST] ✗ Test 804: mount(MS_BIND) returned %ld\n", ret);
        fut_test_fail(804);
    } else {
        fut_printf("[MISC-TEST] ✓ Test 804: bind mount → 0\n");
        fut_test_pass();
    }

    /* Test 805: write to source, read at destination */
    fut_printf("[MISC-TEST] Test 805: write to source, readable at destination\n");
    long fd = sys_open("/tmp/bind_src/hello.txt", 0x241 /* O_WRONLY|O_CREAT|O_TRUNC */, 0644);
    bool t805_ok = false;
    if (fd >= 0) {
        sys_write((int)fd, "hello", 5);
        sys_close((int)fd);
        /* Read from bind destination */
        fd = sys_open("/tmp/bind_dst/hello.txt", 0 /* O_RDONLY */, 0);
        if (fd >= 0) {
            char rbuf[8] = {0};
            ssize_t nr = sys_read((int)fd, rbuf, 5);
            sys_close((int)fd);
            if (nr == 5 && rbuf[0] == 'h' && rbuf[4] == 'o')
                t805_ok = true;
        }
    }
    if (!t805_ok) {
        fut_printf("[MISC-TEST] ✗ Test 805: bind src→dst visibility failed\n");
        fut_test_fail(805);
    } else {
        fut_printf("[MISC-TEST] ✓ Test 805: src write visible at dst\n");
        fut_test_pass();
    }

    /* Test 806: write to destination, read at source */
    fut_printf("[MISC-TEST] Test 806: write to destination, readable at source\n");
    fd = sys_open("/tmp/bind_dst/world.txt", 0x241 /* O_WRONLY|O_CREAT|O_TRUNC */, 0644);
    bool t806_ok = false;
    if (fd >= 0) {
        sys_write((int)fd, "world", 5);
        sys_close((int)fd);
        /* Read from bind source */
        fd = sys_open("/tmp/bind_src/world.txt", 0 /* O_RDONLY */, 0);
        if (fd >= 0) {
            char rbuf[8] = {0};
            ssize_t nr = sys_read((int)fd, rbuf, 5);
            sys_close((int)fd);
            if (nr == 5 && rbuf[0] == 'w' && rbuf[4] == 'd')
                t806_ok = true;
        }
    }
    if (!t806_ok) {
        fut_printf("[MISC-TEST] ✗ Test 806: bind dst→src visibility failed\n");
        fut_test_fail(806);
    } else {
        fut_printf("[MISC-TEST] ✓ Test 806: dst write visible at src\n");
        fut_test_pass();
    }

    /* Test 807: unmount bind destination → 0 */
    fut_printf("[MISC-TEST] Test 807: umount2(\"/tmp/bind_dst\") → 0\n");
    ret = sys_umount2("/tmp/bind_dst", 0);
    if (ret != 0) {
        fut_printf("[MISC-TEST] ✗ Test 807: umount2 returned %ld\n", ret);
        fut_test_fail(807);
    } else {
        fut_printf("[MISC-TEST] ✓ Test 807: umount2 bind → 0\n");
        fut_test_pass();
    }
}

