/* ============================================================
 * Tests 1089-1092: /proc/self/fd/<n> symlink targets for anonymous fds
 *   Test 1089: /proc/self/fd/<n> for socket → "socket:[ino]"
 *   Test 1090: /proc/self/fd/<n> for timerfd → "anon_inode:[timerfd]"
 *   Test 1091: /proc/self/fd/<n> for signalfd → "anon_inode:[signalfd]"
 *   Test 1092: /proc/self/fd/<n> for eventfd → "anon_inode:[eventfd]"
 * ============================================================ */
static int buf_contains(const char *buf, long n, const char *needle, long nlen) {
    for (long j = 0; j + nlen <= n; j++) {
        if (__builtin_memcmp(buf + j, needle, (size_t)nlen) == 0)
            return 1;
    }
    return 0;
}

static void test_proc_fd_anon_symlinks(void) {
    extern long sys_socket(int domain, int type, int protocol);
    extern long sys_timerfd_create(int clockid, int flags);
    extern long sys_signalfd4(int ufd, const void *mask, size_t sizemask, int flags);
    extern long sys_eventfd2(unsigned int initval, int flags);
    extern long sys_readlink(const char *path, char *buf, size_t bufsiz);
    extern long sys_close(int fd);

    /* Helper: build /proc/self/fd/<n> and readlink it */
    char fdpath[64];
    char target[128];

#define BUILD_FD_PATH(fdnum) do { \
    fdpath[0]='/'; fdpath[1]='p'; fdpath[2]='r'; fdpath[3]='o'; fdpath[4]='c'; \
    fdpath[5]='/'; fdpath[6]='s'; fdpath[7]='e'; fdpath[8]='l'; fdpath[9]='f'; \
    fdpath[10]='/'; fdpath[11]='f'; fdpath[12]='d'; fdpath[13]='/'; \
    int _n = (int)(fdnum), _i = 14; \
    if (_n >= 100) fdpath[_i++] = (char)('0' + _n/100); \
    if (_n >= 10)  fdpath[_i++] = (char)('0' + (_n/10)%10); \
    fdpath[_i++] = (char)('0' + _n%10); fdpath[_i] = '\0'; \
} while(0)

    /* ---- Test 1089: socket fd → "socket:[<ino>]" ---- */
    fut_printf("[MISC-TEST] Test 1089: /proc/self/fd socket → 'socket:[ino]'\n");
    {
        long sfd = sys_socket(1 /* AF_UNIX */, 1 /* SOCK_STREAM */, 0);
        if (sfd < 0) {
            fut_printf("[MISC-TEST] ✗ Test 1089: socket() failed: %ld\n", sfd);
            fut_test_fail(1089);
        } else {
            BUILD_FD_PATH(sfd);
            __builtin_memset(target, 0, sizeof(target));
            long rlen = sys_readlink(fdpath, target, sizeof(target) - 1);
            sys_close((int)sfd);
            if (rlen > 0 && buf_contains(target, rlen, "socket:[", 8)) {
                fut_printf("[MISC-TEST] ✓ Test 1089: %s → '%s'\n", fdpath, target);
                fut_test_pass();
            } else {
                fut_printf("[MISC-TEST] ✗ Test 1089: readlink=%ld target='%s' (want 'socket:[...]')\n",
                           rlen, target);
                fut_test_fail(1089);
            }
        }
    }

    /* ---- Test 1090: timerfd → "anon_inode:[timerfd]" ---- */
    fut_printf("[MISC-TEST] Test 1090: /proc/self/fd timerfd → 'anon_inode:[timerfd]'\n");
    {
        long tfd = sys_timerfd_create(1 /* CLOCK_MONOTONIC */, 0);
        if (tfd < 0) {
            fut_printf("[MISC-TEST] ✗ Test 1090: timerfd_create failed: %ld\n", tfd);
            fut_test_fail(1090);
        } else {
            BUILD_FD_PATH(tfd);
            __builtin_memset(target, 0, sizeof(target));
            long rlen = sys_readlink(fdpath, target, sizeof(target) - 1);
            sys_close((int)tfd);
            if (rlen > 0 && buf_contains(target, rlen, "timerfd", 7)) {
                fut_printf("[MISC-TEST] ✓ Test 1090: %s → '%s'\n", fdpath, target);
                fut_test_pass();
            } else {
                fut_printf("[MISC-TEST] ✗ Test 1090: readlink=%ld target='%s' (want 'anon_inode:[timerfd]')\n",
                           rlen, target);
                fut_test_fail(1090);
            }
        }
    }

    /* ---- Test 1091: signalfd → "anon_inode:[signalfd]" ---- */
    fut_printf("[MISC-TEST] Test 1091: /proc/self/fd signalfd → 'anon_inode:[signalfd]'\n");
    {
        uint64_t mask = 1ULL << 9; /* SIGUSR1 */
        long sigfd = sys_signalfd4(-1, &mask, 8, 0);
        if (sigfd < 0) {
            fut_printf("[MISC-TEST] ✗ Test 1091: signalfd4 failed: %ld\n", sigfd);
            fut_test_fail(1091);
        } else {
            BUILD_FD_PATH(sigfd);
            __builtin_memset(target, 0, sizeof(target));
            long rlen = sys_readlink(fdpath, target, sizeof(target) - 1);
            sys_close((int)sigfd);
            if (rlen > 0 && buf_contains(target, rlen, "signalfd", 8)) {
                fut_printf("[MISC-TEST] ✓ Test 1091: %s → '%s'\n", fdpath, target);
                fut_test_pass();
            } else {
                fut_printf("[MISC-TEST] ✗ Test 1091: readlink=%ld target='%s' (want 'anon_inode:[signalfd]')\n",
                           rlen, target);
                fut_test_fail(1091);
            }
        }
    }

    /* ---- Test 1092: eventfd → "anon_inode:[eventfd]" ---- */
    fut_printf("[MISC-TEST] Test 1092: /proc/self/fd eventfd → 'anon_inode:[eventfd]'\n");
    {
        long efd = sys_eventfd2(0, 0);
        if (efd < 0) {
            fut_printf("[MISC-TEST] ✗ Test 1092: eventfd2 failed: %ld\n", efd);
            fut_test_fail(1092);
        } else {
            BUILD_FD_PATH(efd);
            __builtin_memset(target, 0, sizeof(target));
            long rlen = sys_readlink(fdpath, target, sizeof(target) - 1);
            sys_close((int)efd);
            if (rlen > 0 && buf_contains(target, rlen, "eventfd", 7)) {
                fut_printf("[MISC-TEST] ✓ Test 1092: %s → '%s'\n", fdpath, target);
                fut_test_pass();
            } else {
                fut_printf("[MISC-TEST] ✗ Test 1092: readlink=%ld target='%s' (want 'anon_inode:[eventfd]')\n",
                           rlen, target);
                fut_test_fail(1092);
            }
        }
    }

#undef BUILD_FD_PATH
}

/* ============================================================
 * Tests 1093-1096: /proc/self/fdinfo pos: and flags: tracking
 *   Test 1093: fdinfo pos: for regular file is 0 initially
 *   Test 1094: fdinfo pos: for regular file is 100 after lseek(fd,100,SEEK_SET)
 *   Test 1095: fdinfo flags: for pipe read end contains "00" (O_RDONLY)
 *   Test 1096: fdinfo flags: for pipe write end contains "01" (O_WRONLY)
 * ============================================================ */
/* Helper: read /proc/self/fdinfo/<fd_num> into buf; returns bytes read or -errno */
static long read_fdinfo_for_fd(int fd_num, char *buf, size_t bufsz) {
    char path[64];
    path[0]='/'; path[1]='p'; path[2]='r'; path[3]='o'; path[4]='c';
    path[5]='/'; path[6]='s'; path[7]='e'; path[8]='l'; path[9]='f';
    path[10]='/'; path[11]='f'; path[12]='d'; path[13]='i';
    path[14]='n'; path[15]='f'; path[16]='o'; path[17]='/';
    int n = fd_num, i = 18;
    if (n >= 100) { path[i++] = (char)('0' + n/100); n %= 100; }
    if (n >= 10)  { path[i++] = (char)('0' + n/10);  n %= 10; }
    path[i++] = (char)('0' + n);
    path[i] = '\0';
    int ifd = fut_vfs_open(path, O_RDONLY, 0);
    if (ifd < 0) return (long)ifd;
    long nr = fut_vfs_read(ifd, buf, (long)(bufsz - 1));
    fut_vfs_close(ifd);
    if (nr > 0) buf[nr] = '\0';
    return nr;
}

static void test_fdinfo_pos_flags(void) {
    extern int64_t fut_vfs_lseek(int fd, int64_t offset, int whence);
    extern long sys_pipe(int pipefd[2]);

    /* ---- Test 1093: fdinfo pos: = 0 for fresh regular file ---- */
    fut_printf("[MISC-TEST] Test 1093: fdinfo pos: = 0 for fresh regular file\n");
    {
        int fd = fut_vfs_open("/tmp/fdinfo_pos_test", O_CREAT | O_RDWR | O_TRUNC, 0600);
        if (fd < 0) {
            fut_printf("[MISC-TEST] ✗ Test 1093: open failed: %d\n", fd);
            fut_test_fail(1093);
            goto t1094;
        }
        char buf[256];
        long nr = read_fdinfo_for_fd(fd, buf, sizeof(buf));
        fut_vfs_close(fd);
        fut_vfs_unlink("/tmp/fdinfo_pos_test");
        if (nr <= 0) {
            fut_printf("[MISC-TEST] ✗ Test 1093: read fdinfo failed: %ld\n", nr);
            fut_test_fail(1093);
            goto t1094;
        }
        /* Check "pos:\t0" (offset 0) is present */
        int found = 0;
        for (long j = 0; j + 6 <= nr; j++) {
            if (buf[j]=='p' && buf[j+1]=='o' && buf[j+2]=='s' &&
                buf[j+3]==':' && buf[j+4]=='\t' && buf[j+5]=='0') {
                found = 1; break;
            }
        }
        if (!found) {
            fut_printf("[MISC-TEST] ✗ Test 1093: pos:\\t0 not found in fdinfo: '%s'\n", buf);
            fut_test_fail(1093);
        } else {
            fut_printf("[MISC-TEST] ✓ Test 1093: fdinfo pos:\\t0 present for fresh file\n");
            fut_test_pass();
        }
    }
t1094:
    /* ---- Test 1094: fdinfo pos: = 100 after lseek ---- */
    fut_printf("[MISC-TEST] Test 1094: fdinfo pos: = 100 after lseek(fd, 100, SEEK_SET)\n");
    {
        int fd = fut_vfs_open("/tmp/fdinfo_pos_test2", O_CREAT | O_RDWR | O_TRUNC, 0600);
        if (fd < 0) {
            fut_printf("[MISC-TEST] ✗ Test 1094: open failed: %d\n", fd);
            fut_test_fail(1094);
            goto t1095;
        }
        int64_t pos = fut_vfs_lseek(fd, 100, 0 /* SEEK_SET */);
        if (pos != 100) {
            fut_printf("[MISC-TEST] ✗ Test 1094: lseek returned %lld (expected 100)\n",
                       (long long)pos);
            fut_vfs_close(fd);
            fut_vfs_unlink("/tmp/fdinfo_pos_test2");
            fut_test_fail(1094);
            goto t1095;
        }
        char buf[256];
        long nr = read_fdinfo_for_fd(fd, buf, sizeof(buf));
        fut_vfs_close(fd);
        fut_vfs_unlink("/tmp/fdinfo_pos_test2");
        if (nr <= 0) {
            fut_printf("[MISC-TEST] ✗ Test 1094: read fdinfo failed: %ld\n", nr);
            fut_test_fail(1094);
            goto t1095;
        }
        /* Check "pos:\t100" is present */
        int found = 0;
        for (long j = 0; j + 9 <= nr; j++) {
            if (buf[j]=='p' && buf[j+1]=='o' && buf[j+2]=='s' &&
                buf[j+3]==':' && buf[j+4]=='\t' &&
                buf[j+5]=='1' && buf[j+6]=='0' && buf[j+7]=='0') {
                found = 1; break;
            }
        }
        if (!found) {
            fut_printf("[MISC-TEST] ✗ Test 1094: pos:\\t100 not found in fdinfo: '%s'\n", buf);
            fut_test_fail(1094);
        } else {
            fut_printf("[MISC-TEST] ✓ Test 1094: fdinfo pos:\\t100 present after lseek\n");
            fut_test_pass();
        }
    }
t1095:
    /* ---- Test 1095: fdinfo flags for pipe read end (O_RDONLY) ---- */
    fut_printf("[MISC-TEST] Test 1095: fdinfo flags: for pipe read end has 'flags:'\n");
    {
        int pipefd[2] = { -1, -1 };
        long r = sys_pipe(pipefd);
        if (r != 0 || pipefd[0] < 0) {
            fut_printf("[MISC-TEST] ✗ Test 1095: pipe() failed: %ld\n", r);
            fut_test_fail(1095);
            goto t1096;
        }
        char buf[256];
        long nr = read_fdinfo_for_fd(pipefd[0], buf, sizeof(buf));
        fut_vfs_close(pipefd[0]);
        fut_vfs_close(pipefd[1]);
        if (nr <= 0) {
            fut_printf("[MISC-TEST] ✗ Test 1095: read fdinfo for pipe read end failed: %ld\n", nr);
            fut_test_fail(1095);
            goto t1096;
        }
        /* Check "flags:" is present (pipe fds have flags) */
        int found = 0;
        for (long j = 0; j + 6 <= nr; j++) {
            if (buf[j]=='f' && buf[j+1]=='l' && buf[j+2]=='a' &&
                buf[j+3]=='g' && buf[j+4]=='s' && buf[j+5]==':') {
                found = 1; break;
            }
        }
        if (!found) {
            fut_printf("[MISC-TEST] ✗ Test 1095: 'flags:' not found in pipe read fdinfo\n");
            fut_test_fail(1095);
        } else {
            fut_printf("[MISC-TEST] ✓ Test 1095: pipe read end fdinfo has 'flags:'\n");
            fut_test_pass();
        }
    }
t1096:
    /* ---- Test 1096: fdinfo flags for pipe write end shows O_WRONLY ---- */
    fut_printf("[MISC-TEST] Test 1096: fdinfo flags: for pipe write end shows O_WRONLY (01)\n");
    {
        int pipefd[2] = { -1, -1 };
        long r = sys_pipe(pipefd);
        if (r != 0 || pipefd[1] < 0) {
            fut_printf("[MISC-TEST] ✗ Test 1096: pipe() failed: %ld\n", r);
            fut_test_fail(1096);
            return;
        }
        char buf[256];
        long nr = read_fdinfo_for_fd(pipefd[1], buf, sizeof(buf));
        fut_vfs_close(pipefd[0]);
        fut_vfs_close(pipefd[1]);
        if (nr <= 0) {
            fut_printf("[MISC-TEST] ✗ Test 1096: read fdinfo for pipe write end failed: %ld\n", nr);
            fut_test_fail(1096);
            return;
        }
        /* Check "flags:\t01" is present — O_WRONLY=1 in octal is "01",
         * and procfs emits "flags:\t0" + pb_oct(flags), so "flags:\t01" for O_WRONLY */
        int found = 0;
        for (long j = 0; j + 8 <= nr; j++) {
            if (buf[j]=='f' && buf[j+1]=='l' && buf[j+2]=='a' && buf[j+3]=='g' &&
                buf[j+4]=='s' && buf[j+5]==':' && buf[j+6]=='\t' &&
                buf[j+7]=='0' && buf[j+8]=='1') {
                found = 1; break;
            }
        }
        if (!found) {
            fut_printf("[MISC-TEST] ✗ Test 1096: 'flags:\\t01' not in pipe write fdinfo: '%s'\n",
                       buf);
            fut_test_fail(1096);
        } else {
            fut_printf("[MISC-TEST] ✓ Test 1096: pipe write end fdinfo has 'flags:\\t01'\n");
            fut_test_pass();
        }
    }
}

/* ============================================================
 * Tests 1097-1100: SA_RESTART flag roundtrip and SigBlk: accuracy
 *   Test 1097: SA_RESTART flag stored/read back by sigaction
 *   Test 1098: SA_RESTART|SA_NODEFER combined flags roundtrip
 *   Test 1099: /proc/self/status SigBlk: reflects blocked SIGUSR1
 *   Test 1100: /proc/self/status SigBlk: shows 0 after unblocking
 * ============================================================ */

/* Parse a 16-digit hex field value from /proc/self/status.
 * Looks for "<field>:\t" in buf[0..n], parses the following hex string.
 * Returns the parsed 64-bit value, or UINT64_MAX on failure. */
static uint64_t status_parse_hex_field(const char *buf, long n,
                                       const char *field, size_t flen)
{
    for (long i = 0; i + (long)flen + 2 <= n; i++) {
        int match = 1;
        for (size_t j = 0; j < flen; j++) {
            if (buf[i + (long)j] != field[j]) { match = 0; break; }
        }
        if (!match) continue;
        /* Found field name; expect ":\t" immediately after */
        if (buf[i + (long)flen] != ':' || buf[i + (long)flen + 1] != '\t') continue;
        /* Parse hex digits that follow */
        long k = i + (long)flen + 2;
        uint64_t val = 0;
        int digits = 0;
        while (k < n && digits < 16) {
            char c = buf[k++];
            if (c >= '0' && c <= '9') { val = (val << 4) | (uint64_t)(c - '0'); digits++; }
            else if (c >= 'a' && c <= 'f') { val = (val << 4) | (uint64_t)(c - 'a' + 10); digits++; }
            else if (c >= 'A' && c <= 'F') { val = (val << 4) | (uint64_t)(c - 'A' + 10); digits++; }
            else break;
        }
        if (digits > 0) return val;
    }
    return (uint64_t)-1;
}

static void dummy_handler_restart(int sig) { (void)sig; }

static void test_sa_restart_and_sigblk(void) {
    extern long sys_sigaction(int signum, const void *act, void *oldact);
    extern long sys_sigprocmask(int how, const sigset_t *set, sigset_t *oldset);

#define SA_RESTART_FLAG    0x10000000UL
#define SA_NODEFER_FLAG2   0x40000000UL

    struct sa_t {
        void (*sa_handler)(int);
        unsigned long sa_flags;
        void (*sa_restorer)(void);
        uint64_t sa_mask;
    };

    /* ---- Test 1097: SA_RESTART flag roundtrip ---- */
    fut_printf("[MISC-TEST] Test 1097: SA_RESTART flag stored/read back by sigaction\n");
    {
        struct sa_t act = {0}, got = {0};
        act.sa_handler = dummy_handler_restart;
        act.sa_flags   = SA_RESTART_FLAG;
        long r = sys_sigaction(10 /* SIGUSR1 */, &act, NULL);
        if (r != 0) {
            fut_printf("[MISC-TEST] ✗ Test 1097: sigaction set failed: %ld\n", r);
            fut_test_fail(1097);
        } else {
            r = sys_sigaction(10, NULL, &got);
            if (r != 0 || !(got.sa_flags & SA_RESTART_FLAG)) {
                fut_printf("[MISC-TEST] ✗ Test 1097: SA_RESTART not preserved, flags=0x%lx ret=%ld\n",
                           got.sa_flags, r);
                fut_test_fail(1097);
            } else {
                fut_printf("[MISC-TEST] ✓ Test 1097: SA_RESTART flag preserved (0x%lx)\n", got.sa_flags);
                fut_test_pass();
            }
        }
        /* Restore default */
        struct sa_t def = {0};
        def.sa_handler = (void (*)(int))0; /* SIG_DFL */
        sys_sigaction(10, &def, NULL);
    }

    /* ---- Test 1098: SA_RESTART|SA_NODEFER combined roundtrip ---- */
    fut_printf("[MISC-TEST] Test 1098: SA_RESTART|SA_NODEFER combined flags roundtrip\n");
    {
        struct sa_t act = {0}, got = {0};
        act.sa_handler = dummy_handler_restart;
        act.sa_flags   = SA_RESTART_FLAG | SA_NODEFER_FLAG2;
        long r = sys_sigaction(10, &act, NULL);
        if (r != 0) {
            fut_printf("[MISC-TEST] ✗ Test 1098: sigaction set failed: %ld\n", r);
            fut_test_fail(1098);
        } else {
            r = sys_sigaction(10, NULL, &got);
            int restart_ok  = (got.sa_flags & SA_RESTART_FLAG)  != 0;
            int nodefer_ok  = (got.sa_flags & SA_NODEFER_FLAG2)  != 0;
            if (r != 0 || !restart_ok || !nodefer_ok) {
                fut_printf("[MISC-TEST] ✗ Test 1098: flags=0x%lx (want SA_RESTART|SA_NODEFER)\n",
                           got.sa_flags);
                fut_test_fail(1098);
            } else {
                fut_printf("[MISC-TEST] ✓ Test 1098: SA_RESTART|SA_NODEFER preserved (0x%lx)\n",
                           got.sa_flags);
                fut_test_pass();
            }
        }
        struct sa_t def = {0};
        sys_sigaction(10, &def, NULL);
    }

    /* ---- Test 1099: SigBlk: in /proc/self/status after blocking SIGUSR1 ---- */
    fut_printf("[MISC-TEST] Test 1099: /proc/self/status SigBlk: reflects blocked SIGUSR1\n");
    {
        /* Block SIGUSR1 (signal 10 → bit 9) */
        sigset_t block_set = { .__mask = (1ULL << (10 - 1)) };
        sigset_t old_set = {0};
        long r = sys_sigprocmask(0 /* SIG_BLOCK */, &block_set, &old_set);
        if (r != 0) {
            fut_printf("[MISC-TEST] ✗ Test 1099: sigprocmask(SIG_BLOCK) failed: %ld\n", r);
            fut_test_fail(1099);
            goto t1100;
        }
        /* Read /proc/self/status */
        int fd = fut_vfs_open("/proc/self/status", 0, 0);
        if (fd < 0) {
            fut_printf("[MISC-TEST] ✗ Test 1099: open /proc/self/status failed: %d\n", fd);
            sys_sigprocmask(2 /* SIG_SETMASK */, &old_set, NULL);
            fut_test_fail(1099);
            goto t1100;
        }
        char buf[2048];
        long n = fut_vfs_read(fd, buf, sizeof(buf) - 1);
        fut_vfs_close(fd);
        if (n <= 0) {
            fut_printf("[MISC-TEST] ✗ Test 1099: read status failed: %ld\n", n);
            sys_sigprocmask(2, &old_set, NULL);
            fut_test_fail(1099);
            goto t1100;
        }
        buf[n] = '\0';
        uint64_t sigblk = status_parse_hex_field(buf, n, "SigBlk", 6);
        sys_sigprocmask(2 /* SIG_SETMASK */, &old_set, NULL);
        /* SIGUSR1 = signal 10 → bit 9 (0-indexed) = 0x200 */
        if (sigblk == (uint64_t)-1) {
            fut_printf("[MISC-TEST] ✗ Test 1099: SigBlk: not found in status\n");
            fut_test_fail(1099);
        } else if (!(sigblk & 0x200ULL)) {
            fut_printf("[MISC-TEST] ✗ Test 1099: SigBlk=0x%llx missing SIGUSR1 bit (0x200)\n",
                       (unsigned long long)sigblk);
            fut_test_fail(1099);
        } else {
            fut_printf("[MISC-TEST] ✓ Test 1099: SigBlk=0x%llx has SIGUSR1 bit set\n",
                       (unsigned long long)sigblk);
            fut_test_pass();
        }
    }
t1100:
    /* ---- Test 1100: SigBlk: shows 0 for SIGUSR1 after unblocking ---- */
    fut_printf("[MISC-TEST] Test 1100: /proc/self/status SigBlk: clear after unblocking SIGUSR1\n");
    {
        /* Ensure SIGUSR1 is unblocked */
        sigset_t unblock_set = { .__mask = (1ULL << (10 - 1)) };
        sys_sigprocmask(1 /* SIG_UNBLOCK */, &unblock_set, NULL);
        /* Read /proc/self/status */
        int fd = fut_vfs_open("/proc/self/status", 0, 0);
        if (fd < 0) {
            fut_printf("[MISC-TEST] ✗ Test 1100: open /proc/self/status failed: %d\n", fd);
            fut_test_fail(1100);
            return;
        }
        char buf[2048];
        long n = fut_vfs_read(fd, buf, sizeof(buf) - 1);
        fut_vfs_close(fd);
        if (n <= 0) {
            fut_printf("[MISC-TEST] ✗ Test 1100: read status failed: %ld\n", n);
            fut_test_fail(1100);
            return;
        }
        buf[n] = '\0';
        uint64_t sigblk = status_parse_hex_field(buf, n, "SigBlk", 6);
        if (sigblk == (uint64_t)-1) {
            fut_printf("[MISC-TEST] ✗ Test 1100: SigBlk: not found in status\n");
            fut_test_fail(1100);
        } else if (sigblk & 0x200ULL) {
            fut_printf("[MISC-TEST] ✗ Test 1100: SigBlk=0x%llx still has SIGUSR1 bit after unblock\n",
                       (unsigned long long)sigblk);
            fut_test_fail(1100);
        } else {
            fut_printf("[MISC-TEST] ✓ Test 1100: SigBlk=0x%llx SIGUSR1 bit clear\n",
                       (unsigned long long)sigblk);
            fut_test_pass();
        }
    }

#undef SA_RESTART_FLAG
#undef SA_NODEFER_FLAG2
}

/* ============================================================
 * Tests 1101-1104: sched_setscheduler SCHED_BATCH and SCHED_IDLE roundtrip
 *   Test 1101: sched_setscheduler(0, SCHED_BATCH, {0}) returns old policy
 *   Test 1102: sched_getscheduler(0) returns SCHED_BATCH after setting it
 *   Test 1103: sched_setscheduler(0, SCHED_IDLE, {0}) returns old policy
 *   Test 1104: sched_setscheduler(0, SCHED_OTHER, {0}) restores default
 * ============================================================ */
static void test_sched_batch_idle_roundtrip(void) {
    extern long sys_sched_setscheduler(int pid, int policy, const struct sched_param *param);
    extern long sys_sched_getscheduler(int pid);
    struct sched_param zero_param;
    __builtin_memset(&zero_param, 0, sizeof(zero_param));

#ifndef SCHED_BATCH
#define SCHED_BATCH 3
#endif
#ifndef SCHED_IDLE
#define SCHED_IDLE  5
#endif

    /* ---- Test 1101: set SCHED_BATCH → returns old policy ---- */
    fut_printf("[MISC-TEST] Test 1101: sched_setscheduler(SCHED_BATCH) returns old policy\n");
    {
        long old_pol = sys_sched_setscheduler(0, SCHED_BATCH, &zero_param);
        if (old_pol < 0) {
            fut_printf("[MISC-TEST] ✗ Test 1101: sched_setscheduler(SCHED_BATCH) returned %ld\n",
                       old_pol);
            fut_test_fail(1101);
        } else {
            fut_printf("[MISC-TEST] ✓ Test 1101: sched_setscheduler(SCHED_BATCH) old_policy=%ld\n",
                       old_pol);
            fut_test_pass();
        }
    }

    /* ---- Test 1102: getscheduler returns SCHED_BATCH ---- */
    fut_printf("[MISC-TEST] Test 1102: sched_getscheduler returns SCHED_BATCH after setting it\n");
    {
        long pol = sys_sched_getscheduler(0);
        if (pol != SCHED_BATCH) {
            fut_printf("[MISC-TEST] ✗ Test 1102: getscheduler=%ld (expected SCHED_BATCH=%d)\n",
                       pol, SCHED_BATCH);
            fut_test_fail(1102);
        } else {
            fut_printf("[MISC-TEST] ✓ Test 1102: getscheduler → SCHED_BATCH (%ld)\n", pol);
            fut_test_pass();
        }
    }

    /* ---- Test 1103: set SCHED_IDLE → returns old policy ---- */
    fut_printf("[MISC-TEST] Test 1103: sched_setscheduler(SCHED_IDLE) returns old policy\n");
    {
        long old_pol = sys_sched_setscheduler(0, SCHED_IDLE, &zero_param);
        if (old_pol < 0) {
            fut_printf("[MISC-TEST] ✗ Test 1103: sched_setscheduler(SCHED_IDLE) returned %ld\n",
                       old_pol);
            fut_test_fail(1103);
        } else {
            fut_printf("[MISC-TEST] ✓ Test 1103: sched_setscheduler(SCHED_IDLE) old_policy=%ld\n",
                       old_pol);
            fut_test_pass();
        }
    }

    /* ---- Test 1104: restore SCHED_OTHER, verify ---- */
    fut_printf("[MISC-TEST] Test 1104: sched_setscheduler restores SCHED_OTHER\n");
    {
        long r = sys_sched_setscheduler(0, 0 /* SCHED_OTHER */, &zero_param);
        long pol = sys_sched_getscheduler(0);
        if (r < 0 || pol != 0) {
            fut_printf("[MISC-TEST] ✗ Test 1104: restore SCHED_OTHER: ret=%ld getscheduler=%ld\n",
                       r, pol);
            fut_test_fail(1104);
        } else {
            fut_printf("[MISC-TEST] ✓ Test 1104: restored to SCHED_OTHER (%ld)\n", pol);
            fut_test_pass();
        }
    }
}

