/* ============================================================
 * Tests 1517-1522: AF_INET TCP getsockname/getpeername/shutdown
 * ============================================================ */
static void test_af_inet_tcp_extended(void) {
    fut_printf("[MISC-TEST] Tests 1517-1522: AF_INET TCP getsockname/getpeername/shutdown\n");
    extern long sys_socket(int domain, int type, int protocol);
    extern long sys_bind(int sockfd, const void *addr, unsigned int addrlen);
    extern long sys_listen(int sockfd, int backlog);
    extern long sys_connect(int sockfd, const void *addr, unsigned int addrlen);
    extern long sys_accept(int sockfd, void *addr, unsigned int *addrlen);
    extern long sys_getsockname(int sockfd, void *addr, unsigned int *addrlen);
    extern long sys_getpeername(int sockfd, void *addr, unsigned int *addrlen);
    extern long sys_shutdown(int sockfd, int how);
    extern long sys_write(int fd, const void *buf, unsigned long count);
    extern long sys_read(int fd, void *buf, unsigned long count);
    extern long sys_close(int fd);

    struct { uint16_t sin_family; uint16_t sin_port; uint32_t sin_addr; uint8_t sin_zero[8]; } addr;
    unsigned int addrlen;

    /* Set up: server binds port 12346, listens, client connects, server accepts */
    long server_fd = sys_socket(2, 1, 0);
    if (server_fd < 0) { fut_test_fail(1517); return; }
    __builtin_memset(&addr, 0, sizeof(addr));
    addr.sin_family = 2;
    addr.sin_port = test_htons(12346);
    addr.sin_addr = 0;
    if (sys_bind((int)server_fd, &addr, 16) != 0) {
        sys_close((int)server_fd); fut_test_fail(1517); return;
    }
    if (sys_listen((int)server_fd, 5) != 0) {
        sys_close((int)server_fd); fut_test_fail(1517); return;
    }

    long client_fd = sys_socket(2, 1, 0);
    if (client_fd < 0) {
        sys_close((int)server_fd); fut_test_fail(1517); return;
    }
    __builtin_memset(&addr, 0, sizeof(addr));
    addr.sin_family = 2;
    addr.sin_port = test_htons(12346);
    addr.sin_addr = 0;
    if (sys_connect((int)client_fd, &addr, 16) != 0) {
        sys_close((int)client_fd); sys_close((int)server_fd);
        fut_test_fail(1517); return;
    }

    struct { uint16_t sin_family; uint16_t sin_port; uint32_t sin_addr; uint8_t sin_zero[8]; } peer_addr;
    unsigned int peer_len = 16;
    __builtin_memset(&peer_addr, 0, sizeof(peer_addr));
    long accepted_fd = sys_accept((int)server_fd, &peer_addr, &peer_len);
    if (accepted_fd < 0) {
        sys_close((int)client_fd); sys_close((int)server_fd);
        fut_test_fail(1517); return;
    }

    /* Test 1517: getsockname on client → ephemeral port >= 49152 */
    __builtin_memset(&addr, 0, sizeof(addr));
    addrlen = 16;
    long ret = sys_getsockname((int)client_fd, &addr, &addrlen);
    uint16_t client_port = test_htons(addr.sin_port);
    /* Client gets an ephemeral port from ip_local_port_range (sysctl, default 32768-60999) */
    if (ret != 0 || addr.sin_family != 2 || client_port < g_net_sysctl.port_range_min) {
        fut_printf("[MISC-TEST] ✗ Test 1517: getsockname(client) → ret=%ld family=%u port=%u\n",
                   ret, addr.sin_family, client_port);
        sys_close((int)accepted_fd); sys_close((int)client_fd); sys_close((int)server_fd);
        fut_test_fail(1517); return;
    }
    fut_printf("[MISC-TEST] ✓ Test 1517: getsockname(client) → AF_INET port=%u\n", client_port);
    fut_test_pass();

    /* Test 1518: getpeername on accepted → client's ephemeral port */
    __builtin_memset(&addr, 0, sizeof(addr));
    addrlen = 16;
    ret = sys_getpeername((int)accepted_fd, &addr, &addrlen);
    uint16_t reported_peer_port = test_htons(addr.sin_port);
    if (ret != 0 || addr.sin_family != 2 || reported_peer_port != client_port) {
        fut_printf("[MISC-TEST] ✗ Test 1518: getpeername(accepted) → ret=%ld family=%u port=%u (expected %u)\n",
                   ret, addr.sin_family, reported_peer_port, client_port);
        sys_close((int)accepted_fd); sys_close((int)client_fd); sys_close((int)server_fd);
        fut_test_fail(1518); return;
    }
    fut_printf("[MISC-TEST] ✓ Test 1518: getpeername(accepted) → client port=%u\n", reported_peer_port);
    fut_test_pass();

    /* Test 1519: getpeername on client → server port 12346 */
    __builtin_memset(&addr, 0, sizeof(addr));
    addrlen = 16;
    ret = sys_getpeername((int)client_fd, &addr, &addrlen);
    uint16_t reported_server_port = test_htons(addr.sin_port);
    if (ret != 0 || addr.sin_family != 2 || reported_server_port != 12346) {
        fut_printf("[MISC-TEST] ✗ Test 1519: getpeername(client) → ret=%ld family=%u port=%u (expected 12346)\n",
                   ret, addr.sin_family, reported_server_port);
        sys_close((int)accepted_fd); sys_close((int)client_fd); sys_close((int)server_fd);
        fut_test_fail(1519); return;
    }
    fut_printf("[MISC-TEST] ✓ Test 1519: getpeername(client) → server port=12346\n");
    fut_test_pass();

    /* Test 1520: getsockname on accepted → server port 12346 */
    __builtin_memset(&addr, 0, sizeof(addr));
    addrlen = 16;
    ret = sys_getsockname((int)accepted_fd, &addr, &addrlen);
    uint16_t accepted_local_port = test_htons(addr.sin_port);
    if (ret != 0 || addr.sin_family != 2 || accepted_local_port != 12346) {
        fut_printf("[MISC-TEST] ✗ Test 1520: getsockname(accepted) → ret=%ld family=%u port=%u (expected 12346)\n",
                   ret, addr.sin_family, accepted_local_port);
        sys_close((int)accepted_fd); sys_close((int)client_fd); sys_close((int)server_fd);
        fut_test_fail(1520); return;
    }
    fut_printf("[MISC-TEST] ✓ Test 1520: getsockname(accepted) → server port=12346\n");
    fut_test_pass();

    /* Test 1521: shutdown(SHUT_WR) on accepted → client read returns 0 (EOF) */
    ret = sys_shutdown((int)accepted_fd, 1 /* SHUT_WR */);
    if (ret != 0) {
        fut_printf("[MISC-TEST] ✗ Test 1521: shutdown(accepted, SHUT_WR) → %ld\n", ret);
        sys_close((int)accepted_fd); sys_close((int)client_fd); sys_close((int)server_fd);
        fut_test_fail(1521); return;
    }
    char buf[16] = {0};
    long rr = sys_read((int)client_fd, buf, 16);
    if (rr != 0) {
        fut_printf("[MISC-TEST] ✗ Test 1521: read(client) after shutdown → %ld (expected 0 EOF)\n", rr);
        sys_close((int)accepted_fd); sys_close((int)client_fd); sys_close((int)server_fd);
        fut_test_fail(1521); return;
    }
    fut_printf("[MISC-TEST] ✓ Test 1521: shutdown(SHUT_WR) → client read returns 0 (EOF)\n");
    fut_test_pass();

    /* Test 1522: client can still write after server SHUT_WR (half-close) */
    long wr = sys_write((int)client_fd, "ping", 4);
    __builtin_memset(buf, 0, 16);
    rr = sys_read((int)accepted_fd, buf, 16);
    if (wr != 4 || rr != 4 || __builtin_memcmp(buf, "ping", 4) != 0) {
        fut_printf("[MISC-TEST] ✗ Test 1522: half-close write/read → wr=%ld rr=%ld\n", wr, rr);
        sys_close((int)accepted_fd); sys_close((int)client_fd); sys_close((int)server_fd);
        fut_test_fail(1522); return;
    }
    fut_printf("[MISC-TEST] ✓ Test 1522: half-close: client→server write/read still works\n");
    fut_test_pass();

    sys_close((int)accepted_fd);
    sys_close((int)client_fd);
    sys_close((int)server_fd);
}

/* ============================================================
 * Tests 1523-1530: AF_INET edge cases — nonblocking, port 0,
 *                  SO_REUSEADDR, multi-accept
 * ============================================================ */
static void test_af_inet_edge_cases(void) {
    fut_printf("[MISC-TEST] Tests 1523-1530: AF_INET edge cases\n");
    extern long sys_socket(int domain, int type, int protocol);
    extern long sys_bind(int sockfd, const void *addr, unsigned int addrlen);
    extern long sys_listen(int sockfd, int backlog);
    extern long sys_connect(int sockfd, const void *addr, unsigned int addrlen);
    extern long sys_accept(int sockfd, void *addr, unsigned int *addrlen);
    extern long sys_getsockname(int sockfd, void *addr, unsigned int *addrlen);
    extern long sys_setsockopt(int sockfd, int level, int optname,
                               const void *optval, unsigned int optlen);
    extern long sys_read(int fd, void *buf, unsigned long count);
    extern long sys_write(int fd, const void *buf, unsigned long count);
    extern long sys_close(int fd);
    extern long sys_fcntl(int fd, int cmd, unsigned long arg);

    struct { uint16_t sin_family; uint16_t sin_port; uint32_t sin_addr; uint8_t sin_zero[8]; } addr;
    unsigned int addrlen;

    /* Test 1523: SOCK_NONBLOCK — recv on empty connected socket returns EAGAIN */
    {
        long srv = sys_socket(2, 1, 0);  /* server: blocking */
        if (srv < 0) { fut_test_fail(1523); goto t1524; }
        __builtin_memset(&addr, 0, sizeof(addr));
        addr.sin_family = 2;
        addr.sin_port = test_htons(12350);
        if (sys_bind((int)srv, &addr, 16) != 0 || sys_listen((int)srv, 5) != 0) {
            sys_close((int)srv); fut_test_fail(1523); goto t1524;
        }
        /* client: SOCK_NONBLOCK (0x800) */
        long cli = sys_socket(2, 1 | 0x800, 0);
        if (cli < 0) { sys_close((int)srv); fut_test_fail(1523); goto t1524; }
        __builtin_memset(&addr, 0, sizeof(addr));
        addr.sin_family = 2; addr.sin_port = test_htons(12350);
        if (sys_connect((int)cli, &addr, 16) != 0) {
            sys_close((int)cli); sys_close((int)srv); fut_test_fail(1523); goto t1524;
        }
        unsigned int al = 16;
        long acc = sys_accept((int)srv, &addr, &al);
        if (acc < 0) { sys_close((int)cli); sys_close((int)srv); fut_test_fail(1523); goto t1524; }
        /* Read on nonblocking client with no data → EAGAIN (-11) */
        char buf[16];
        long rr = sys_read((int)cli, buf, 16);
        if (rr == -11 /* EAGAIN */) {
            fut_printf("[MISC-TEST] ✓ Test 1523: nonblocking recv on empty socket → EAGAIN\n");
            fut_test_pass();
        } else {
            fut_printf("[MISC-TEST] ✗ Test 1523: nonblocking recv → %ld (expected -11 EAGAIN)\n", rr);
            fut_test_fail(1523);
        }
        sys_close((int)acc); sys_close((int)cli); sys_close((int)srv);
    }

t1524:
    /* Test 1524: listen on port 0 → auto-assigned port via getsockname */
    {
        long fd = sys_socket(2, 1, 0);
        if (fd < 0) { fut_test_fail(1524); goto t1525; }
        __builtin_memset(&addr, 0, sizeof(addr));
        addr.sin_family = 2; addr.sin_port = 0; addr.sin_addr = 0;
        if (sys_bind((int)fd, &addr, 16) != 0) {
            sys_close((int)fd); fut_test_fail(1524); goto t1525;
        }
        __builtin_memset(&addr, 0, sizeof(addr));
        addrlen = 16;
        long ret = sys_getsockname((int)fd, &addr, &addrlen);
        uint16_t assigned = test_htons(addr.sin_port);
        if (ret == 0 && assigned >= g_net_sysctl.port_range_min) {
            fut_printf("[MISC-TEST] ✓ Test 1524: bind(port=0) → auto port=%u\n", assigned);
            fut_test_pass();
        } else {
            fut_printf("[MISC-TEST] ✗ Test 1524: bind(port=0) → ret=%ld port=%u\n", ret, assigned);
            fut_test_fail(1524);
        }
        sys_close((int)fd);
    }

t1525:
    /* Test 1525: SO_REUSEADDR allows rebinding to a just-freed port */
    {
        /* First, bind to port 12351 and close */
        long fd1 = sys_socket(2, 1, 0);
        if (fd1 < 0) { fut_test_fail(1525); goto t1526; }
        __builtin_memset(&addr, 0, sizeof(addr));
        addr.sin_family = 2; addr.sin_port = test_htons(12351);
        if (sys_bind((int)fd1, &addr, 16) != 0) {
            sys_close((int)fd1); fut_test_fail(1525); goto t1526;
        }
        sys_close((int)fd1);

        /* Now rebind to same port with SO_REUSEADDR */
        long fd2 = sys_socket(2, 1, 0);
        if (fd2 < 0) { fut_test_fail(1525); goto t1526; }
        int optval = 1;
        sys_setsockopt((int)fd2, 1 /*SOL_SOCKET*/, 2 /*SO_REUSEADDR*/, &optval, 4);
        long br = sys_bind((int)fd2, &addr, 16);
        if (br == 0) {
            fut_printf("[MISC-TEST] ✓ Test 1525: SO_REUSEADDR allows rebind to port 12351\n");
            fut_test_pass();
        } else {
            fut_printf("[MISC-TEST] ✗ Test 1525: rebind with REUSEADDR → %ld\n", br);
            fut_test_fail(1525);
        }
        sys_close((int)fd2);
    }

t1526:
    /* Test 1526: multi-client accept — two clients connect, two accepts */
    {
        long srv = sys_socket(2, 1, 0);
        if (srv < 0) { fut_test_fail(1526); goto t1527; }
        __builtin_memset(&addr, 0, sizeof(addr));
        addr.sin_family = 2; addr.sin_port = test_htons(12352);
        if (sys_bind((int)srv, &addr, 16) != 0 || sys_listen((int)srv, 5) != 0) {
            sys_close((int)srv); fut_test_fail(1526); goto t1527;
        }
        /* Connect two clients */
        long c1 = sys_socket(2, 1, 0);
        long c2 = sys_socket(2, 1, 0);
        if (c1 < 0 || c2 < 0) {
            if (c1 >= 0) sys_close((int)c1);
            if (c2 >= 0) sys_close((int)c2);
            sys_close((int)srv); fut_test_fail(1526); goto t1527;
        }
        __builtin_memset(&addr, 0, sizeof(addr));
        addr.sin_family = 2; addr.sin_port = test_htons(12352);
        long cr1 = sys_connect((int)c1, &addr, 16);
        long cr2 = sys_connect((int)c2, &addr, 16);
        if (cr1 != 0 || cr2 != 0) {
            fut_printf("[MISC-TEST] ✗ Test 1526: connect → %ld/%ld\n", cr1, cr2);
            sys_close((int)c1); sys_close((int)c2); sys_close((int)srv);
            fut_test_fail(1526); goto t1527;
        }
        /* Accept both */
        unsigned int al = 16;
        long a1 = sys_accept((int)srv, &addr, &al);
        al = 16;
        long a2 = sys_accept((int)srv, &addr, &al);
        if (a1 < 0 || a2 < 0) {
            fut_printf("[MISC-TEST] ✗ Test 1526: accept → %ld/%ld\n", a1, a2);
            if (a1 >= 0) sys_close((int)a1);
            if (a2 >= 0) sys_close((int)a2);
            sys_close((int)c1); sys_close((int)c2); sys_close((int)srv);
            fut_test_fail(1526); goto t1527;
        }
        /* Verify independent data paths */
        sys_write((int)c1, "AA", 2);
        sys_write((int)c2, "BB", 2);
        char b1[4] = {0}, b2[4] = {0};
        long r1 = sys_read((int)a1, b1, 4);
        long r2 = sys_read((int)a2, b2, 4);
        if (r1 == 2 && r2 == 2 &&
            b1[0] == 'A' && b1[1] == 'A' &&
            b2[0] == 'B' && b2[1] == 'B') {
            fut_printf("[MISC-TEST] ✓ Test 1526: multi-accept: 2 clients, independent data paths\n");
            fut_test_pass();
        } else {
            fut_printf("[MISC-TEST] ✗ Test 1526: data mismatch r1=%ld r2=%ld\n", r1, r2);
            fut_test_fail(1526);
        }
        sys_close((int)a1); sys_close((int)a2);
        sys_close((int)c1); sys_close((int)c2); sys_close((int)srv);
    }

t1527:
    /* Test 1527: fcntl F_SETFL O_NONBLOCK on AF_INET socket */
    {
        long fd = sys_socket(2, 1, 0);
        if (fd < 0) { fut_test_fail(1527); goto t1528; }
        /* Set O_NONBLOCK via fcntl */
        long ret = sys_fcntl((int)fd, 4 /*F_SETFL*/, 0x800 /*O_NONBLOCK*/);
        if (ret != 0) {
            fut_printf("[MISC-TEST] ✗ Test 1527: fcntl F_SETFL O_NONBLOCK → %ld\n", ret);
            sys_close((int)fd); fut_test_fail(1527); goto t1528;
        }
        /* Verify with F_GETFL */
        long flags = sys_fcntl((int)fd, 3 /*F_GETFL*/, 0);
        if (flags >= 0 && (flags & 0x800)) {
            fut_printf("[MISC-TEST] ✓ Test 1527: fcntl F_SETFL/F_GETFL O_NONBLOCK on AF_INET\n");
            fut_test_pass();
        } else {
            fut_printf("[MISC-TEST] ✗ Test 1527: F_GETFL → 0x%lx (no O_NONBLOCK)\n", flags);
            fut_test_fail(1527);
        }
        sys_close((int)fd);
    }

t1528:
    /* Test 1528: accept on non-listening socket → EINVAL */
    {
        long fd = sys_socket(2, 1, 0);
        if (fd < 0) { fut_test_fail(1528); goto t1529; }
        __builtin_memset(&addr, 0, sizeof(addr));
        addr.sin_family = 2; addr.sin_port = test_htons(12353);
        sys_bind((int)fd, &addr, 16);
        /* accept without listen */
        unsigned int al = 16;
        long ret = sys_accept((int)fd, &addr, &al);
        if (ret == -22 /* EINVAL */) {
            fut_printf("[MISC-TEST] ✓ Test 1528: accept on non-listening socket → EINVAL\n");
            fut_test_pass();
        } else {
            fut_printf("[MISC-TEST] ✗ Test 1528: accept on non-listening → %ld\n", ret);
            fut_test_fail(1528);
        }
        sys_close((int)fd);
    }

t1529:
    /* Test 1529: connect to self (same port) → ECONNREFUSED or EADDRINUSE */
    {
        long fd = sys_socket(2, 1, 0);
        if (fd < 0) { fut_test_fail(1529); goto t1530; }
        __builtin_memset(&addr, 0, sizeof(addr));
        addr.sin_family = 2; addr.sin_port = test_htons(12354);
        if (sys_bind((int)fd, &addr, 16) != 0) {
            sys_close((int)fd); fut_test_fail(1529); goto t1530;
        }
        /* connect bound (not listening) socket to itself */
        long ret = sys_connect((int)fd, &addr, 16);
        if (ret == -111 /* ECONNREFUSED */ || ret == -98 /* EADDRINUSE */ || ret == -22 /* EINVAL */) {
            fut_printf("[MISC-TEST] ✓ Test 1529: connect bound to self → %ld\n", ret);
            fut_test_pass();
        } else {
            fut_printf("[MISC-TEST] ✗ Test 1529: connect to self → %ld\n", ret);
            fut_test_fail(1529);
        }
        sys_close((int)fd);
    }

t1530:
    /* Test 1530: double listen is harmless (updates backlog) */
    {
        long fd = sys_socket(2, 1, 0);
        if (fd < 0) { fut_test_fail(1530); return; }
        __builtin_memset(&addr, 0, sizeof(addr));
        addr.sin_family = 2; addr.sin_port = test_htons(12355);
        if (sys_bind((int)fd, &addr, 16) != 0) {
            sys_close((int)fd); fut_test_fail(1530); return;
        }
        long r1 = sys_listen((int)fd, 5);
        long r2 = sys_listen((int)fd, 10);
        if (r1 == 0 && r2 == 0) {
            fut_printf("[MISC-TEST] ✓ Test 1530: double listen succeeds (backlog updated)\n");
            fut_test_pass();
        } else {
            fut_printf("[MISC-TEST] ✗ Test 1530: listen → %ld/%ld\n", r1, r2);
            fut_test_fail(1530);
        }
        sys_close((int)fd);
    }
}

/* ============================================================
 * Tests 1531-1538: flock/fcntl locking edge cases
 *
 * Test 1531: flock(LOCK_EX) then same fd flock(LOCK_SH) → downgrade succeeds
 * Test 1532: flock(LOCK_SH) then same fd flock(LOCK_EX) → upgrade succeeds
 * Test 1533: F_SETLKW WRLCK on unlocked file → immediate success (no block)
 * Test 1534: F_SETLKW RDLCK on unlocked file → immediate success
 * Test 1535: F_OFD_SETLK / F_OFD_GETLK round-trip
 * Test 1536: flock(LOCK_UN) on unlocked file → idempotent success
 * Test 1537: flock(invalid op) → EINVAL
 * Test 1538: F_SETLK on closed fd → EBADF
 * ============================================================ */
static void test_flock_fcntl_edge_cases(void) {
    extern long sys_flock(int fd, int operation);
    extern long sys_fcntl(int fd, int cmd, uint64_t arg);

#define EDGE_LOCK_SH  1
#define EDGE_LOCK_EX  2
#define EDGE_LOCK_NB  4
#define EDGE_LOCK_UN  8
#define EDGE_F_GETLK  5
#define EDGE_F_SETLK  6
#define EDGE_F_SETLKW 7
#define EDGE_F_OFD_GETLK  36
#define EDGE_F_OFD_SETLK  37
#define EDGE_F_RDLCK  0
#define EDGE_F_WRLCK  1
#define EDGE_F_UNLCK  2

    struct {
        short l_type;
        short l_whence;
        int   _pad;
        long  l_start;
        long  l_len;
        int   l_pid;
    } lk;

    fut_printf("[MISC-TEST] Tests 1531-1538: flock/fcntl locking edge cases\n");

    const char *path = "/flock_edge_test.txt";
    fut_vfs_unlink(path);
    int fd = fut_vfs_open(path, O_CREAT | O_RDWR, 0644);
    if (fd < 0) {
        fut_printf("[MISC-TEST] ✗ open failed: %d\n", fd);
        for (int t = 1531; t <= 1538; t++) fut_test_fail(t);
        return;
    }

    /* Test 1531: EX → SH downgrade on same fd */
    fut_printf("[MISC-TEST] Test 1531: flock EX→SH downgrade\n");
    long r = sys_flock(fd, EDGE_LOCK_EX);
    long r2 = sys_flock(fd, EDGE_LOCK_SH);
    sys_flock(fd, EDGE_LOCK_UN);
    if (r == 0 && r2 == 0) {
        fut_printf("[MISC-TEST] ✓ Test 1531: EX→SH downgrade succeeded\n");
        fut_test_pass();
    } else {
        fut_printf("[MISC-TEST] ✗ Test 1531: EX=%ld SH=%ld\n", r, r2);
        fut_test_fail(1531);
    }

    /* Test 1532: flock(LOCK_EX|LOCK_NB) on locked file → EAGAIN (then unlock and re-lock) */
    fut_printf("[MISC-TEST] Test 1532: flock LOCK_EX|LOCK_NB contention → EAGAIN\n");
    {
        /* Open a second fd to the same file to create contention */
        int fd2 = fut_vfs_open(path, O_RDWR, 0644);
        if (fd2 < 0) {
            fut_printf("[MISC-TEST] ✗ Test 1532: second open failed: %d\n", fd2);
            fut_test_fail(1532);
        } else {
            /* Hold SH on fd, try EX|NB on fd2 → EAGAIN */
            r = sys_flock(fd, EDGE_LOCK_SH);
            r2 = sys_flock(fd2, EDGE_LOCK_EX | EDGE_LOCK_NB);
            sys_flock(fd, EDGE_LOCK_UN);
            fut_vfs_close(fd2);
            if (r == 0 && r2 == -EAGAIN) {
                fut_printf("[MISC-TEST] ✓ Test 1532: LOCK_EX|LOCK_NB → EAGAIN (SH held)\n");
                fut_test_pass();
            } else {
                fut_printf("[MISC-TEST] ✗ Test 1532: SH=%ld EX|NB=%ld (want 0, -11)\n", r, r2);
                fut_test_fail(1532);
            }
        }
    }

    /* Test 1533: F_SETLKW WRLCK on unlocked file → immediate success */
    fut_printf("[MISC-TEST] Test 1533: F_SETLKW WRLCK no-contention\n");
    __builtin_memset(&lk, 0, sizeof(lk));
    lk.l_type   = EDGE_F_WRLCK;
    lk.l_whence = 0;
    lk.l_start  = 0;
    lk.l_len    = 0;
    r = sys_fcntl(fd, EDGE_F_SETLKW, (uint64_t)(uintptr_t)&lk);
    if (r == 0) {
        fut_printf("[MISC-TEST] ✓ Test 1533: F_SETLKW WRLCK → 0\n");
        fut_test_pass();
    } else {
        fut_printf("[MISC-TEST] ✗ Test 1533: F_SETLKW WRLCK → %ld\n", r);
        fut_test_fail(1533);
    }
    /* Unlock */
    lk.l_type = EDGE_F_UNLCK;
    sys_fcntl(fd, EDGE_F_SETLK, (uint64_t)(uintptr_t)&lk);

    /* Test 1534: F_SETLKW RDLCK on unlocked file → immediate success */
    fut_printf("[MISC-TEST] Test 1534: F_SETLKW RDLCK no-contention\n");
    __builtin_memset(&lk, 0, sizeof(lk));
    lk.l_type   = EDGE_F_RDLCK;
    lk.l_whence = 0;
    lk.l_start  = 0;
    lk.l_len    = 0;
    r = sys_fcntl(fd, EDGE_F_SETLKW, (uint64_t)(uintptr_t)&lk);
    if (r == 0) {
        fut_printf("[MISC-TEST] ✓ Test 1534: F_SETLKW RDLCK → 0\n");
        fut_test_pass();
    } else {
        fut_printf("[MISC-TEST] ✗ Test 1534: F_SETLKW RDLCK → %ld\n", r);
        fut_test_fail(1534);
    }
    /* Unlock */
    lk.l_type = EDGE_F_UNLCK;
    sys_fcntl(fd, EDGE_F_SETLK, (uint64_t)(uintptr_t)&lk);

    /* Test 1535: F_OFD_SETLK / F_OFD_GETLK round-trip */
    fut_printf("[MISC-TEST] Test 1535: F_OFD_SETLK/GETLK round-trip\n");
    __builtin_memset(&lk, 0, sizeof(lk));
    lk.l_type   = EDGE_F_WRLCK;
    lk.l_whence = 0;
    lk.l_start  = 0;
    lk.l_len    = 0;
    r = sys_fcntl(fd, EDGE_F_OFD_SETLK, (uint64_t)(uintptr_t)&lk);
    if (r != 0) {
        fut_printf("[MISC-TEST] ✗ Test 1535: F_OFD_SETLK → %ld\n", r);
        fut_test_fail(1535);
    } else {
        /* Query with F_OFD_GETLK: same owner → should report F_UNLCK */
        __builtin_memset(&lk, 0, sizeof(lk));
        lk.l_type   = EDGE_F_WRLCK;
        lk.l_whence = 0;
        lk.l_start  = 0;
        lk.l_len    = 0;
        r = sys_fcntl(fd, EDGE_F_OFD_GETLK, (uint64_t)(uintptr_t)&lk);
        if (r == 0 && lk.l_type == EDGE_F_UNLCK) {
            fut_printf("[MISC-TEST] ✓ Test 1535: F_OFD round-trip OK\n");
            fut_test_pass();
        } else {
            fut_printf("[MISC-TEST] ✗ Test 1535: F_OFD_GETLK r=%ld l_type=%d\n", r, (int)lk.l_type);
            fut_test_fail(1535);
        }
        /* Unlock */
        lk.l_type = EDGE_F_UNLCK;
        sys_fcntl(fd, EDGE_F_OFD_SETLK, (uint64_t)(uintptr_t)&lk);
    }

    /* Test 1536: flock(LOCK_UN) on unlocked file → idempotent success (0) */
    fut_printf("[MISC-TEST] Test 1536: flock LOCK_UN on unlocked file\n");
    r = sys_flock(fd, EDGE_LOCK_UN);
    if (r == 0) {
        fut_printf("[MISC-TEST] ✓ Test 1536: LOCK_UN on unlocked → 0\n");
        fut_test_pass();
    } else {
        fut_printf("[MISC-TEST] ✗ Test 1536: LOCK_UN → %ld\n", r);
        fut_test_fail(1536);
    }

    /* Test 1537: flock(invalid op) → EINVAL */
    fut_printf("[MISC-TEST] Test 1537: flock invalid operation\n");
    r = sys_flock(fd, 0xFF);
    if (r == -EINVAL) {
        fut_printf("[MISC-TEST] ✓ Test 1537: flock(0xFF) → EINVAL\n");
        fut_test_pass();
    } else {
        fut_printf("[MISC-TEST] ✗ Test 1537: flock(0xFF) → %ld\n", r);
        fut_test_fail(1537);
    }

    fut_vfs_close(fd);

    /* Test 1538: fcntl F_SETLK on closed fd → EBADF */
    fut_printf("[MISC-TEST] Test 1538: F_SETLK on closed fd\n");
    __builtin_memset(&lk, 0, sizeof(lk));
    lk.l_type   = EDGE_F_WRLCK;
    lk.l_whence = 0;
    lk.l_start  = 0;
    lk.l_len    = 0;
    r = sys_fcntl(fd, EDGE_F_SETLK, (uint64_t)(uintptr_t)&lk);
    if (r == -EBADF) {
        fut_printf("[MISC-TEST] ✓ Test 1538: F_SETLK on closed fd → EBADF\n");
        fut_test_pass();
    } else {
        fut_printf("[MISC-TEST] ✗ Test 1538: F_SETLK closed → %ld\n", r);
        fut_test_fail(1538);
    }

    fut_vfs_unlink(path);
}

/* ============================================================
 * Tests 1539-1542: getsockname/getpeername with addrlen=0
 *
 * Test 1539: getsockname(AF_UNIX, addrlen=0) → 0 + actual len written
 * Test 1540: getsockname(AF_INET, addrlen=0) → 0 + actual len=16
 * Test 1541: getpeername(connected AF_UNIX, addrlen=0) → 0
 * Test 1542: getpeername(connected AF_INET, addrlen=0) → 0
 * ============================================================ */
static void test_sockname_zero_addrlen(void) {
    extern long sys_socket(int domain, int type, int protocol);
    extern long sys_bind(int sockfd, const void *addr, unsigned int addrlen);
    extern long sys_listen(int sockfd, int backlog);
    extern long sys_connect(int sockfd, const void *addr, unsigned int addrlen);
    extern long sys_accept(int sockfd, void *addr, unsigned int *addrlen);
    extern long sys_getsockname(int sockfd, void *addr, unsigned int *addrlen);
    extern long sys_getpeername(int sockfd, void *addr, unsigned int *addrlen);
    extern long sys_close(int fd);

    fut_printf("[MISC-TEST] Tests 1539-1542: getsockname/getpeername addrlen=0\n");

    /* Test 1539: getsockname(AF_UNIX, addrlen=0) → 0 + writes actual len */
    fut_printf("[MISC-TEST] Test 1539: getsockname(AF_UNIX, addrlen=0)\n");
    {
        long fd = sys_socket(1 /* AF_UNIX */, 1 /* SOCK_STREAM */, 0);
        if (fd < 0) {
            fut_printf("[MISC-TEST] ✗ Test 1539: socket failed: %ld\n", fd);
            fut_test_fail(1539);
        } else {
            char buf[128];
            __builtin_memset(buf, 0, sizeof(buf));
            unsigned int alen = 0;
            long r = sys_getsockname((int)fd, buf, &alen);
            if (r == 0) {
                fut_printf("[MISC-TEST] ✓ Test 1539: getsockname(addrlen=0) → 0, alen=%u\n", alen);
                fut_test_pass();
            } else {
                fut_printf("[MISC-TEST] ✗ Test 1539: getsockname(addrlen=0) → %ld\n", r);
                fut_test_fail(1539);
            }
            sys_close((int)fd);
        }
    }

    /* Test 1540: getsockname(AF_INET, addrlen=0) → 0 + actual_len=16 */
    fut_printf("[MISC-TEST] Test 1540: getsockname(AF_INET, addrlen=0)\n");
    {
        long fd = sys_socket(2 /* AF_INET */, 1 /* SOCK_STREAM */, 0);
        if (fd < 0) {
            fut_printf("[MISC-TEST] ✗ Test 1540: socket failed: %ld\n", fd);
            fut_test_fail(1540);
        } else {
            char buf[128];
            __builtin_memset(buf, 0, sizeof(buf));
            unsigned int alen = 0;
            long r = sys_getsockname((int)fd, buf, &alen);
            if (r == 0 && alen == 16) {
                fut_printf("[MISC-TEST] ✓ Test 1540: getsockname(AF_INET, addrlen=0) → 0, alen=%u\n", alen);
                fut_test_pass();
            } else {
                fut_printf("[MISC-TEST] ✗ Test 1540: r=%ld alen=%u (want 0, 16)\n", r, alen);
                fut_test_fail(1540);
            }
            sys_close((int)fd);
        }
    }

    /* Test 1541: getpeername(connected AF_UNIX, addrlen=0) → 0 */
    fut_printf("[MISC-TEST] Test 1541: getpeername(AF_UNIX connected, addrlen=0)\n");
    {
        extern long sys_socketpair(int domain, int type, int protocol, int *sv);
        int sv[2] = {-1, -1};
        long r = sys_socketpair(1 /* AF_UNIX */, 1 /* SOCK_STREAM */, 0, sv);
        if (r < 0) {
            fut_printf("[MISC-TEST] ✗ Test 1541: socketpair failed: %ld\n", r);
            fut_test_fail(1541);
        } else {
            char buf[128];
            __builtin_memset(buf, 0, sizeof(buf));
            unsigned int alen = 0;
            r = sys_getpeername(sv[0], buf, &alen);
            if (r == 0) {
                fut_printf("[MISC-TEST] ✓ Test 1541: getpeername(addrlen=0) → 0, alen=%u\n", alen);
                fut_test_pass();
            } else {
                fut_printf("[MISC-TEST] ✗ Test 1541: getpeername(addrlen=0) → %ld\n", r);
                fut_test_fail(1541);
            }
            sys_close(sv[0]);
            sys_close(sv[1]);
        }
    }

    /* Test 1542: getpeername(connected AF_INET, addrlen=0) → 0 */
    fut_printf("[MISC-TEST] Test 1542: getpeername(AF_INET connected, addrlen=0)\n");
    {
        /* Create a simple AF_INET TCP connection */
        long sfd = sys_socket(2 /* AF_INET */, 1 /* SOCK_STREAM */, 0);
        if (sfd < 0) {
            fut_printf("[MISC-TEST] ✗ Test 1542: socket failed: %ld\n", sfd);
            fut_test_fail(1542);
        } else {
            struct { uint16_t sin_family; uint16_t sin_port; uint32_t sin_addr; uint8_t sin_zero[8]; } addr;
            __builtin_memset(&addr, 0, sizeof(addr));
            addr.sin_family = 2; /* AF_INET */
            addr.sin_port = ((12399 >> 8) & 0xFF) | ((12399 & 0xFF) << 8); /* htons */
            addr.sin_addr = ((127) | (0 << 8) | (0 << 16) | (1 << 24)); /* 127.0.0.1 */
            long br = sys_bind((int)sfd, &addr, 16);
            long lr = sys_listen((int)sfd, 1);
            long cfd = sys_socket(2, 1, 0);
            long cr = sys_connect((int)cfd, &addr, 16);
            unsigned int plen = 0;
            long afd = sys_accept((int)sfd, NULL, NULL);
            if (br < 0 || lr < 0 || cfd < 0 || cr < 0 || afd < 0) {
                fut_printf("[MISC-TEST] ✗ Test 1542: setup failed b=%ld l=%ld c=%ld cn=%ld a=%ld\n",
                           br, lr, cfd, cr, afd);
                fut_test_fail(1542);
            } else {
                char buf[128];
                __builtin_memset(buf, 0, sizeof(buf));
                plen = 0;
                long r = sys_getpeername((int)cfd, buf, &plen);
                if (r == 0) {
                    fut_printf("[MISC-TEST] ✓ Test 1542: getpeername(AF_INET, addrlen=0) → 0, alen=%u\n", plen);
                    fut_test_pass();
                } else {
                    fut_printf("[MISC-TEST] ✗ Test 1542: getpeername(addrlen=0) → %ld\n", r);
                    fut_test_fail(1542);
                }
                if (afd >= 0) sys_close((int)afd);
            }
            if (cfd >= 0) sys_close((int)cfd);
            sys_close((int)sfd);
        }
    }
}

/**
 * Test SO_LINGER enforcement on socket close.
 *
 * Test 1543: SO_LINGER l_linger=0 discards send buffer — peer recv returns ECONNRESET.
 * Test 1544: SO_LINGER l_linger=0 on setsockopt returns 0 (option accepted).
 * Test 1545: Default close (no linger) delivers buffered data to peer.
 * Test 1546: SO_LINGER l_onoff=0 (disabled) still delivers buffered data.
 */
static void test_so_linger(void) {
    extern long sys_socket(int domain, int type, int protocol);
    extern long sys_bind(int sockfd, const void *addr, unsigned int addrlen);
    extern long sys_listen(int sockfd, int backlog);
    extern long sys_connect(int sockfd, const void *addr, unsigned int addrlen);
    extern long sys_accept(int sockfd, void *addr, unsigned int *addrlen);
    extern long sys_close(int fd);
    extern ssize_t sys_write(int fd, const void *buf, size_t count);
    extern ssize_t sys_read(int fd, void *buf, size_t count);
    extern long sys_setsockopt(int fd, int level, int optname, const void *optval, unsigned int optlen);

    /* Test 1543: SO_LINGER l_linger=0: close discards buffer, peer gets ECONNRESET */
    fut_printf("[MISC-TEST] Test 1543: SO_LINGER l_linger=0 discards data, peer gets ECONNRESET\n");
    {
        long sfd = sys_socket(1 /* AF_UNIX */, 1 /* SOCK_STREAM */, 0);
        if (sfd < 0) {
            fut_printf("[MISC-TEST] ✗ Test 1543: server socket failed: %ld\n", sfd);
            fut_test_fail(1543);
        } else {
            struct { unsigned short family; char path[108]; } addr;
            addr.family = 1;
            __builtin_memcpy(addr.path, "/tmp/.t1543_linger", 19);
            sys_bind((int)sfd, &addr, (unsigned int)(2 + 19));
            sys_listen((int)sfd, 5);

            long cfd = sys_socket(1, 1, 0);
            sys_connect((int)cfd, &addr, (unsigned int)(2 + 19));
            long afd = sys_accept((int)sfd, NULL, NULL);

            if (cfd < 0 || afd < 0) {
                fut_printf("[MISC-TEST] ✗ Test 1543: connect/accept failed: cfd=%ld afd=%ld\n", cfd, afd);
                fut_test_fail(1543);
            } else {
                /* Client sends data */
                sys_write((int)cfd, "hello", 5);

                /* Set SO_LINGER with l_linger=0 on client */
                struct { int l_onoff; int l_linger; } ling = { 1, 0 };
                sys_setsockopt((int)cfd, 1 /* SOL_SOCKET */, 13 /* SO_LINGER */,
                               &ling, sizeof(ling));

                /* Close client — should discard buffered data and RST */
                sys_close((int)cfd);
                cfd = -1;

                /* Server tries to read — should get ECONNRESET, not the data */
                char buf[16];
                ssize_t nr = sys_read((int)afd, buf, sizeof(buf));
                if (nr == -104 /* -ECONNRESET */) {
                    fut_printf("[MISC-TEST] ✓ Test 1543: recv after linger=0 close = -ECONNRESET\n");
                    fut_test_pass();
                } else {
                    fut_printf("[MISC-TEST] ✗ Test 1543: recv = %ld (want -104 ECONNRESET)\n", (long)nr);
                    fut_test_fail(1543);
                }
            }
            if (cfd >= 0) sys_close((int)cfd);
            if (afd >= 0) sys_close((int)afd);
            sys_close((int)sfd);
        }
    }

    /* Test 1544: setsockopt SO_LINGER returns 0 */
    fut_printf("[MISC-TEST] Test 1544: setsockopt SO_LINGER returns 0\n");
    {
        long fd = sys_socket(1, 1, 0);
        if (fd < 0) {
            fut_printf("[MISC-TEST] ✗ Test 1544: socket failed: %ld\n", fd);
            fut_test_fail(1544);
        } else {
            struct { int l_onoff; int l_linger; } ling = { 1, 0 };
            long r = sys_setsockopt((int)fd, 1, 13, &ling, sizeof(ling));
            if (r == 0) {
                fut_printf("[MISC-TEST] ✓ Test 1544: setsockopt SO_LINGER = 0\n");
                fut_test_pass();
            } else {
                fut_printf("[MISC-TEST] ✗ Test 1544: setsockopt SO_LINGER = %ld\n", r);
                fut_test_fail(1544);
            }
            sys_close((int)fd);
        }
    }

    /* Test 1545: Default close (no linger) delivers buffered data to peer */
    fut_printf("[MISC-TEST] Test 1545: default close delivers buffered data\n");
    {
        long sfd = sys_socket(1, 1, 0);
        if (sfd < 0) {
            fut_printf("[MISC-TEST] ✗ Test 1545: server socket failed: %ld\n", sfd);
            fut_test_fail(1545);
        } else {
            struct { unsigned short family; char path[108]; } addr;
            addr.family = 1;
            __builtin_memcpy(addr.path, "/tmp/.t1545_nolinger", 21);
            sys_bind((int)sfd, &addr, (unsigned int)(2 + 21));
            sys_listen((int)sfd, 5);

            long cfd = sys_socket(1, 1, 0);
            sys_connect((int)cfd, &addr, (unsigned int)(2 + 21));
            long afd = sys_accept((int)sfd, NULL, NULL);

            if (cfd < 0 || afd < 0) {
                fut_printf("[MISC-TEST] ✗ Test 1545: connect/accept failed\n");
                fut_test_fail(1545);
            } else {
                /* Client sends data and closes WITHOUT linger */
                sys_write((int)cfd, "world", 5);
                sys_close((int)cfd);
                cfd = -1;

                /* Server reads — should get the data */
                char buf[16];
                ssize_t nr = sys_read((int)afd, buf, sizeof(buf));
                if (nr == 5) {
                    fut_printf("[MISC-TEST] ✓ Test 1545: default close delivers data (got %ld bytes)\n", (long)nr);
                    fut_test_pass();
                } else {
                    fut_printf("[MISC-TEST] ✗ Test 1545: read = %ld (want 5)\n", (long)nr);
                    fut_test_fail(1545);
                }
            }
            if (cfd >= 0) sys_close((int)cfd);
            if (afd >= 0) sys_close((int)afd);
            sys_close((int)sfd);
        }
    }

    /* Test 1546: SO_LINGER l_onoff=0 (disabled) still delivers buffered data */
    fut_printf("[MISC-TEST] Test 1546: SO_LINGER disabled still delivers data\n");
    {
        long sfd = sys_socket(1, 1, 0);
        if (sfd < 0) {
            fut_printf("[MISC-TEST] ✗ Test 1546: server socket failed: %ld\n", sfd);
            fut_test_fail(1546);
        } else {
            struct { unsigned short family; char path[108]; } addr;
            addr.family = 1;
            __builtin_memcpy(addr.path, "/tmp/.t1546_lingoff", 20);
            sys_bind((int)sfd, &addr, (unsigned int)(2 + 20));
            sys_listen((int)sfd, 5);

            long cfd = sys_socket(1, 1, 0);
            sys_connect((int)cfd, &addr, (unsigned int)(2 + 20));
            long afd = sys_accept((int)sfd, NULL, NULL);

            if (cfd < 0 || afd < 0) {
                fut_printf("[MISC-TEST] ✗ Test 1546: connect/accept failed\n");
                fut_test_fail(1546);
            } else {
                /* Client sends data, sets linger OFF, closes */
                sys_write((int)cfd, "data!", 5);
                struct { int l_onoff; int l_linger; } ling = { 0, 0 };
                sys_setsockopt((int)cfd, 1, 13, &ling, sizeof(ling));
                sys_close((int)cfd);
                cfd = -1;

                /* Server reads — should get the data (linger disabled) */
                char buf[16];
                ssize_t nr = sys_read((int)afd, buf, sizeof(buf));
                if (nr == 5) {
                    fut_printf("[MISC-TEST] ✓ Test 1546: linger-off close delivers data (got %ld bytes)\n", (long)nr);
                    fut_test_pass();
                } else {
                    fut_printf("[MISC-TEST] ✗ Test 1546: read = %ld (want 5)\n", (long)nr);
                    fut_test_fail(1546);
                }
            }
            if (cfd >= 0) sys_close((int)cfd);
            if (afd >= 0) sys_close((int)afd);
            sys_close((int)sfd);
        }
    }
}

