    struct iovec riov;
    riov.iov_base = rbuf;
    riov.iov_len = sizeof(rbuf);

    struct test_msghdr rmsg;
    __builtin_memset(&rmsg, 0, sizeof(rmsg));
    rmsg.msg_iov = &riov;
    rmsg.msg_iovlen = 1;

    ssize_t nr = sys_recvmsg(sv[1], &rmsg, 0);

    /* Test 1569: recv should return 10 bytes (truncated) */
