/*
 * test_recv_msg_trunc_flag - recv(MSG_TRUNC) returns actual datagram size
 *
 * Tests 1571-1572:
 *   1571: recv(MSG_TRUNC) on DGRAM socketpair returns actual datagram size, not truncated
 *   1572: recv(MSG_TRUNC) on SEQPACKET socketpair returns actual message size
 */
static void test_recv_msg_trunc_flag(void) {
    fut_printf("[MISC-TEST] Tests 1571-1572: recv(MSG_TRUNC) returns actual datagram size\n");

    extern long sys_socketpair(int domain, int type, int protocol, int *sv);
    extern long sys_sendto(int sockfd, const void *buf, size_t len, int flags,
                           const void *dest_addr, unsigned int addrlen);
    extern long sys_recvfrom(int sockfd, void *buf, size_t len, int flags,
                             void *src_addr, unsigned int *addrlen);
    extern ssize_t sys_recvmsg(int sockfd, struct test_msghdr *msg, int flags);

    /* Test 1571: sendto/recvfrom(MSG_TRUNC) on DGRAM socketpair returns actual datagram size.
     * Linux: when MSG_TRUNC is passed as input flag to recv/recvfrom on a DGRAM socket,
     * the return value is the actual datagram size even if it was truncated. */
    {
        int sv[2] = {-1, -1};
        long ret = sys_socketpair(1 /* AF_UNIX */, 2 /* SOCK_DGRAM */, 0, sv);
        if (ret < 0) {
            fut_printf("[MISC-TEST] ✗ Test 1571: socketpair(DGRAM) failed: %ld\n", ret);
            fut_test_fail(1571);
        } else {
            char msg[20];
            for (int i = 0; i < 20; i++) msg[i] = (char)('a' + i % 26);
            /* Use sendto (with NULL dest_addr) — tests the sendto fix for DGRAM socketpairs */
            long nw = sys_sendto(sv[0], msg, 20, 0, 0, 0);
            if (nw < 0) {
                fut_printf("[MISC-TEST] ✗ Test 1571: sendto on DGRAM socketpair failed: %ld\n", nw);
                fut_test_fail(1571);
            } else {
                char rbuf[10];
                long nr = sys_recvfrom(sv[1], rbuf, 10, 0x20 /* MSG_TRUNC */, 0, 0);
                if (nr == 20) {
                    fut_printf("[MISC-TEST] ✓ Test 1571: recvfrom(MSG_TRUNC) returned %ld (actual datagram size)\n",
                               nr);
                    fut_test_pass();
                } else {
                    fut_printf("[MISC-TEST] ✗ Test 1571: recvfrom(MSG_TRUNC) returned %ld (expected 20)\n", nr);
                    fut_test_fail(1571);
                }
            }
            sys_close(sv[0]);
            sys_close(sv[1]);
        }
    }

    /* Test 1572: SEQPACKET recvmsg MSG_TRUNC in msg_flags */
    {
        int sv[2] = {-1, -1};
        long ret = sys_socketpair(1 /* AF_UNIX */, 5 /* SOCK_SEQPACKET */, 0, sv);
        if (ret < 0) {
            fut_printf("[MISC-TEST] ✗ Test 1572: socketpair(SEQPACKET) failed: %ld\n", ret);
            fut_test_fail(1572);
        } else {
            char msg[30];
            for (int i = 0; i < 30; i++) msg[i] = (char)('A' + i % 26);
            long nw = sys_sendto(sv[0], msg, 30, 0, 0, 0);

            char rbuf[8];
            struct iovec riov = { .iov_base = rbuf, .iov_len = 8 };
            struct test_msghdr rmsg;
            __builtin_memset(&rmsg, 0, sizeof(rmsg));
            rmsg.msg_iov = &riov;
            rmsg.msg_iovlen = 1;

            ssize_t nr = sys_recvmsg(sv[1], &rmsg, 0);
            if (nr == 8 && (rmsg.msg_flags & 0x20)) {
                fut_printf("[MISC-TEST] ✓ Test 1572: SEQPACKET recvmsg truncated to %ld, MSG_TRUNC set\n",
                           (long)nr);
                fut_test_pass();
            } else {
                fut_printf("[MISC-TEST] ✗ Test 1572: recvmsg returned %ld, msg_flags=0x%x\n",
                           (long)nr, rmsg.msg_flags);
                fut_test_fail(1572);
            }
            (void)nw;
            sys_close(sv[0]);
            sys_close(sv[1]);
        }
    }
}

/*
 * test_peek_trunc_dgram_size - MSG_PEEK|MSG_TRUNC returns actual datagram size
 *
 * Tests 1573-1574:
 *   1573: recv(MSG_PEEK|MSG_TRUNC) on DGRAM socketpair returns actual datagram size
 *   1574: After MSG_PEEK|MSG_TRUNC, the datagram is still available for normal recv
 */
static void test_peek_trunc_dgram_size(void) {
    fut_printf("[MISC-TEST] Tests 1573-1574: MSG_PEEK|MSG_TRUNC datagram size discovery\n");

    extern long sys_socketpair(int domain, int type, int protocol, int *sv);
    extern ssize_t sys_write(int fd, const void *buf, size_t count);
    extern long sys_recvfrom(int sockfd, void *buf, size_t len, int flags,
                             void *src_addr, unsigned int *addrlen);

    int sv[2] = {-1, -1};
    long ret = sys_socketpair(1 /* AF_UNIX */, 2 /* SOCK_DGRAM */, 0, sv);
    if (ret < 0) {
        fut_printf("[MISC-TEST] ✗ Test 1573: socketpair failed: %ld\n", ret);
        fut_test_fail(1573);
        fut_test_fail(1574);
        return;
    }

    /* Send a 25-byte datagram */
    char msg[25];
    for (int i = 0; i < 25; i++) msg[i] = (char)('A' + i % 26);
    ssize_t nw = sys_write(sv[0], msg, 25);
    if (nw != 25) {
        fut_printf("[MISC-TEST] ✗ Test 1573: write returned %ld\n", (long)nw);
        sys_close(sv[0]); sys_close(sv[1]);
        fut_test_fail(1573);
        fut_test_fail(1574);
        return;
    }

    /* Test 1573: recv(MSG_PEEK|MSG_TRUNC) with a 1-byte buffer should return 25 */
    char tiny[1];
    long nr = sys_recvfrom(sv[1], tiny, 1, 0x22 /* MSG_PEEK(0x2)|MSG_TRUNC(0x20) */, 0, 0);
    if (nr == 25) {
        fut_printf("[MISC-TEST] ✓ Test 1573: MSG_PEEK|MSG_TRUNC returned %ld (actual datagram size)\n", nr);
        fut_test_pass();
    } else {
        fut_printf("[MISC-TEST] ✗ Test 1573: returned %ld (expected 25)\n", nr);
        fut_test_fail(1573);
    }

    /* Test 1574: Datagram should still be available (MSG_PEEK doesn't consume) */
    char full[32];
    nr = sys_recvfrom(sv[1], full, 32, 0, 0, 0);
    if (nr == 25 && __builtin_memcmp(full, msg, 25) == 0) {
        fut_printf("[MISC-TEST] ✓ Test 1574: datagram still available after peek (%ld bytes)\n", nr);
        fut_test_pass();
    } else {
        fut_printf("[MISC-TEST] ✗ Test 1574: recv returned %ld (expected 25)\n", nr);
        fut_test_fail(1574);
    }

    sys_close(sv[0]);
    sys_close(sv[1]);
}

/*
 * test_seqpacket_msg_waitall - MSG_WAITALL ignored on SEQPACKET (message boundary)
 *
 *   Test 1575: SEQPACKET recvfrom(MSG_WAITALL) returns one message, not concatenated.
 *   Test 1576: Second message still available after first recv.
 *
 * On Linux, MSG_WAITALL is only meaningful for SOCK_STREAM.  For SEQPACKET,
 * each recv returns exactly one message.  If the implementation incorrectly
 * loops for MSG_WAITALL on SEQPACKET, it would concatenate messages.
 */
static void test_seqpacket_msg_waitall(void) {
    extern long sys_socketpair(int domain, int type, int protocol, int *sv);
    extern long sys_sendto(int sockfd, const void *buf, size_t len, int flags,
                           const void *dest_addr, unsigned int addrlen);
    extern long sys_recvfrom(int sockfd, void *buf, size_t len, int flags,
                             void *src_addr, unsigned int *addrlen);
    fut_printf("[MISC-TEST] Tests 1575-1576: SEQPACKET MSG_WAITALL preserves message boundaries\n");

    int sv[2];
    long sr = sys_socketpair(1 /* AF_UNIX */, 5 /* SOCK_SEQPACKET */, 0, sv);
    if (sr < 0) {
        fut_printf("[MISC-TEST] ✗ Tests 1575-1576: socketpair failed: %ld\n", sr);
        fut_test_fail(1575);
        fut_test_fail(1576);
        return;
    }

    /* Send two separate 10-byte messages */
    const char msg1[10] = "AAAAAAAAAA";
    const char msg2[10] = "BBBBBBBBBB";
    sys_sendto(sv[0], msg1, 10, 0, 0, 0);
    sys_sendto(sv[0], msg2, 10, 0, 0, 0);

    /* recv with MSG_WAITALL and a 20-byte buffer.
     * Correct: returns 10 (one message).
     * Bug: would return 20 (concatenated both messages). */
    char buf[20];
    __builtin_memset(buf, 0, sizeof(buf));
    long nr = sys_recvfrom(sv[1], buf, 20,
                           0x100 /* MSG_WAITALL */, 0, 0);

    /* Test 1575: Should get exactly 10 bytes (one message) */
    fut_printf("[MISC-TEST] Test 1575: SEQPACKET recvfrom(MSG_WAITALL, buf=20) returned %ld\n", nr);
    if (nr == 10) {
        fut_test_pass();
    } else {
        fut_printf("[MISC-TEST] ✗ Test 1575: expected 10, got %ld (messages concatenated?)\n", nr);
        fut_test_fail(1575);
    }

    /* Test 1576: Second message should still be available */
    __builtin_memset(buf, 0, sizeof(buf));
    nr = sys_recvfrom(sv[1], buf, 20, 0, 0, 0);
    fut_printf("[MISC-TEST] Test 1576: second recv returned %ld\n", nr);
    if (nr == 10 && buf[0] == 'B') {
        fut_test_pass();
    } else {
        fut_printf("[MISC-TEST] ✗ Test 1576: expected 10 bytes of 'B', got %ld bytes, first='%c'\n",
                   nr, buf[0]);
        fut_test_fail(1576);
    }

    sys_close(sv[0]);
    sys_close(sv[1]);
}

/*
 * test_fionread_dgram_next_msg - FIONREAD on DGRAM socket returns next datagram size
 *
 *   Test 1577: FIONREAD with two datagrams (10 + 20 bytes) returns 10 (first msg only).
 *   Test 1578: After consuming first datagram, FIONREAD returns 20 (second msg).
 *
 * On Linux, ioctl(FIONREAD) on a DGRAM socket returns the size of the NEXT
 * pending datagram, not the total bytes in the buffer.
 */
static void test_fionread_dgram_next_msg(void) {
    extern long sys_socketpair(int domain, int type, int protocol, int *sv);
    extern long sys_sendto(int sockfd, const void *buf, size_t len, int flags,
                           const void *dest_addr, unsigned int addrlen);
    extern long sys_recvfrom(int sockfd, void *buf, size_t len, int flags,
                             void *src_addr, unsigned int *addrlen);
    extern long sys_ioctl(int fd, unsigned long request, void *argp);
    fut_printf("[MISC-TEST] Tests 1577-1578: FIONREAD returns next datagram size\n");

    int sv[2];
    long sr = sys_socketpair(1 /* AF_UNIX */, 2 /* SOCK_DGRAM */, 0, sv);
    if (sr < 0) {
        fut_printf("[MISC-TEST] ✗ Tests 1577-1578: socketpair failed: %ld\n", sr);
        fut_test_fail(1577);
        fut_test_fail(1578);
        return;
    }

    /* Send two datagrams of different sizes */
    char msg1[10]; __builtin_memset(msg1, 'A', 10);
    char msg2[20]; __builtin_memset(msg2, 'B', 20);
    sys_sendto(sv[0], msg1, 10, 0, 0, 0);
    sys_sendto(sv[0], msg2, 20, 0, 0, 0);

    /* Test 1577: FIONREAD should return 10 (first datagram size), not 30 (total) */
    int avail = 0;
    long r = sys_ioctl(sv[1], 0x541B /* FIONREAD */, &avail);
    fut_printf("[MISC-TEST] Test 1577: FIONREAD returned %d (ioctl=%ld)\n", avail, r);
    if (r == 0 && avail == 10) {
        fut_test_pass();
    } else {
        fut_printf("[MISC-TEST] ✗ Test 1577: expected FIONREAD=10, got %d (ioctl=%ld)\n", avail, r);
        fut_test_fail(1577);
    }

    /* Consume the first datagram */
    char discard[10];
    sys_recvfrom(sv[1], discard, 10, 0, 0, 0);

    /* Test 1578: FIONREAD should now return 20 (second datagram size) */
    avail = 0;
    r = sys_ioctl(sv[1], 0x541B /* FIONREAD */, &avail);
    fut_printf("[MISC-TEST] Test 1578: FIONREAD after consuming first msg returned %d\n", avail);
    if (r == 0 && avail == 20) {
        fut_test_pass();
    } else {
        fut_printf("[MISC-TEST] ✗ Test 1578: expected FIONREAD=20, got %d\n", avail);
        fut_test_fail(1578);
    }

    sys_close(sv[0]);
    sys_close(sv[1]);
}

/*
 * test_recv_eof_after_shutdown_wr - recv returns 0 (EOF) after peer shutdown(SHUT_WR)
 *
 *   Test 1579: After peer calls shutdown(SHUT_WR), recv on our end returns 0 (EOF).
 *   Test 1580: send after shutdown(SHUT_WR) returns EPIPE.
 *
 * These behaviors are critical for half-close semantics in network programming.
 */
static void test_recv_eof_after_shutdown_wr(void) {
    extern long sys_socketpair(int domain, int type, int protocol, int *sv);
    extern long sys_recvfrom(int sockfd, void *buf, size_t len, int flags,
                             void *src_addr, unsigned int *addrlen);
    extern long sys_sendto(int sockfd, const void *buf, size_t len, int flags,
                           const void *dest_addr, unsigned int addrlen);
    extern long sys_shutdown(int sockfd, int how);
    fut_printf("[MISC-TEST] Tests 1579-1580: recv EOF / send EPIPE after shutdown(SHUT_WR)\n");

    int sv[2];
    long sr = sys_socketpair(1 /* AF_UNIX */, 1 /* SOCK_STREAM */, 0, sv);
    if (sr < 0) {
        fut_printf("[MISC-TEST] ✗ Tests 1579-1580: socketpair failed: %ld\n", sr);
        fut_test_fail(1579);
        fut_test_fail(1580);
        return;
    }

    /* sv[0] shuts down its write side — sv[1] should see EOF */
    long sh = sys_shutdown(sv[0], 1 /* SHUT_WR */);
    if (sh < 0) {
        fut_printf("[MISC-TEST] ✗ Tests 1579-1580: shutdown failed: %ld\n", sh);
        fut_test_fail(1579);
        fut_test_fail(1580);
        sys_close(sv[0]);
        sys_close(sv[1]);
        return;
    }

    /* Test 1579: recv on sv[1] should return 0 (EOF) immediately */
    char buf[16];
    long nr = sys_recvfrom(sv[1], buf, 16, 0x40 /* MSG_DONTWAIT */, 0, 0);
    fut_printf("[MISC-TEST] Test 1579: recv after peer shutdown(SHUT_WR) returned %ld\n", nr);
    if (nr == 0) {
        fut_test_pass();
    } else {
        fut_printf("[MISC-TEST] ✗ Test 1579: expected 0 (EOF), got %ld\n", nr);
        fut_test_fail(1579);
    }

    /* Test 1580: send on sv[0] (after SHUT_WR) should return EPIPE */
    long wr = sys_sendto(sv[0], "x", 1, 0x4000 /* MSG_NOSIGNAL */, 0, 0);
    fut_printf("[MISC-TEST] Test 1580: send after shutdown(SHUT_WR) returned %ld\n", wr);
    if (wr == -32 /* -EPIPE */) {
        fut_test_pass();
    } else {
        fut_printf("[MISC-TEST] ✗ Test 1580: expected -EPIPE(-32), got %ld\n", wr);
        fut_test_fail(1580);
    }

    sys_close(sv[0]);
    sys_close(sv[1]);
}

/* ============================================================
 * test_epoll_rdhup_vs_hup - EPOLLRDHUP on half-close vs EPOLLHUP on full close
 *
 *   Test 1581: poll(POLLRDHUP) reports POLLRDHUP on peer shutdown(SHUT_WR)
 *   Test 1582: poll(POLLRDHUP) does NOT report POLLHUP on half-close
 *   Test 1583: epoll with EPOLLRDHUP reports EPOLLRDHUP on peer shutdown(SHUT_WR)
 *   Test 1584: epoll reports EPOLLHUP|EPOLLRDHUP after full peer close
 *
 * EPOLLRDHUP (Linux 2.6.17+) is critical for event-driven servers (nginx,
 * HAProxy) to distinguish graceful half-close from connection drop.
 */
static void test_epoll_rdhup_vs_hup(void) {
    extern long sys_socketpair(int domain, int type, int protocol, int *sv);
    extern long sys_shutdown(int sockfd, int how);
    extern long sys_poll(struct pollfd *fds, unsigned long nfds, int timeout);
    extern long sys_epoll_create1(int flags);
    extern long sys_epoll_ctl(int epfd, int op, int fd, void *event);
    extern long sys_epoll_wait(int epfd, void *events, int maxevents, int timeout);

    /* epoll_event: events(u32) + pad(u32) + data(u64) = 16 bytes */
    typedef struct { uint32_t events; uint32_t pad; uint64_t data; } epev_t;

    fut_printf("[MISC-TEST] Tests 1581-1584: EPOLLRDHUP half-close vs EPOLLHUP full close\n");

    int sv[2];
    long sr = sys_socketpair(1 /* AF_UNIX */, 1 /* SOCK_STREAM */, 0, sv);
    if (sr < 0) {
        fut_printf("[MISC-TEST] ✗ socketpair failed: %ld\n", sr);
        fut_test_fail(1581); fut_test_fail(1582);
        fut_test_fail(1583); fut_test_fail(1584);
        return;
    }

    /* sv[0] shuts down its write side (half-close) */
    long sh = sys_shutdown(sv[0], 1 /* SHUT_WR */);
    if (sh < 0) {
        fut_printf("[MISC-TEST] ✗ shutdown failed: %ld\n", sh);
        fut_test_fail(1581); fut_test_fail(1582);
        fut_test_fail(1583); fut_test_fail(1584);
        sys_close(sv[0]); sys_close(sv[1]);
        return;
    }

    /* Test 1581: poll(POLLRDHUP) on sv[1] should report POLLRDHUP */
    struct pollfd pfd;
    pfd.fd = sv[1];
    pfd.events = 0x2000 | 0x1;  /* POLLRDHUP | POLLIN */
    pfd.revents = 0;
    long pr = sys_poll(&pfd, 1, 0);
    fut_printf("[MISC-TEST] Test 1581: poll revents=0x%x (expect POLLRDHUP 0x2000)\n",
               (unsigned)pfd.revents);
    if (pr >= 1 && (pfd.revents & 0x2000)) {
        fut_test_pass();
    } else {
        fut_printf("[MISC-TEST] ✗ Test 1581: POLLRDHUP not set (revents=0x%x, ret=%ld)\n",
                   (unsigned)pfd.revents, pr);
        fut_test_fail(1581);
    }

    /* Test 1582: POLLHUP should NOT be set on half-close (peer only shut write) */
    fut_printf("[MISC-TEST] Test 1582: poll revents=0x%x (expect NO POLLHUP 0x10)\n",
               (unsigned)pfd.revents);
    if (!(pfd.revents & 0x10)) {
        fut_test_pass();
    } else {
        fut_printf("[MISC-TEST] ✗ Test 1582: POLLHUP wrongly set on half-close\n");
        fut_test_fail(1582);
    }

    /* Test 1583: epoll with EPOLLRDHUP on sv[1] should report EPOLLRDHUP */
    int epfd = (int)sys_epoll_create1(0);
    if (epfd < 0) {
        fut_printf("[MISC-TEST] ✗ epoll_create1 failed: %d\n", epfd);
        fut_test_fail(1583); fut_test_fail(1584);
        sys_close(sv[0]); sys_close(sv[1]);
        return;
    }
    epev_t ev = { 0x2000 | 0x1, 0, (uint64_t)sv[1] };  /* EPOLLRDHUP | EPOLLIN */
    sys_epoll_ctl(epfd, 1 /* EPOLL_CTL_ADD */, sv[1], &ev);

    epev_t out = { 0, 0, 0 };
    long er = sys_epoll_wait(epfd, &out, 1, 0);
    fut_printf("[MISC-TEST] Test 1583: epoll events=0x%x (expect EPOLLRDHUP 0x2000)\n",
               er >= 1 ? out.events : 0);
    if (er >= 1 && (out.events & 0x2000)) {
        fut_test_pass();
    } else {
        fut_printf("[MISC-TEST] ✗ Test 1583: EPOLLRDHUP not set (events=0x%x, ret=%ld)\n",
                   er >= 1 ? out.events : 0, er);
        fut_test_fail(1583);
    }

    /* Now fully close sv[0] → sv[1] should get POLLHUP */
    sys_close(sv[0]);

    /* Test 1584: After full close, epoll should report both EPOLLHUP and EPOLLRDHUP */
    out = (epev_t){ 0, 0, 0 };
    er = sys_epoll_wait(epfd, &out, 1, 0);
    fut_printf("[MISC-TEST] Test 1584: after close, epoll events=0x%x (expect HUP|RDHUP)\n",
               er >= 1 ? out.events : 0);
    if (er >= 1 && (out.events & 0x10) && (out.events & 0x2000)) {
        fut_test_pass();
    } else {
        fut_printf("[MISC-TEST] ✗ Test 1584: expected EPOLLHUP(0x10)|EPOLLRDHUP(0x2000), got 0x%x\n",
                   er >= 1 ? out.events : 0);
        fut_test_fail(1584);
    }

    sys_close(epfd);
    sys_close(sv[1]);
}

/* ============================================================
 * Tests 1585-1587: MAP_SHARED → /proc/self/maps shows 's'
 * ============================================================
 * 1585: MAP_SHARED anon mapping shows 's' in /proc/self/maps
 * 1586: MAP_PRIVATE anon mapping shows 'p' in /proc/self/maps
 * 1587: MAP_SHARED|MAP_ANONYMOUS flags preserved after mmap
 */
static void test_map_shared_procfs(void) {
    extern long sys_mmap(void *addr, size_t len, int prot, int flags, int fd, long offset);
    extern long sys_munmap(void *addr, size_t len);

#define MSP_MAP_SHARED    0x01
#define MSP_MAP_PRIVATE   0x02
#define MSP_MAP_ANON      0x20
#define MSP_PROT_RW       3

    fut_printf("[MISC-TEST] Tests 1585-1587: MAP_SHARED vs MAP_PRIVATE in /proc/self/maps\n");

    /* Create both a shared and a private anonymous mapping */
    long shared_addr = sys_mmap(NULL, 4096, MSP_PROT_RW,
                                 MSP_MAP_SHARED | MSP_MAP_ANON, -1, 0);
    if (shared_addr < 0) {
        fut_printf("[MISC-TEST] ✗ mmap(MAP_SHARED) failed: %ld\n", shared_addr);
        fut_test_fail(1585); fut_test_fail(1586); fut_test_fail(1587);
        return;
    }

    long priv_addr = sys_mmap(NULL, 4096, MSP_PROT_RW,
                               MSP_MAP_PRIVATE | MSP_MAP_ANON, -1, 0);
    if (priv_addr < 0) {
        fut_printf("[MISC-TEST] ✗ mmap(MAP_PRIVATE) failed: %ld\n", priv_addr);
        sys_munmap((void *)(uintptr_t)shared_addr, 4096);
        fut_test_fail(1585); fut_test_fail(1586); fut_test_fail(1587);
        return;
    }

    /* Read /proc/self/maps */
    int fd = fut_vfs_open("/proc/self/maps", 0 /* O_RDONLY */, 0);
    if (fd < 0) {
        fut_printf("[MISC-TEST] ✗ open /proc/self/maps: %d\n", fd);
        sys_munmap((void *)(uintptr_t)shared_addr, 4096);
        sys_munmap((void *)(uintptr_t)priv_addr, 4096);
        fut_test_fail(1585); fut_test_fail(1586); fut_test_fail(1587);
        return;
    }

    /* Read a large chunk — maps can be long */
    char buf[4096];
    long total = 0;
    long n;
    while (total < (long)sizeof(buf) - 1) {
        n = fut_vfs_read(fd, buf + total, sizeof(buf) - 1 - total);
        if (n <= 0) break;
        total += n;
    }
    fut_vfs_close(fd);
    buf[total] = '\0';

    /* Helper: convert addr to lowercase hex string (pb_hex8 uses at least 8 digits) */
    char shared_hex[17], priv_hex[17];
    unsigned long sa = (unsigned long)shared_addr;
    unsigned long pa = (unsigned long)priv_addr;

    /* Build hex string from LSB, then reverse — mirrors pb_hex8 logic */
    int sn = 0, pn = 0;
    { unsigned long w = sa; do { shared_hex[sn++] = "0123456789abcdef"[w & 0xf]; w >>= 4; } while (w); while (sn < 8) shared_hex[sn++] = '0'; }
    { unsigned long w = pa; do { priv_hex[pn++] = "0123456789abcdef"[w & 0xf]; w >>= 4; } while (w); while (pn < 8) priv_hex[pn++] = '0'; }
    /* Reverse in place */
    for (int i = 0; i < sn / 2; i++) { char t = shared_hex[i]; shared_hex[i] = shared_hex[sn-1-i]; shared_hex[sn-1-i] = t; }
    shared_hex[sn] = '\0';
    for (int i = 0; i < pn / 2; i++) { char t = priv_hex[i]; priv_hex[i] = priv_hex[pn-1-i]; priv_hex[pn-1-i] = t; }
    priv_hex[pn] = '\0';

    int found_shared = 0, found_private = 0;
    char shared_flag = '?', priv_flag = '?';

    /* Scan line by line.
     * Format: "ADDR-ADDR rw-s ..."
     * The perms field is after the second addr and a space.
     * The s/p char is the 4th character of the perms field. */
    char *line = buf;
    while (*line) {
        /* Check if this line starts with our address */
        int match_shared = 1, match_private = 1;
        for (int i = 0; i < sn && line[i]; i++) {
            if (line[i] != shared_hex[i]) match_shared = 0;
        }
        for (int i = 0; i < pn && line[i]; i++) {
            if (line[i] != priv_hex[i]) match_private = 0;
        }

        if ((match_shared || match_private) && line[sn] == '-') {
            /* Find the perms field: skip "ADDR-ADDR " */
            char *p = line;
            while (*p && *p != ' ' && *p != '\n') p++; /* skip "ADDR-ADDR" */
            if (*p == ' ') p++; /* skip space before perms */
            /* p now points to "rw-s" or "rw-p" — 4th char is s/p */
            if (p[0] && p[1] && p[2] && p[3]) {
                if (match_shared) { shared_flag = p[3]; found_shared = 1; }
                if (match_private) { priv_flag = p[3]; found_private = 1; }
            }
        }

        /* Advance to next line */
        while (*line && *line != '\n') line++;
        if (*line == '\n') line++;
    }

    /* Test 1585: shared mapping shows 's' */
    fut_printf("[MISC-TEST] Test 1585: shared mapping %s, flag='%c'\n",
               found_shared ? "found" : "NOT FOUND", shared_flag);
    if (found_shared && shared_flag == 's') {
        fut_test_pass();
    } else {
        fut_printf("[MISC-TEST] ✗ Test 1585: expected 's', got '%c' (found=%d)\n",
                   shared_flag, found_shared);
        fut_test_fail(1585);
    }

    /* Test 1586: private mapping shows 'p' */
    fut_printf("[MISC-TEST] Test 1586: private mapping %s, flag='%c'\n",
               found_private ? "found" : "NOT FOUND", priv_flag);
    if (found_private && priv_flag == 'p') {
        fut_test_pass();
    } else {
        fut_printf("[MISC-TEST] ✗ Test 1586: expected 'p', got '%c' (found=%d)\n",
                   priv_flag, found_private);
        fut_test_fail(1586);
    }

    /* Test 1587: MAP_SHARED flag is properly stored (we already proved it works
     * via procfs, but let's also verify the mapping itself is functional) */
    volatile int *shared_ptr = (volatile int *)(uintptr_t)shared_addr;
    *shared_ptr = 0xDEADBEEF;
    if (*shared_ptr == (int)0xDEADBEEF) {
        fut_printf("[MISC-TEST] ✓ Test 1587: MAP_SHARED mapping read/write works\n");
        fut_test_pass();
    } else {
        fut_printf("[MISC-TEST] ✗ Test 1587: MAP_SHARED read-back failed\n");
        fut_test_fail(1587);
    }

    sys_munmap((void *)(uintptr_t)shared_addr, 4096);
    sys_munmap((void *)(uintptr_t)priv_addr, 4096);
}

/* ============================================================
 * Tests 1588-1590: mprotect VMA splitting
 * ============================================================
 * 1588: mprotect on first page of 2-page region splits VMA
 * 1589: second page remains writable after first page made read-only
 * 1590: mprotect on middle page of 3-page region creates 3 VMAs
 */
static void test_mprotect_vma_split(void) {
    extern long sys_mmap(void *addr, size_t len, int prot, int flags, int fd, long offset);
    extern long sys_munmap(void *addr, size_t len);
    extern long sys_mprotect(void *addr, size_t len, int prot);

#define MPSPLIT_PRIVATE  0x02
#define MPSPLIT_ANON     0x20
#define MPSPLIT_PROT_RW  3   /* PROT_READ | PROT_WRITE */
#define MPSPLIT_PROT_RO  1   /* PROT_READ */

    fut_printf("[MISC-TEST] Tests 1588-1590: mprotect VMA splitting\n");

    /* Map 2 contiguous pages as RW */
    long addr2 = sys_mmap(NULL, 4096 * 2, MPSPLIT_PROT_RW,
                           MPSPLIT_PRIVATE | MPSPLIT_ANON, -1, 0);
    if (addr2 < 0) {
        fut_printf("[MISC-TEST] ✗ mmap(2 pages) failed: %ld\n", addr2);
        fut_test_fail(1588); fut_test_fail(1589); fut_test_fail(1590);
        return;
    }

    /* Touch both pages to ensure they're faulted in */
    volatile int *p1 = (volatile int *)(uintptr_t)addr2;
    volatile int *p2 = (volatile int *)(uintptr_t)(addr2 + 4096);
    *p1 = 0x11111111;
    *p2 = 0x22222222;

    /* mprotect only the first page to PROT_READ */
    long ret = sys_mprotect((void *)(uintptr_t)addr2, 4096, MPSPLIT_PROT_RO);
    if (ret != 0) {
        fut_printf("[MISC-TEST] ✗ Test 1588: mprotect returned %ld\n", ret);
        sys_munmap((void *)(uintptr_t)addr2, 4096 * 2);
        fut_test_fail(1588); fut_test_fail(1589); fut_test_fail(1590);
        return;
    }

    /* Test 1588: mprotect succeeded (VMA was split) */
    fut_printf("[MISC-TEST] ✓ Test 1588: mprotect(first page, PROT_READ) succeeded\n");
    fut_test_pass();

    /* Test 1589: second page should still be writable */
    *p2 = 0x33333333;
    if (*p2 == 0x33333333) {
        fut_printf("[MISC-TEST] ✓ Test 1589: second page still writable after partial mprotect\n");
        fut_test_pass();
    } else {
        fut_printf("[MISC-TEST] ✗ Test 1589: second page read-back failed\n");
        fut_test_fail(1589);
    }

    sys_munmap((void *)(uintptr_t)addr2, 4096 * 2);

    /* Test 1590: mprotect middle page of 3-page region.
     * Map 3 pages, mprotect middle to PROT_READ, verify /proc/self/maps
     * shows the mapping split into 3 entries. */
    long addr3 = sys_mmap(NULL, 4096 * 3, MPSPLIT_PROT_RW,
                           MPSPLIT_PRIVATE | MPSPLIT_ANON, -1, 0);
    if (addr3 < 0) {
        fut_printf("[MISC-TEST] ✗ mmap(3 pages) failed: %ld\n", addr3);
        fut_test_fail(1590);
        return;
    }

    /* Touch pages so they're faulted in */
    *(volatile int *)(uintptr_t)addr3 = 1;
    *(volatile int *)(uintptr_t)(addr3 + 4096) = 2;
    *(volatile int *)(uintptr_t)(addr3 + 8192) = 3;

    /* mprotect middle page to PROT_READ */
    ret = sys_mprotect((void *)(uintptr_t)(addr3 + 4096), 4096, MPSPLIT_PROT_RO);
    if (ret != 0) {
        fut_printf("[MISC-TEST] ✗ Test 1590: mprotect(middle) returned %ld\n", ret);
        sys_munmap((void *)(uintptr_t)addr3, 4096 * 3);
        fut_test_fail(1590);
        return;
    }

    /* Read /proc/self/maps and count entries in our 3-page range */
    int fd = fut_vfs_open("/proc/self/maps", 0, 0);
    if (fd < 0) {
        fut_printf("[MISC-TEST] ✗ Test 1590: open /proc/self/maps failed\n");
        sys_munmap((void *)(uintptr_t)addr3, 4096 * 3);
        fut_test_fail(1590);
        return;
    }

    char mapbuf[4096];
    long mtotal = 0;
    while (mtotal < (long)sizeof(mapbuf) - 1) {
        long rd = fut_vfs_read(fd, mapbuf + mtotal, sizeof(mapbuf) - 1 - mtotal);
        if (rd <= 0) break;
        mtotal += rd;
    }
    fut_vfs_close(fd);
    mapbuf[mtotal] = '\0';

    /* Build hex strings for the 3 expected VMA start addresses */
    unsigned long a0 = (unsigned long)addr3;
    unsigned long a1 = a0 + 4096;
    unsigned long a2 = a0 + 8192;
    char hex0[17], hex1[17], hex2[17];
    int n0 = 0, n1 = 0, n2 = 0;
    { unsigned long w = a0; do { hex0[n0++] = "0123456789abcdef"[w & 0xf]; w >>= 4; } while (w); while (n0 < 8) hex0[n0++] = '0'; }
    { unsigned long w = a1; do { hex1[n1++] = "0123456789abcdef"[w & 0xf]; w >>= 4; } while (w); while (n1 < 8) hex1[n1++] = '0'; }
    { unsigned long w = a2; do { hex2[n2++] = "0123456789abcdef"[w & 0xf]; w >>= 4; } while (w); while (n2 < 8) hex2[n2++] = '0'; }
    for (int i = 0; i < n0/2; i++) { char t = hex0[i]; hex0[i] = hex0[n0-1-i]; hex0[n0-1-i] = t; } hex0[n0] = '\0';
    for (int i = 0; i < n1/2; i++) { char t = hex1[i]; hex1[i] = hex1[n1-1-i]; hex1[n1-1-i] = t; } hex1[n1] = '\0';
    for (int i = 0; i < n2/2; i++) { char t = hex2[i]; hex2[i] = hex2[n2-1-i]; hex2[n2-1-i] = t; } hex2[n2] = '\0';

    /* Count how many of our 3 expected VMAs appear in the maps output */
    int vma_count = 0;
    char *ln = mapbuf;
    while (*ln) {
        int m0 = 1, m1 = 1, m2 = 1;
        for (int i = 0; i < n0 && ln[i]; i++) if (ln[i] != hex0[i]) m0 = 0;
        for (int i = 0; i < n1 && ln[i]; i++) if (ln[i] != hex1[i]) m1 = 0;
        for (int i = 0; i < n2 && ln[i]; i++) if (ln[i] != hex2[i]) m2 = 0;
        if ((m0 || m1 || m2) && ln[n0] == '-') vma_count++;
        while (*ln && *ln != '\n') ln++;
        if (*ln == '\n') ln++;
    }

    fut_printf("[MISC-TEST] Test 1590: 3-page split: found %d VMAs (expect 3)\n", vma_count);
    if (vma_count == 3) {
        fut_test_pass();
    } else {
        fut_printf("[MISC-TEST] ✗ Test 1590: expected 3 VMAs, got %d\n", vma_count);
        fut_test_fail(1590);
    }

    sys_munmap((void *)(uintptr_t)addr3, 4096 * 3);
}

/* ============================================================
 * Test 1591: mprotect VMA merge after restoring original prot
 * ============================================================
 * Split a 3-page RW region by mprotecting the middle page to RO,
 * then mprotect it back to RW. Verify the 3 VMAs merge back to 1.
 */
static void test_mprotect_vma_merge(void) {
    extern long sys_mmap(void *addr, size_t len, int prot, int flags, int fd, long offset);
    extern long sys_munmap(void *addr, size_t len);
    extern long sys_mprotect(void *addr, size_t len, int prot);

    fut_printf("[MISC-TEST] Test 1591: mprotect VMA merge after restoring prot\n");

    /* Map 3 contiguous pages as RW */
    long addr = sys_mmap(NULL, 4096 * 3, 3 /* PROT_RW */,
                          0x02 | 0x20 /* MAP_PRIVATE|MAP_ANONYMOUS */, -1, 0);
    if (addr < 0) {
        fut_printf("[MISC-TEST] ✗ mmap(3 pages) failed: %ld\n", addr);
        fut_test_fail(1591);
        return;
    }

    /* Touch all pages */
    *(volatile int *)(uintptr_t)addr = 1;
    *(volatile int *)(uintptr_t)(addr + 4096) = 2;
    *(volatile int *)(uintptr_t)(addr + 8192) = 3;

    /* Split: mprotect middle page to PROT_READ */
    sys_mprotect((void *)(uintptr_t)(addr + 4096), 4096, 1 /* PROT_READ */);

    /* Restore: mprotect middle page back to PROT_READ|PROT_WRITE */
    sys_mprotect((void *)(uintptr_t)(addr + 4096), 4096, 3 /* PROT_RW */);

    /* Count VMAs in /proc/self/maps covering our range */
    int fd = fut_vfs_open("/proc/self/maps", 0, 0);
    if (fd < 0) {
        fut_printf("[MISC-TEST] ✗ Test 1591: open /proc/self/maps failed\n");
        sys_munmap((void *)(uintptr_t)addr, 4096 * 3);
        fut_test_fail(1591);
        return;
    }
    char buf[4096];
    long total = 0;
    while (total < (long)sizeof(buf) - 1) {
        long rd = fut_vfs_read(fd, buf + total, sizeof(buf) - 1 - total);
        if (rd <= 0) break;
        total += rd;
    }
    fut_vfs_close(fd);
    buf[total] = '\0';

    /* Build hex for start addr and start+4096 and start+8192 */
    unsigned long a0 = (unsigned long)addr;
    unsigned long a1 = a0 + 4096;
    unsigned long a2 = a0 + 8192;
    char h0[17], h1[17], h2[17];
    int n0 = 0, n1 = 0, n2 = 0;
    { unsigned long w = a0; do { h0[n0++] = "0123456789abcdef"[w & 0xf]; w >>= 4; } while (w); while (n0 < 8) h0[n0++] = '0'; }
    { unsigned long w = a1; do { h1[n1++] = "0123456789abcdef"[w & 0xf]; w >>= 4; } while (w); while (n1 < 8) h1[n1++] = '0'; }
    { unsigned long w = a2; do { h2[n2++] = "0123456789abcdef"[w & 0xf]; w >>= 4; } while (w); while (n2 < 8) h2[n2++] = '0'; }
    for (int i = 0; i < n0/2; i++) { char t = h0[i]; h0[i] = h0[n0-1-i]; h0[n0-1-i] = t; } h0[n0] = '\0';
    for (int i = 0; i < n1/2; i++) { char t = h1[i]; h1[i] = h1[n1-1-i]; h1[n1-1-i] = t; } h1[n1] = '\0';
    for (int i = 0; i < n2/2; i++) { char t = h2[i]; h2[i] = h2[n2-1-i]; h2[n2-1-i] = t; } h2[n2] = '\0';

    /* Count entries starting with a0, a1, or a2 */
    int vma_count = 0;
    char *ln = buf;
    while (*ln) {
        int m0 = 1, m1 = 1, m2 = 1;
        for (int i = 0; i < n0 && ln[i]; i++) if (ln[i] != h0[i]) m0 = 0;
        for (int i = 0; i < n1 && ln[i]; i++) if (ln[i] != h1[i]) m1 = 0;
        for (int i = 0; i < n2 && ln[i]; i++) if (ln[i] != h2[i]) m2 = 0;
        if ((m0 || m1 || m2) && ln[n0] == '-') vma_count++;
        while (*ln && *ln != '\n') ln++;
        if (*ln == '\n') ln++;
    }

    fut_printf("[MISC-TEST] Test 1591: after restore, found %d VMAs (expect 1 = merged)\n", vma_count);
    if (vma_count == 1) {
        fut_test_pass();
    } else {
        fut_printf("[MISC-TEST] ✗ Test 1591: expected 1 merged VMA, got %d\n", vma_count);
        fut_test_fail(1591);
    }

    sys_munmap((void *)(uintptr_t)addr, 4096 * 3);
}

/* ============================================================
 * Tests 1592-1593: splice respects O_APPEND on output file
 * ============================================================
 * 1592: splice from pipe to O_APPEND file appends at end
 * 1593: data appears after existing content, not at offset 0
 */
static void test_splice_o_append(void) {
    extern long sys_splice(int fd_in, int64_t *off_in, int fd_out, int64_t *off_out,
                            size_t len, unsigned int flags);
    extern long sys_pipe2(int pipefd[2], int flags);

    fut_printf("[MISC-TEST] Tests 1592-1593: splice with O_APPEND output file\n");

    /* Create a file with initial content "AAAA" */
    int fd = fut_vfs_open("/splice_append_test.txt", 0x42 /* O_RDWR|O_CREAT */, 0644);
    if (fd < 0) {
        fut_printf("[MISC-TEST] ✗ create file failed: %d\n", fd);
        fut_test_fail(1592); fut_test_fail(1593);
        return;
    }
    fut_vfs_write(fd, "AAAA", 4);
    fut_vfs_close(fd);

    /* Reopen with O_APPEND */
    fd = fut_vfs_open("/splice_append_test.txt", 0x402 /* O_RDWR|O_APPEND */, 0);
    if (fd < 0) {
        fut_printf("[MISC-TEST] ✗ open O_APPEND failed: %d\n", fd);
        fut_test_fail(1592); fut_test_fail(1593);
        return;
    }

    /* Create a pipe and write "BBBB" into it */
    int pipefd[2];
    long ret = sys_pipe2(pipefd, 0);
    if (ret < 0) {
        fut_printf("[MISC-TEST] ✗ pipe2 failed: %ld\n", ret);
        fut_vfs_close(fd);
        fut_test_fail(1592); fut_test_fail(1593);
        return;
    }
    fut_vfs_write(pipefd[1], "BBBB", 4);

    /* splice from pipe to O_APPEND file */
    ret = sys_splice(pipefd[0], NULL, fd, NULL, 4, 0);
    fut_vfs_close(pipefd[0]);
    fut_vfs_close(pipefd[1]);
    fut_vfs_close(fd);

    /* Test 1592: splice succeeded */
    if (ret == 4) {
        fut_printf("[MISC-TEST] ✓ Test 1592: splice to O_APPEND file wrote 4 bytes\n");
        fut_test_pass();
    } else {
        fut_printf("[MISC-TEST] ✗ Test 1592: splice returned %ld (expected 4)\n", ret);
        fut_test_fail(1592);
    }

    /* Test 1593: verify file content is "AAAABBBB" */
    fd = fut_vfs_open("/splice_append_test.txt", 0 /* O_RDONLY */, 0);
    if (fd < 0) {
        fut_printf("[MISC-TEST] ✗ Test 1593: reopen failed: %d\n", fd);
        fut_test_fail(1593);
        return;
    }
    char buf[16];
    long n = fut_vfs_read(fd, buf, sizeof(buf) - 1);
    fut_vfs_close(fd);
    buf[n > 0 ? n : 0] = '\0';

    if (n == 8 && buf[0] == 'A' && buf[3] == 'A' && buf[4] == 'B' && buf[7] == 'B') {
        fut_printf("[MISC-TEST] ✓ Test 1593: file content is \"%s\" (appended correctly)\n", buf);
        fut_test_pass();
    } else {
        fut_printf("[MISC-TEST] ✗ Test 1593: file content is \"%s\" (expected \"AAAABBBB\")\n", buf);
        fut_test_fail(1593);
    }
}

