/* Tests 1729-1732: umask enforcement on file/directory creation (POSIX) */
/* Tests 1761-1764: SIGHUP delivery when session leader exits */
/* Tests 1765-1768: daemon lifecycle integration (setsid+chdir+devnull) */
/* Tests 1801-1804: packet filter (firewall) rules and evaluation */
__attribute__((noinline)) static void test_firewall_rules(void) {
    extern void firewall_init(void);
    extern int firewall_add_rule(int, uint8_t, uint8_t, uint32_t, uint32_t,
                                  uint32_t, uint32_t, uint16_t, uint16_t);
    extern int firewall_set_policy(int, uint8_t);
    extern int firewall_eval(int, const uint8_t *, size_t, int, int);
    extern int firewall_flush(int);

    /* Re-init to clean state */
    firewall_init();

    /* Test 1801: default policy ACCEPT allows packet */
    fut_printf("[MISC-TEST] Test 1801: default ACCEPT allows packet\n");
    {
        /* Build a minimal IP packet: proto=TCP(6), src=10.0.0.2, dst=8.8.8.8 */
        static uint8_t pkt[40];
        __builtin_memset(pkt, 0, sizeof(pkt));
        pkt[0] = 0x45;  /* IPv4, IHL=5 (20 bytes) */
        pkt[9] = 6;     /* TCP */
        pkt[12]=10; pkt[13]=0; pkt[14]=0; pkt[15]=2;   /* src 10.0.0.2 */
        pkt[16]=8; pkt[17]=8; pkt[18]=8; pkt[19]=8;     /* dst 8.8.8.8 */
        pkt[20]=0x1F; pkt[21]=0x90;  /* src port 8080 */
        pkt[22]=0x00; pkt[23]=0x50;  /* dst port 80 */

        int verdict = firewall_eval(1 /* FORWARD */, pkt, 40, 0, 0);
        if (verdict == 0 /* FW_ACCEPT */) {
            fut_printf("[MISC-TEST] ✓ Test 1801: default ACCEPT\n");
            fut_test_pass();
        } else {
            fut_printf("[MISC-TEST] ✗ Test 1801: verdict=%d\n", verdict);
            fut_test_fail(1801);
        }
    }

    /* Test 1802: DROP rule blocks matching packet */
    fut_printf("[MISC-TEST] Test 1802: DROP rule blocks packet\n");
    {
        /* Add rule: DROP TCP to 8.8.8.8 port 80 */
        firewall_add_rule(1 /* FORWARD */, 1 /* DROP */, 6 /* TCP */,
                         0, 0,                       /* any source */
                         0x08080808, 0xFFFFFFFF,     /* dst 8.8.8.8/32 */
                         80, 80);                    /* dst port 80 */

        static uint8_t pkt[40];
        __builtin_memset(pkt, 0, sizeof(pkt));
        pkt[0] = 0x45; pkt[9] = 6;
        pkt[12]=10; pkt[13]=0; pkt[14]=0; pkt[15]=2;
        pkt[16]=8; pkt[17]=8; pkt[18]=8; pkt[19]=8;
        pkt[22]=0x00; pkt[23]=0x50;  /* dst port 80 */

        int verdict = firewall_eval(1, pkt, 40, 0, 0);
        if (verdict == 1 /* FW_DROP */) {
            fut_printf("[MISC-TEST] ✓ Test 1802: DROP matched\n");
            fut_test_pass();
        } else {
            fut_printf("[MISC-TEST] ✗ Test 1802: verdict=%d\n", verdict);
            fut_test_fail(1802);
        }
    }

    /* Test 1803: non-matching packet passes DROP rule */
    fut_printf("[MISC-TEST] Test 1803: non-matching passes rule\n");
    {
        /* Same rule blocks 8.8.8.8:80, but packet goes to 1.1.1.1:443 */
        static uint8_t pkt[40];
        __builtin_memset(pkt, 0, sizeof(pkt));
        pkt[0] = 0x45; pkt[9] = 6;
        pkt[12]=10; pkt[13]=0; pkt[14]=0; pkt[15]=2;
        pkt[16]=1; pkt[17]=1; pkt[18]=1; pkt[19]=1;  /* dst 1.1.1.1 */
        pkt[22]=0x01; pkt[23]=0xBB;  /* dst port 443 */

        int verdict = firewall_eval(1, pkt, 40, 0, 0);
        if (verdict == 0 /* FW_ACCEPT */) {
            fut_printf("[MISC-TEST] ✓ Test 1803: non-match passes\n");
            fut_test_pass();
        } else {
            fut_printf("[MISC-TEST] ✗ Test 1803: verdict=%d\n", verdict);
            fut_test_fail(1803);
        }
    }

    /* Test 1804: flush clears rules, packet passes again */
    fut_printf("[MISC-TEST] Test 1804: flush restores ACCEPT\n");
    {
        firewall_flush(1 /* FORWARD */);
        static uint8_t pkt[40];
        __builtin_memset(pkt, 0, sizeof(pkt));
        pkt[0] = 0x45; pkt[9] = 6;
        pkt[16]=8; pkt[17]=8; pkt[18]=8; pkt[19]=8;
        pkt[22]=0x00; pkt[23]=0x50;

        int verdict = firewall_eval(1, pkt, 40, 0, 0);
        if (verdict == 0 /* FW_ACCEPT */) {
            fut_printf("[MISC-TEST] ✓ Test 1804: flush → ACCEPT\n");
            fut_test_pass();
        } else {
            fut_printf("[MISC-TEST] ✗ Test 1804: verdict=%d\n", verdict);
            fut_test_fail(1804);
        }
    }
}

/* Tests 1797-1800: network interface and routing table (router OS foundation) */
#include <futura/netif.h>
__attribute__((noinline)) static void test_netif_routing(void) {
    /* Test 1797: loopback interface exists after netif_init */
    fut_printf("[MISC-TEST] Test 1797: lo interface exists\n");
    {
        struct net_iface *lo = netif_by_name("lo");
        if (lo && lo->active && (lo->flags & 0x0008 /* IFF_LOOPBACK */)) {
            fut_printf("[MISC-TEST] ✓ Test 1797: lo idx=%d ip=0x%x\n",
                       lo->index, lo->ip_addr);
            fut_test_pass();
        } else {
            fut_printf("[MISC-TEST] ✗ Test 1797: lo not found\n");
            fut_test_fail(1797);
        }
    }

    /* Test 1798: route_lookup(127.0.0.1) finds loopback route */
    fut_printf("[MISC-TEST] Test 1798: route_lookup(127.0.0.1) → lo\n");
    {
        const struct net_route *rt = route_lookup(0x7F000001);
        if (rt && rt->active) {
            struct net_iface *iface = netif_by_index(rt->iface_idx);
            if (iface && iface->name[0] == 'l' && iface->name[1] == 'o') {
                fut_printf("[MISC-TEST] ✓ Test 1798: 127.0.0.1 → lo (mask=0x%x)\n",
                           rt->netmask);
                fut_test_pass();
            } else {
                fut_printf("[MISC-TEST] ✗ Test 1798: wrong iface\n");
                fut_test_fail(1798);
            }
        } else {
            fut_printf("[MISC-TEST] ✗ Test 1798: no route\n");
            fut_test_fail(1798);
        }
    }

    /* Test 1799: register eth0 interface + add default route */
    fut_printf("[MISC-TEST] Test 1799: register eth0 + default route\n");
    {
        unsigned char mac[6] = {0x52, 0x54, 0x00, 0xAA, 0xBB, 0xCC};
        int idx = netif_register("eth0", mac, 1500, NULL);
        if (idx > 0) {
            netif_set_addr(idx, 0x0A000002 /* 10.0.0.2 */,
                          0xFFFFFF00 /* 255.255.255.0 */,
                          0x0A0000FF /* 10.0.0.255 */);
            netif_set_flags(idx, 0x0001 | 0x0040 /* IFF_UP|IFF_RUNNING */);
            /* Add default route via gateway */
            route_add(0, 0, 0x0A000001 /* 10.0.0.1 gw */, idx, 100);
            /* Add connected route for 10.0.0.0/24 */
            route_add(0x0A000000, 0xFFFFFF00, 0, idx, 0);

            /* Verify route_lookup for external IP goes via eth0 */
            const struct net_route *rt = route_lookup(0x08080808 /* 8.8.8.8 */);
            if (rt && rt->gateway == 0x0A000001) {
                fut_printf("[MISC-TEST] ✓ Test 1799: 8.8.8.8 → gw 10.0.0.1\n");
                fut_test_pass();
            } else {
                fut_printf("[MISC-TEST] ✗ Test 1799: no default route\n");
                fut_test_fail(1799);
            }
        } else {
            fut_printf("[MISC-TEST] ✗ Test 1799: register failed %d\n", idx);
            fut_test_fail(1799);
        }
    }

    /* Test 1800: longest prefix match — more specific route wins */
    fut_printf("[MISC-TEST] Test 1800: longest prefix match\n");
    {
        /* 10.0.0.0/24 is more specific than default route 0.0.0.0/0 */
        const struct net_route *rt = route_lookup(0x0A000005 /* 10.0.0.5 */);
        if (rt && rt->dest == 0x0A000000 && rt->gateway == 0) {
            fut_printf("[MISC-TEST] ✓ Test 1800: 10.0.0.5 → directly connected\n");
            fut_test_pass();
        } else {
            fut_printf("[MISC-TEST] ✗ Test 1800: wrong route\n");
            fut_test_fail(1800);
        }
    }
}

/* Tests 1809-1812: ARP cache in /proc/net/arp and ICMP error generation */
__attribute__((noinline)) static void test_arp_icmp_router(void) {
    extern long sys_open(const char *, int, int);
    extern long sys_close(int);
    extern long sys_read(int, void *, size_t);
    extern int arp_add_static(uint32_t ip, const uint8_t mac[6]);
    extern int ip_forward(const void *, size_t, struct net_iface *);

    /* Test 1809: arp_add_static populates /proc/net/arp */
    fut_printf("[MISC-TEST] Test 1809: /proc/net/arp has real entries\n");
    {
        uint8_t mac[6] = {0xDE, 0xAD, 0xBE, 0xEF, 0x00, 0x01};
        arp_add_static(0xC0A80101 /* 192.168.1.1 */, mac);
    }
    {
        long fd = sys_open("/proc/net/arp", 0, 0);
        if (fd >= 0) {
            static char abuf[1024];
            long n = sys_read((int)fd, abuf, sizeof(abuf) - 1);
            sys_close((int)fd);
            if (n > 0) {
                abuf[n] = '\0';
                /* Check that the header exists and at least one entry (the static one we added) */
                bool has_header = false, has_entry = false;
                for (int i = 0; i < n - 2; i++) {
                    if (abuf[i] == 'I' && abuf[i+1] == 'P') has_header = true;
                    /* Look for "de:ad:be:ef:00:01" from our static entry */
                    if (abuf[i] == 'd' && abuf[i+1] == 'e' && abuf[i+2] == ':') has_entry = true;
                }
                if (has_header && has_entry) {
                    fut_printf("[MISC-TEST] ✓ Test 1809: /proc/net/arp has ARP entry\n");
                    fut_test_pass();
                } else {
                    fut_printf("[MISC-TEST] ✗ Test 1809: header=%d entry=%d\n", has_header, has_entry);
                    fut_test_fail(1809);
                }
            } else {
                fut_printf("[MISC-TEST] ✗ Test 1809: read=%ld\n", n);
                fut_test_fail(1809);
            }
        } else {
            fut_printf("[MISC-TEST] ✗ Test 1809: open failed\n");
            fut_test_fail(1809);
        }
    }

    /* Test 1810: ip_forward with TTL=1 returns -ETIMEDOUT */
    fut_printf("[MISC-TEST] Test 1810: ip_forward TTL=1 → ETIMEDOUT\n");
    {
        extern bool g_ip_forward_enabled;
        bool old_fwd = g_ip_forward_enabled;
        g_ip_forward_enabled = true;

        /* Build minimal IP packet: TTL=1, dest=8.8.8.8 */
        static uint8_t ip_pkt[40];
        memset(ip_pkt, 0, sizeof(ip_pkt));
        ip_pkt[0] = 0x45;  /* IPv4, IHL=5 */
        ip_pkt[2] = 0; ip_pkt[3] = 40; /* total length = 40 */
        ip_pkt[8] = 1;   /* TTL = 1 */
        ip_pkt[9] = 6;   /* Protocol = TCP */
        /* src = 10.0.0.5, dest = 8.8.8.8 */
        ip_pkt[12] = 10; ip_pkt[13] = 0; ip_pkt[14] = 0; ip_pkt[15] = 5;
        ip_pkt[16] = 8;  ip_pkt[17] = 8; ip_pkt[18] = 8; ip_pkt[19] = 8;

        int rc = ip_forward(ip_pkt, 40, NULL);
        g_ip_forward_enabled = old_fwd;

        if (rc == -110 /* ETIMEDOUT */) {
            fut_printf("[MISC-TEST] ✓ Test 1810: TTL=1 → ETIMEDOUT\n");
            fut_test_pass();
        } else {
            fut_printf("[MISC-TEST] ✗ Test 1810: rc=%d expected -110\n", rc);
            fut_test_fail(1810);
        }
    }

    /* Test 1811: ip_forward with no route returns -ENETUNREACH */
    fut_printf("[MISC-TEST] Test 1811: ip_forward no route → ENETUNREACH\n");
    {
        extern bool g_ip_forward_enabled;
        bool old_fwd = g_ip_forward_enabled;
        g_ip_forward_enabled = true;

        /* Delete default route first so 203.0.113.1 has no route */
        route_del(0, 0);

        static uint8_t ip_pkt[40];
        memset(ip_pkt, 0, sizeof(ip_pkt));
        ip_pkt[0] = 0x45;
        ip_pkt[2] = 0; ip_pkt[3] = 40;
        ip_pkt[8] = 64;  /* TTL = 64 */
        ip_pkt[9] = 17;  /* Protocol = UDP */
        ip_pkt[12] = 10; ip_pkt[13] = 0; ip_pkt[14] = 0; ip_pkt[15] = 5;
        /* dest = 203.0.113.1 — TEST-NET-3 (should have no route) */
        ip_pkt[16] = 203; ip_pkt[17] = 0; ip_pkt[18] = 113; ip_pkt[19] = 1;

        int rc = ip_forward(ip_pkt, 40, NULL);
        /* Re-add default route for other tests */
        struct net_iface *eth = netif_by_name("eth0");
        if (eth) route_add(0, 0, 0x0A000001, eth->index, 100);
        g_ip_forward_enabled = old_fwd;

        if (rc == -101 /* ENETUNREACH */) {
            fut_printf("[MISC-TEST] ✓ Test 1811: no route → ENETUNREACH\n");
            fut_test_pass();
        } else {
            fut_printf("[MISC-TEST] ✗ Test 1811: rc=%d expected -101\n", rc);
            fut_test_fail(1811);
        }
    }

    /* Test 1812: ip_forward disabled returns -EPERM */
    fut_printf("[MISC-TEST] Test 1812: ip_forward disabled → EPERM\n");
    {
        extern bool g_ip_forward_enabled;
        bool old_fwd = g_ip_forward_enabled;
        g_ip_forward_enabled = false;

        static uint8_t ip_pkt[40];
        memset(ip_pkt, 0, sizeof(ip_pkt));
        ip_pkt[0] = 0x45;
        ip_pkt[2] = 0; ip_pkt[3] = 40;
        ip_pkt[8] = 64;
        ip_pkt[12] = 10; ip_pkt[13] = 0; ip_pkt[14] = 0; ip_pkt[15] = 5;
        ip_pkt[16] = 8;  ip_pkt[17] = 8; ip_pkt[18] = 8; ip_pkt[19] = 8;

        int rc = ip_forward(ip_pkt, 40, NULL);
        g_ip_forward_enabled = old_fwd;

        if (rc == -1 /* EPERM */) {
            fut_printf("[MISC-TEST] ✓ Test 1812: disabled → EPERM\n");
            fut_test_pass();
        } else {
            fut_printf("[MISC-TEST] ✗ Test 1812: rc=%d expected -1\n", rc);
            fut_test_fail(1812);
        }
    }
}

/* Tests 1813-1816: SO_BINDTODEVICE and multi-interface SIOCGIFCONF */
__attribute__((noinline)) static void test_bindtodevice_ifconf(void) {
    extern long sys_socket(int, int, int);
    extern long sys_setsockopt(int, int, int, const void *, unsigned int);
    extern long sys_getsockopt(int, int, int, void *, unsigned int *);
    extern long sys_ioctl(int fd, unsigned long request, void *argp);
    extern long sys_close(int);

    /* Test 1813: SO_BINDTODEVICE to "lo" */
    fut_printf("[MISC-TEST] Test 1813: SO_BINDTODEVICE to lo\n");
    {
        long fd = sys_socket(2 /* AF_INET */, 2 /* SOCK_DGRAM */, 0);
        if (fd >= 0) {
            static const char dev[] = "lo";
            long rc = sys_setsockopt((int)fd, 1 /* SOL_SOCKET */, 25 /* SO_BINDTODEVICE */,
                                     dev, sizeof(dev));
            if (rc == 0) {
                /* Read back the device name */
                static char got[16];
                unsigned int got_len = sizeof(got);
                __builtin_memset(got, 0, sizeof(got));
                long rc2 = sys_getsockopt((int)fd, 1, 25, got, &got_len);
                if (rc2 == 0 && got[0] == 'l' && got[1] == 'o') {
                    fut_printf("[MISC-TEST] ✓ Test 1813: BINDTODEVICE='%s'\n", got);
                    fut_test_pass();
                } else {
                    fut_printf("[MISC-TEST] ✗ Test 1813: readback='%s' rc=%ld\n", got, rc2);
                    fut_test_fail(1813);
                }
            } else {
                fut_printf("[MISC-TEST] ✗ Test 1813: set rc=%ld\n", rc);
                fut_test_fail(1813);
            }
            sys_close((int)fd);
        } else {
            fut_printf("[MISC-TEST] ✗ Test 1813: socket=%ld\n", fd);
            fut_test_fail(1813);
        }
    }

    /* Test 1814: SO_BINDTODEVICE to nonexistent device → ENODEV */
    fut_printf("[MISC-TEST] Test 1814: BINDTODEVICE invalid → ENODEV\n");
    {
        long fd = sys_socket(2, 2, 0);
        if (fd >= 0) {
            static const char bad[] = "nosuchdev";
            long rc = sys_setsockopt((int)fd, 1, 25, bad, sizeof(bad));
            sys_close((int)fd);
            if (rc == -19 /* ENODEV */) {
                fut_printf("[MISC-TEST] ✓ Test 1814: ENODEV\n");
                fut_test_pass();
            } else {
                fut_printf("[MISC-TEST] ✗ Test 1814: rc=%ld\n", rc);
                fut_test_fail(1814);
            }
        } else { fut_test_fail(1814); }
    }

    /* Test 1815: SO_BINDTODEVICE unbind with empty string */
    fut_printf("[MISC-TEST] Test 1815: BINDTODEVICE unbind\n");
    {
        long fd = sys_socket(2, 2, 0);
        if (fd >= 0) {
            static const char lo[] = "lo";
            sys_setsockopt((int)fd, 1, 25, lo, sizeof(lo));
            /* Unbind */
            static const char empty[] = "";
            long rc = sys_setsockopt((int)fd, 1, 25, empty, 1);
            if (rc == 0) {
                static char got[16];
                unsigned int got_len = sizeof(got);
                __builtin_memset(got, 0, sizeof(got));
                sys_getsockopt((int)fd, 1, 25, got, &got_len);
                if (got[0] == '\0') {
                    fut_printf("[MISC-TEST] ✓ Test 1815: unbound\n");
                    fut_test_pass();
                } else {
                    fut_printf("[MISC-TEST] ✗ Test 1815: still='%s'\n", got);
                    fut_test_fail(1815);
                }
            } else {
                fut_printf("[MISC-TEST] ✗ Test 1815: unbind rc=%ld\n", rc);
                fut_test_fail(1815);
            }
            sys_close((int)fd);
        } else { fut_test_fail(1815); }
    }

    /* Test 1816: SIOCGIFCONF returns multiple interfaces */
    fut_printf("[MISC-TEST] Test 1816: SIOCGIFCONF multi-interface\n");
    {
        long nfd = sys_socket(2, 2, 0);
        if (nfd < 0) {
            fut_printf("[MISC-TEST] ✗ Test 1816: socket=%ld\n", nfd);
            fut_test_fail(1816);
        } else {
            /* Query: NULL buf to get needed size */
            static char conf[16]; /* struct ifconf: int len + int pad + ptr */
            __builtin_memset(conf, 0, 16);
            /* ifc_len=0, ifc_buf=NULL */
            long rc = sys_ioctl((int)nfd, 0x8912 /* SIOCGIFCONF */, conf);
            if (rc == 0) {
                int needed = 0;
                __builtin_memcpy(&needed, conf, 4);
                /* Should need space for at least 2 interfaces (lo + eth0) */
                if (needed >= 80 /* 2 * 40 */) {
                    fut_printf("[MISC-TEST] ✓ Test 1816: SIOCGIFCONF needs %d bytes (≥2 ifaces)\n", needed);
                    fut_test_pass();
                } else {
                    fut_printf("[MISC-TEST] ✗ Test 1816: only %d bytes needed\n", needed);
                    fut_test_fail(1816);
                }
            } else {
                fut_printf("[MISC-TEST] ✗ Test 1816: ioctl rc=%ld\n", rc);
                fut_test_fail(1816);
            }
            sys_close((int)nfd);
        }
    }
}

/* Tests 1817-1820: SIOCGIFHWADDR, SIOCGIFINDEX, SIOCGIFNAME, SIOCSIFMTU (real netif) */
__attribute__((noinline)) static void test_netif_ioctl_extended(void) {
    extern long sys_ioctl(int fd, unsigned long request, void *argp);
    extern long sys_open(const char *, int, int);
    extern long sys_close(int);

    long nfd = sys_open("/dev/null", 0x0002, 0);
    if (nfd < 0) {
        fut_test_fail(1817); fut_test_fail(1818); fut_test_fail(1819); fut_test_fail(1820);
        return;
    }

    /* Test 1817: SIOCGIFHWADDR on eth0 returns real MAC */
    fut_printf("[MISC-TEST] Test 1817: SIOCGIFHWADDR eth0\n");
    {
        static char ifr[40];
        __builtin_memset(ifr, 0, 40);
        __builtin_memcpy(ifr, "eth0", 4);
        long rc = sys_ioctl((int)nfd, 0x8927 /* SIOCGIFHWADDR */, ifr);
        if (rc == 0) {
            /* sa_family at offset 16 should be 1 (ARPHRD_ETHER) */
            uint16_t family = 0;
            __builtin_memcpy(&family, ifr + 16, 2);
            /* MAC at sa_data = offset 18, first byte should be 0x52 (from test registration) */
            uint8_t mac0 = (uint8_t)ifr[18];
            if (family == 1 && mac0 == 0x52) {
                fut_printf("[MISC-TEST] ✓ Test 1817: eth0 ARPHRD_ETHER mac[0]=0x52\n");
                fut_test_pass();
            } else {
                fut_printf("[MISC-TEST] ✗ Test 1817: family=%u mac0=0x%02x\n", family, mac0);
                fut_test_fail(1817);
            }
        } else {
            fut_printf("[MISC-TEST] ✗ Test 1817: rc=%ld\n", rc);
            fut_test_fail(1817);
        }
    }

    /* Test 1818: SIOCGIFINDEX on eth0 returns real index */
    fut_printf("[MISC-TEST] Test 1818: SIOCGIFINDEX eth0\n");
    {
        static char ifr[40];
        __builtin_memset(ifr, 0, 40);
        __builtin_memcpy(ifr, "eth0", 4);
        long rc = sys_ioctl((int)nfd, 0x8933 /* SIOCGIFINDEX */, ifr);
        if (rc == 0) {
            int idx = 0;
            __builtin_memcpy(&idx, ifr + 16, 4);
            struct net_iface *eth = netif_by_name("eth0");
            if (eth && idx == eth->index) {
                fut_printf("[MISC-TEST] ✓ Test 1818: eth0 index=%d\n", idx);
                fut_test_pass();
            } else {
                fut_printf("[MISC-TEST] ✗ Test 1818: idx=%d expected=%d\n",
                           idx, eth ? eth->index : -1);
                fut_test_fail(1818);
            }
        } else {
            fut_printf("[MISC-TEST] ✗ Test 1818: rc=%ld\n", rc);
            fut_test_fail(1818);
        }
    }

    /* Test 1819: SIOCGIFNAME by index returns correct name */
    fut_printf("[MISC-TEST] Test 1819: SIOCGIFNAME for lo index\n");
    {
        static char ifr[40];
        __builtin_memset(ifr, 0, 40);
        /* Set ifru_ivalue = 1 (lo index) at offset 16 */
        int lo_idx = 1;
        __builtin_memcpy(ifr + 16, &lo_idx, 4);
        long rc = sys_ioctl((int)nfd, 0x8910 /* SIOCGIFNAME */, ifr);
        if (rc == 0 && ifr[0] == 'l' && ifr[1] == 'o') {
            fut_printf("[MISC-TEST] ✓ Test 1819: idx=1 → '%s'\n", ifr);
            fut_test_pass();
        } else {
            fut_printf("[MISC-TEST] ✗ Test 1819: rc=%ld name='%s'\n", rc, ifr);
            fut_test_fail(1819);
        }
    }

    /* Test 1820: SIOCSIFMTU set + SIOCGIFMTU read back */
    fut_printf("[MISC-TEST] Test 1820: SIOCSIFMTU set and readback\n");
    {
        static char ifr[40];
        __builtin_memset(ifr, 0, 40);
        __builtin_memcpy(ifr, "eth0", 4);
        int new_mtu = 9000; /* jumbo frames */
        __builtin_memcpy(ifr + 16, &new_mtu, 4);
        long rc = sys_ioctl((int)nfd, 0x8922 /* SIOCSIFMTU */, ifr);
        if (rc == 0) {
            /* Read back */
            __builtin_memset(ifr, 0, 40);
            __builtin_memcpy(ifr, "eth0", 4);
            long rc2 = sys_ioctl((int)nfd, 0x8921 /* SIOCGIFMTU */, ifr);
            int got_mtu = 0;
            __builtin_memcpy(&got_mtu, ifr + 16, 4);
            if (rc2 == 0 && got_mtu == 9000) {
                fut_printf("[MISC-TEST] ✓ Test 1820: eth0 MTU=9000\n");
                fut_test_pass();
            } else {
                fut_printf("[MISC-TEST] ✗ Test 1820: got_mtu=%d rc2=%ld\n", got_mtu, rc2);
                fut_test_fail(1820);
            }
        } else {
            fut_printf("[MISC-TEST] ✗ Test 1820: set rc=%ld\n", rc);
            fut_test_fail(1820);
        }
    }

    sys_close((int)nfd);
}

/* Tests 1805-1808: ioctl-based interface/route configuration (SIOCSIFADDR etc.) */
__attribute__((noinline)) static void test_netif_ioctl_config(void) {
    extern long sys_ioctl(int fd, unsigned long request, void *argp);
    extern long sys_open(const char *, int, int);
    extern long sys_close(int);

    /* We need a socket fd for network ioctls. Use any fd for kernel-internal dispatch. */
    /* Futura routes SIOC* ioctls to built-in handlers regardless of fd type, */
    /* so we can use /dev/null as placeholder fd for kernel selftests. */
    long sfd = sys_open("/dev/null", 0x0002, 0);
    if (sfd < 0) {
        fut_printf("[MISC-TEST] ✗ Tests 1805-1808: can't open /dev/null\n");
        fut_test_fail(1805); fut_test_fail(1806); fut_test_fail(1807); fut_test_fail(1808);
        return;
    }

    /* ifreq struct layout: char ifr_name[16]; union { sockaddr(16), short flags, int val, pad[24] } */
    /* sockaddr layout: uint16_t sa_family; char sa_data[14]; IP at sa_data[2..5] (big-endian) */

    /* Test 1805: SIOCSIFADDR — set eth0 IP via ioctl */
    fut_printf("[MISC-TEST] Test 1805: SIOCSIFADDR on eth0\n");
    {
        /* eth0 was registered by test_netif_routing (index >0) */
        static char ifr[40];
        __builtin_memset(ifr, 0, 40);
        __builtin_memcpy(ifr, "eth0", 4); /* ifr_name */
        /* sockaddr at offset 16: sa_family=AF_INET(2), sa_data[2..5]=192.168.1.100 */
        ifr[16] = 2; ifr[17] = 0; /* sa_family = AF_INET */
        ifr[20] = (char)192; ifr[21] = (char)168; ifr[22] = 1; ifr[23] = 100;
        long rc = sys_ioctl((int)sfd, 0x8916 /* SIOCSIFADDR */, ifr);
        if (rc == 0) {
            struct net_iface *eth = netif_by_name("eth0");
            /* 192.168.1.100 = 0xC0A80164 */
            if (eth && eth->ip_addr == 0xC0A80164) {
                fut_printf("[MISC-TEST] ✓ Test 1805: eth0 ip=0x%x\n", eth->ip_addr);
                fut_test_pass();
            } else {
                fut_printf("[MISC-TEST] ✗ Test 1805: ip=0x%x expected 0xC0A80164\n",
                           eth ? eth->ip_addr : 0);
                fut_test_fail(1805);
            }
        } else {
            fut_printf("[MISC-TEST] ✗ Test 1805: SIOCSIFADDR ret=%ld\n", rc);
            fut_test_fail(1805);
        }
    }

    /* Test 1806: SIOCSIFNETMASK — set eth0 netmask via ioctl */
    fut_printf("[MISC-TEST] Test 1806: SIOCSIFNETMASK on eth0\n");
    {
        static char ifr[40];
        __builtin_memset(ifr, 0, 40);
        __builtin_memcpy(ifr, "eth0", 4);
        ifr[16] = 2; ifr[17] = 0; /* AF_INET */
        ifr[20] = (char)255; ifr[21] = (char)255; ifr[22] = (char)255; ifr[23] = 0;
        long rc = sys_ioctl((int)sfd, 0x891C /* SIOCSIFNETMASK */, ifr);
        if (rc == 0) {
            struct net_iface *eth = netif_by_name("eth0");
            /* 255.255.255.0 = 0xFFFFFF00 */
            if (eth && eth->netmask == 0xFFFFFF00) {
                fut_printf("[MISC-TEST] ✓ Test 1806: eth0 netmask=0x%x\n", eth->netmask);
                fut_test_pass();
            } else {
                fut_printf("[MISC-TEST] ✗ Test 1806: mask=0x%x\n", eth ? eth->netmask : 0);
                fut_test_fail(1806);
            }
        } else {
            fut_printf("[MISC-TEST] ✗ Test 1806: SIOCSIFNETMASK ret=%ld\n", rc);
            fut_test_fail(1806);
        }
    }

    /* Test 1807: SIOCADDRT — add route via ioctl */
    fut_printf("[MISC-TEST] Test 1807: SIOCADDRT via ioctl\n");
    {
        /* rtentry layout: 3x sockaddr (rt_dst, rt_gateway, rt_genmask) + short flags + short pad + char dev[16] */
        /* sockaddr = 16 bytes each → 48 bytes + 4 bytes (flags+pad) + 16 bytes (dev) = 68 bytes */
        static char rt[68];
        __builtin_memset(rt, 0, 68);
        /* rt_dst: 172.16.0.0 */
        rt[0] = 2; rt[1] = 0; /* AF_INET */
        rt[4] = (char)172; rt[5] = 16; rt[6] = 0; rt[7] = 0;
        /* rt_gateway: 192.168.1.1 */
        rt[16] = 2; rt[17] = 0;
        rt[20] = (char)192; rt[21] = (char)168; rt[22] = 1; rt[23] = 1;
        /* rt_genmask: 255.255.0.0 */
        rt[32] = 2; rt[33] = 0;
        rt[36] = (char)255; rt[37] = (char)255; rt[38] = 0; rt[39] = 0;
        /* rt_flags + rt_pad (4 bytes at offset 48) - leave 0 */
        /* rt_dev: "eth0" at offset 52 */
        __builtin_memcpy(rt + 52, "eth0", 4);

        long rc = sys_ioctl((int)sfd, 0x890B /* SIOCADDRT */, rt);
        if (rc == 0) {
            /* Verify: route_lookup(172.16.5.5) should find this route */
            const struct net_route *rte = route_lookup(0xAC100505 /* 172.16.5.5 */);
            if (rte && rte->dest == 0xAC100000 && rte->gateway == 0xC0A80101) {
                fut_printf("[MISC-TEST] ✓ Test 1807: 172.16.0.0/16 → gw 192.168.1.1\n");
                fut_test_pass();
            } else {
                fut_printf("[MISC-TEST] ✗ Test 1807: route not found\n");
                fut_test_fail(1807);
            }
        } else {
            fut_printf("[MISC-TEST] ✗ Test 1807: SIOCADDRT ret=%ld\n", rc);
            fut_test_fail(1807);
        }
    }

    /* Test 1808: SIOCDELRT — delete route via ioctl */
    fut_printf("[MISC-TEST] Test 1808: SIOCDELRT via ioctl\n");
    {
        static char rt[68];
        __builtin_memset(rt, 0, 68);
        /* rt_dst: 172.16.0.0 */
        rt[0] = 2; rt[1] = 0;
        rt[4] = (char)172; rt[5] = 16; rt[6] = 0; rt[7] = 0;
        /* rt_gateway: 0.0.0.0 (not used for delete) */
        rt[16] = 2; rt[17] = 0;
        /* rt_genmask: 255.255.0.0 */
        rt[32] = 2; rt[33] = 0;
        rt[36] = (char)255; rt[37] = (char)255; rt[38] = 0; rt[39] = 0;

        long rc = sys_ioctl((int)sfd, 0x890C /* SIOCDELRT */, rt);
        if (rc == 0) {
            /* Verify: 172.16.5.5 should now fall through to default route (not 172.16.0.0/16) */
            const struct net_route *rte = route_lookup(0xAC100505);
            if (!rte || rte->dest != 0xAC100000) {
                fut_printf("[MISC-TEST] ✓ Test 1808: route deleted, lookup=%p\n", (void*)rte);
                fut_test_pass();
            } else {
                fut_printf("[MISC-TEST] ✗ Test 1808: route still exists\n");
                fut_test_fail(1808);
            }
        } else {
            fut_printf("[MISC-TEST] ✗ Test 1808: SIOCDELRT ret=%ld\n", rc);
            fut_test_fail(1808);
        }
    }

    sys_close((int)sfd);
}

