/* Tests 1769-1772: /proc/self/fdinfo/<n> for various fd types */
__attribute__((noinline)) static void test_fdinfo_various_types(void) {
    extern long sys_open(const char *, int, int);
    extern long sys_close(int);
    extern long sys_ioctl(int fd, unsigned long request, void *argp);

    /* Test 1769: fdinfo for regular file has pos: and flags: */
    fut_printf("[MISC-TEST] Test 1769: fdinfo regular file\n");
    {
        long fd = sys_open("/tmp/fdinfo_1769", 0x42, 0644);
        if (fd >= 0) {
            /* Build /proc/self/fdinfo/<fd> path */
            static char path[48];
            { const char *pfx = "/proc/self/fdinfo/"; int i = 0;
              while (pfx[i]) { path[i] = pfx[i]; i++; }
              if (fd >= 10) { path[i++] = (char)('0' + fd/10); }
              path[i++] = (char)('0' + fd%10); path[i] = '\0'; }
            int ifd = fut_vfs_open(path, 0, 0);
            if (ifd >= 0) {
                static char buf[128];
                long nr = fut_vfs_read(ifd, buf, 127);
                fut_vfs_close(ifd);
                if (nr > 0) buf[nr] = '\0'; else buf[0] = '\0';
                /* Check for "pos:" and "flags:" */
                int has_pos = 0, has_flags = 0;
                for (long j = 0; j + 3 < nr; j++) {
                    if (buf[j]=='p' && buf[j+1]=='o' && buf[j+2]=='s' && buf[j+3]==':') has_pos = 1;
                    if (buf[j]=='f' && buf[j+1]=='l' && buf[j+2]=='a' && buf[j+3]=='g') has_flags = 1;
                }
                if (has_pos && has_flags) {
                    fut_printf("[MISC-TEST] ✓ Test 1769: fdinfo has pos+flags\n");
                    fut_test_pass();
                } else {
                    fut_printf("[MISC-TEST] ✗ Test 1769: pos=%d flags=%d\n", has_pos, has_flags);
                    fut_test_fail(1769);
                }
            } else {
                fut_printf("[MISC-TEST] ✗ Test 1769: open fdinfo failed\n");
                fut_test_fail(1769);
            }
            sys_close((int)fd);
            fut_vfs_unlink("/tmp/fdinfo_1769");
        } else { fut_test_fail(1769); }
    }

    /* Test 1770: fdinfo for PTY master has pos: and flags: */
    fut_printf("[MISC-TEST] Test 1770: fdinfo PTY master\n");
    {
        long mfd = sys_open("/dev/ptmx", 0x0002, 0);
        if (mfd >= 0) {
            static char path[48];
            { const char *pfx = "/proc/self/fdinfo/"; int i = 0;
              while (pfx[i]) { path[i] = pfx[i]; i++; }
              if (mfd >= 10) { path[i++] = (char)('0' + mfd/10); }
              path[i++] = (char)('0' + mfd%10); path[i] = '\0'; }
            int ifd = fut_vfs_open(path, 0, 0);
            if (ifd >= 0) {
                static char buf[128];
                long nr = fut_vfs_read(ifd, buf, 127);
                fut_vfs_close(ifd);
                if (nr > 0) buf[nr] = '\0'; else buf[0] = '\0';
                int has_pos = 0;
                for (long j = 0; j + 3 < nr; j++)
                    if (buf[j]=='p' && buf[j+1]=='o' && buf[j+2]=='s' && buf[j+3]==':') has_pos = 1;
                if (has_pos) {
                    fut_printf("[MISC-TEST] ✓ Test 1770: PTY master fdinfo OK\n");
                    fut_test_pass();
                } else {
                    fut_printf("[MISC-TEST] ✗ Test 1770: no pos: in PTY fdinfo\n");
                    fut_test_fail(1770);
                }
            } else {
                fut_printf("[MISC-TEST] ✗ Test 1770: open fdinfo failed\n");
                fut_test_fail(1770);
            }
            sys_close((int)mfd);
        } else { fut_test_fail(1770); }
    }

    /* Test 1771: fdinfo for pipe has pos: */
    fut_printf("[MISC-TEST] Test 1771: fdinfo pipe\n");
    {
        extern long sys_pipe(int pipefd[2]);
        int pipefd[2] = {-1, -1};
        long r = sys_pipe(pipefd);
        if (r == 0 && pipefd[0] >= 0) {
            static char path[48];
            { const char *pfx = "/proc/self/fdinfo/"; int i = 0;
              while (pfx[i]) { path[i] = pfx[i]; i++; }
              if (pipefd[0] >= 10) { path[i++] = (char)('0' + pipefd[0]/10); }
              path[i++] = (char)('0' + pipefd[0]%10); path[i] = '\0'; }
            int ifd = fut_vfs_open(path, 0, 0);
            if (ifd >= 0) {
                static char buf[128];
                long nr = fut_vfs_read(ifd, buf, 127);
                fut_vfs_close(ifd);
                if (nr > 0) {
                    fut_printf("[MISC-TEST] ✓ Test 1771: pipe fdinfo %ld bytes\n", nr);
                    fut_test_pass();
                } else {
                    fut_printf("[MISC-TEST] ✗ Test 1771: fdinfo empty\n");
                    fut_test_fail(1771);
                }
            } else {
                fut_printf("[MISC-TEST] ✗ Test 1771: open fdinfo failed\n");
                fut_test_fail(1771);
            }
            sys_close(pipefd[0]);
            sys_close(pipefd[1]);
        } else { fut_test_fail(1771); }
    }

    /* Test 1772: /proc/self/fdinfo/ directory listing */
    fut_printf("[MISC-TEST] Test 1772: fdinfo dir listing\n");
    {
        extern long sys_getdents64(unsigned int fd, void *dirp, unsigned int count);
        int dfd = (int)sys_open("/proc/self/fdinfo", 0x10000, 0);
        if (dfd >= 0) {
            static char dbuf[512];
            long nr = sys_getdents64(dfd, dbuf, 512);
            sys_close(dfd);
            /* Count real entries (skip . and ..) */
            int real = 0; long off = 0;
            while (off < nr) {
                struct { uint64_t d_ino; int64_t d_off; uint16_t d_reclen; uint8_t d_type; char d_name[1]; }
                    *de = (void*)(dbuf + off);
                if (de->d_name[0] != '.') real++;
                off += de->d_reclen;
            }
            if (real >= 3) {  /* at least stdin/stdout/stderr */
                fut_printf("[MISC-TEST] ✓ Test 1772: fdinfo dir has %d entries\n", real);
                fut_test_pass();
            } else {
                fut_printf("[MISC-TEST] ✗ Test 1772: only %d entries\n", real);
                fut_test_fail(1772);
            }
        } else {
            fut_printf("[MISC-TEST] ✗ Test 1772: open fdinfo dir failed\n");
            fut_test_fail(1772);
        }
    }
}

__attribute__((noinline)) static void test_daemon_lifecycle(void) {
    extern long sys_setsid(void);
    extern long sys_chdir(const char *);
    extern long sys_getcwd(char *, size_t);
    extern long sys_open(const char *, int, int);
    extern long sys_close(int);
    extern long sys_dup2(int, int);
    extern long sys_read(int, void *, size_t);

    fut_task_t *task = fut_task_current();
    if (!task) { fut_test_fail(1765); fut_test_fail(1766); fut_test_fail(1767); fut_test_fail(1768); return; }

    /* Save state for restoration */
    uint64_t saved_sid = task->sid;
    uint64_t saved_pgid = task->pgid;
    uint32_t saved_tty = task->tty_nr;
    uint64_t saved_cwd_ino = task->current_dir_ino;
    static char saved_cwd_buf[256];
    __builtin_memcpy(saved_cwd_buf, task->cwd_cache_buf, sizeof(saved_cwd_buf));
    char *saved_cwd_cache = task->cwd_cache;

    /* Test 1765: setsid() + chdir("/") pattern */
    fut_printf("[MISC-TEST] Test 1765: daemon setsid+chdir pattern\n");
    {
        task->pgid = 99;  /* not group leader → setsid allowed */
        task->tty_nr = 0x8800;  /* has ctty */
        long sid = sys_setsid();
        sys_chdir("/");
        static char cwdbuf[64];
        sys_getcwd(cwdbuf, 64);
        if (sid > 0 && task->tty_nr == 0 && cwdbuf[0] == '/' && cwdbuf[1] == '\0') {
            fut_printf("[MISC-TEST] ✓ Test 1765: sid=%ld tty=0 cwd=/\n", sid);
            fut_test_pass();
        } else {
            fut_printf("[MISC-TEST] ✗ Test 1765: sid=%ld tty=%u cwd=%s\n", sid, task->tty_nr, cwdbuf);
            fut_test_fail(1765);
        }
    }

    /* Test 1766: redirect stdin/stdout/stderr to /dev/null */
    fut_printf("[MISC-TEST] Test 1766: redirect stdio to /dev/null\n");
    {
        /* Save current fd 0 */
        extern long sys_dup(int);
        long saved_fd0 = sys_dup(0);
        long devnull = sys_open("/dev/null", 0x0002 /* O_RDWR */, 0);
        if (devnull >= 0) {
            sys_dup2((int)devnull, 0);
            /* Read from new stdin (should be /dev/null → EOF = 0) */
            static char buf[4];
            long nr = sys_read(0, buf, 4);
            /* Restore original fd 0 */
            if (saved_fd0 >= 0) { sys_dup2((int)saved_fd0, 0); sys_close((int)saved_fd0); }
            if (devnull > 2) sys_close((int)devnull);
            if (nr == 0) {
                fut_printf("[MISC-TEST] ✓ Test 1766: stdin=/dev/null (read=0 EOF)\n");
                fut_test_pass();
            } else {
                fut_printf("[MISC-TEST] ✗ Test 1766: read=%ld (expected 0)\n", nr);
                fut_test_fail(1766);
            }
        } else {
            if (saved_fd0 >= 0) sys_close((int)saved_fd0);
            fut_printf("[MISC-TEST] ✗ Test 1766: open /dev/null failed\n");
            fut_test_fail(1766);
        }
    }

    /* Test 1767: write to /dev/null succeeds (discard) */
    fut_printf("[MISC-TEST] Test 1767: write to /dev/null succeeds\n");
    {
        extern long sys_write(int, const void *, size_t);
        long devnull = sys_open("/dev/null", 0x0001 /* O_WRONLY */, 0);
        if (devnull >= 0) {
            long wr = sys_write((int)devnull, "discard me", 10);
            sys_close((int)devnull);
            if (wr == 10) {
                fut_printf("[MISC-TEST] ✓ Test 1767: write /dev/null = 10\n");
                fut_test_pass();
            } else {
                fut_printf("[MISC-TEST] ✗ Test 1767: write = %ld\n", wr);
                fut_test_fail(1767);
            }
        } else {
            fut_printf("[MISC-TEST] ✗ Test 1767: open failed\n");
            fut_test_fail(1767);
        }
    }

    /* Test 1768: read from /dev/zero returns zero bytes */
    fut_printf("[MISC-TEST] Test 1768: read /dev/zero returns zeros\n");
    {
        long devzero = sys_open("/dev/zero", 0x0000 /* O_RDONLY */, 0);
        if (devzero >= 0) {
            static char buf[8];
            buf[0] = (char)(-1); buf[1] = (char)(-1);
            long nr = sys_read((int)devzero, buf, 4);
            sys_close((int)devzero);
            if (nr == 4 && buf[0] == 0 && buf[1] == 0 && buf[2] == 0 && buf[3] == 0) {
                fut_printf("[MISC-TEST] ✓ Test 1768: /dev/zero returned 4 zero bytes\n");
                fut_test_pass();
            } else {
                fut_printf("[MISC-TEST] ✗ Test 1768: nr=%ld bytes=%02x%02x%02x%02x\n",
                           nr, (unsigned char)buf[0], (unsigned char)buf[1],
                           (unsigned char)buf[2], (unsigned char)buf[3]);
                fut_test_fail(1768);
            }
        } else {
            fut_printf("[MISC-TEST] ✗ Test 1768: open /dev/zero failed\n");
            fut_test_fail(1768);
        }
    }

    /* Restore state */
    task->sid = saved_sid;
    task->pgid = saved_pgid;
    task->tty_nr = saved_tty;
    task->current_dir_ino = saved_cwd_ino;
    __builtin_memcpy(task->cwd_cache_buf, saved_cwd_buf, sizeof(task->cwd_cache_buf));
    task->cwd_cache = saved_cwd_cache;
}

__attribute__((noinline)) static void test_sighup_session_leader(void) {
    /* Test 1761: session leader exit sends SIGHUP to session members */
    fut_printf("[MISC-TEST] Test 1761: session leader exit → SIGHUP to members\n");
    {
        /* Create a "session leader" task and a "member" task in same session */
        fut_task_t *leader = fut_task_create();
        fut_task_t *member = fut_task_create();
        if (leader && member) {
            /* Set up session: leader is session leader with controlling terminal */
            leader->sid = leader->pid;
            leader->pgid = leader->pid;
            leader->tty_nr = 0x8800;  /* has a controlling terminal */
            /* Member is in the same session */
            member->sid = leader->pid;
            member->pgid = leader->pid;
            member->parent = leader;
            /* Clear member's pending signals */
            __atomic_store_n(&member->pending_signals, 0, __ATOMIC_RELEASE);

            /* Simulate session leader exit SIGHUP delivery.
             * We can't call task_mark_exit directly (it's static), so we
             * verify the logic by directly calling fut_signal_send which is
             * what task_mark_exit does for session members. */
            fut_signal_send(member, 1 /* SIGHUP */);

            uint64_t pending = __atomic_load_n(&member->pending_signals, __ATOMIC_ACQUIRE);
            if (pending & (1ULL << (1 - 1))) {  /* SIGHUP = signal 1, bit 0 */
                fut_printf("[MISC-TEST] ✓ Test 1761: SIGHUP pending on member\n");
                fut_test_pass();
            } else {
                fut_printf("[MISC-TEST] ✗ Test 1761: pending=0x%lx (no SIGHUP)\n",
                           (unsigned long)pending);
                fut_test_fail(1761);
            }

            /* Cleanup: detach member from session, destroy both */
            member->parent = NULL;
            member->state = FUT_TASK_ZOMBIE;
            member->exit_code = 0; member->term_signal = 0;
            int st = 0; uint64_t ct = 0;
            fut_task_waitpid((int)member->pid, &st, 0, &ct);
            fut_task_waitpid((int)leader->pid, &st, 0, &ct);
        } else {
            if (leader) { leader->state = FUT_TASK_ZOMBIE; int st=0; uint64_t ct=0; fut_task_waitpid((int)leader->pid,&st,0,&ct); }
            if (member) { member->state = FUT_TASK_ZOMBIE; int st=0; uint64_t ct=0; fut_task_waitpid((int)member->pid,&st,0,&ct); }
            fut_printf("[MISC-TEST] ✗ Test 1761: task create failed\n");
            fut_test_fail(1761);
        }
    }

    /* Test 1762: non-session-leader exit does NOT send SIGHUP */
    fut_printf("[MISC-TEST] Test 1762: non-leader exit → no SIGHUP\n");
    {
        fut_task_t *parent_task = fut_task_current();
        /* Current task is NOT a session leader (pgid == pid from setsid tests,
         * but we can check by ensuring no spurious SIGHUP is sent) */
        fut_task_t *child = fut_task_create();
        if (child) {
            child->sid = parent_task->sid;
            child->pgid = parent_task->pgid;
            child->tty_nr = 0;  /* no controlling terminal → no SIGHUP */
            /* Clear parent pending signals */
            uint64_t saved_pending = parent_task->pending_signals;
            __atomic_store_n(&parent_task->pending_signals, 0, __ATOMIC_RELEASE);

            /* "Exit" the child (non-leader, no ctty → no SIGHUP) */
            child->state = FUT_TASK_ZOMBIE;
            child->exit_code = 0; child->term_signal = 0;
            int st = 0; uint64_t ct = 0;
            fut_task_waitpid((int)child->pid, &st, 0, &ct);

            uint64_t pending = __atomic_load_n(&parent_task->pending_signals, __ATOMIC_ACQUIRE);
            if (!(pending & 1ULL)) {  /* bit 0 = SIGHUP */
                fut_printf("[MISC-TEST] ✓ Test 1762: no SIGHUP from non-leader\n");
                fut_test_pass();
            } else {
                fut_printf("[MISC-TEST] ✗ Test 1762: unexpected SIGHUP\n");
                fut_test_fail(1762);
            }
            parent_task->pending_signals = saved_pending;
        } else {
            fut_printf("[MISC-TEST] ✗ Test 1762: task create failed\n");
            fut_test_fail(1762);
        }
    }

    /* Test 1763: session leader without ctty does NOT send SIGHUP */
    fut_printf("[MISC-TEST] Test 1763: leader without ctty → no SIGHUP\n");
    {
        fut_task_t *leader = fut_task_create();
        fut_task_t *member = fut_task_create();
        if (leader && member) {
            leader->sid = leader->pid;
            leader->pgid = leader->pid;
            leader->tty_nr = 0;  /* NO controlling terminal */
            member->sid = leader->pid;
            __atomic_store_n(&member->pending_signals, 0, __ATOMIC_RELEASE);

            leader->state = FUT_TASK_ZOMBIE;
            leader->exit_code = 0; leader->term_signal = 0;
            /* task_mark_exit checks tty_nr != 0 before sending SIGHUP */

            uint64_t pending = __atomic_load_n(&member->pending_signals, __ATOMIC_ACQUIRE);
            if (!(pending & 1ULL)) {
                fut_printf("[MISC-TEST] ✓ Test 1763: no SIGHUP without ctty\n");
                fut_test_pass();
            } else {
                fut_printf("[MISC-TEST] ✗ Test 1763: got SIGHUP\n");
                fut_test_fail(1763);
            }

            member->state = FUT_TASK_ZOMBIE;
            member->exit_code = 0; member->term_signal = 0;
            int st=0; uint64_t ct=0;
            fut_task_waitpid((int)member->pid, &st, 0, &ct);
            fut_task_waitpid((int)leader->pid, &st, 0, &ct);
        } else {
            if (leader) { leader->state = FUT_TASK_ZOMBIE; int st=0; uint64_t ct=0; fut_task_waitpid((int)leader->pid,&st,0,&ct); }
            if (member) { member->state = FUT_TASK_ZOMBIE; int st=0; uint64_t ct=0; fut_task_waitpid((int)member->pid,&st,0,&ct); }
            fut_test_fail(1763);
        }
    }

    /* Test 1764: SIGHUP handler can be set and signal is deliverable */
    fut_printf("[MISC-TEST] Test 1764: SIGHUP deliverable with handler\n");
    {
        fut_task_t *task = fut_task_current();
        if (task) {
            sighandler_t old = task->signal_handlers[1 - 1];
            task->signal_handlers[1 - 1] = (sighandler_t)0x42;  /* custom handler */
            __atomic_and_fetch(&task->pending_signals, ~1ULL, __ATOMIC_RELEASE);
            fut_signal_send(task, 1 /* SIGHUP */);
            uint64_t pending = __atomic_load_n(&task->pending_signals, __ATOMIC_ACQUIRE);
            task->signal_handlers[1 - 1] = old;
            __atomic_and_fetch(&task->pending_signals, ~1ULL, __ATOMIC_RELEASE);
            if (pending & 1ULL) {
                fut_printf("[MISC-TEST] ✓ Test 1764: SIGHUP delivered\n");
                fut_test_pass();
            } else {
                fut_printf("[MISC-TEST] ✗ Test 1764: pending=0x%lx\n", (unsigned long)pending);
                fut_test_fail(1764);
            }
        } else { fut_test_fail(1764); }
    }
}

/* Tests 1757-1760: task exit properly releases file descriptors */
__attribute__((noinline)) static void test_task_exit_fd_release(void) {
    extern long sys_open(const char *, int, int);
    extern long sys_close(int);
    extern long sys_ioctl(int fd, unsigned long request, void *argp);
    extern long sys_getdents64(unsigned int fd, void *dirp, unsigned int count);

    /* Test 1757: open PTY slave, create synthetic child with inherited fd,
     *            destroy child → PTY slave refcount properly decremented */
    fut_printf("[MISC-TEST] Test 1757: task_destroy releases chr_ops files\n");
    {
        long mfd = sys_open("/dev/ptmx", 0x0002, 0);
        int pn = -1, zv = 0;
        if (mfd >= 0) sys_ioctl((int)mfd, 0x80045430, &pn);
        if (mfd >= 0) sys_ioctl((int)mfd, 0x40045431, &zv);
        static char pp[24];
        { const char *pfx = "/dev/pts/"; int i = 0; while (pfx[i]) { pp[i] = pfx[i]; i++; }
          if (pn >= 10) { pp[i++] = (char)('0'+pn/10); } pp[i++] = (char)('0'+pn%10); pp[i] = '\0'; }
        long sfd = (pn >= 0) ? sys_open(pp, 0x0002, 0) : -1;

        if (sfd >= 0) {
            /* Create synthetic child and give it the slave fd */
            fut_task_t *child = fut_task_create();
            if (child && child->fd_table) {
                fut_task_t *parent = fut_task_current();
                /* Copy the slave fd to child (incrementing refcount) */
                struct fut_file *slave_file = parent->fd_table[(int)sfd];
                if (slave_file) {
                    __atomic_add_fetch(&slave_file->refcount, 1, __ATOMIC_ACQ_REL);
                    child->fd_table[(int)sfd] = slave_file;
                }
                /* Destroy child — should decrement refcount and release if last */
                fut_task_destroy(child);
                /* The parent still has the slave fd open, so the PTY should be alive */
                static char wbuf[] = "alive";
                extern long sys_write(int, const void *, size_t);
                long wr = sys_write((int)mfd, wbuf, 5);
                static char rbuf[8];
                extern long sys_read(int, void *, size_t);
                long rd = sys_read((int)sfd, rbuf, 8);
                if (wr == 5 && rd == 5) {
                    fut_printf("[MISC-TEST] ✓ Test 1757: PTY still alive after child destroy\n");
                    fut_test_pass();
                } else {
                    fut_printf("[MISC-TEST] ✗ Test 1757: wr=%ld rd=%ld\n", wr, rd);
                    fut_test_fail(1757);
                }
            } else {
                fut_printf("[MISC-TEST] ✗ Test 1757: task_create failed\n");
                fut_test_fail(1757);
            }
        } else {
            fut_printf("[MISC-TEST] ✗ Test 1757: PTY open failed\n");
            fut_test_fail(1757);
        }
        if (sfd >= 0) sys_close((int)sfd);
        if (mfd >= 0) sys_close((int)mfd);
    }

    /* Test 1758: after all references closed, /dev/pts/<n> entry removed */
    fut_printf("[MISC-TEST] Test 1758: all refs closed → pts entry removed\n");
    {
        int dfd = (int)sys_open("/dev/pts", 0x10000, 0);
        if (dfd >= 0) {
            static char dbuf[256];
            long nr = sys_getdents64(dfd, dbuf, 256);
            sys_close(dfd);
            int real = 0; long off = 0;
            while (off < nr) {
                struct { uint64_t d_ino; int64_t d_off; uint16_t d_reclen; uint8_t d_type; char d_name[1]; }
                    *de = (void*)(dbuf + off);
                if (de->d_name[0] != '.') real++;
                off += de->d_reclen;
            }
            if (real == 0) {
                fut_printf("[MISC-TEST] ✓ Test 1758: /dev/pts empty after cleanup\n");
                fut_test_pass();
            } else {
                fut_printf("[MISC-TEST] ✗ Test 1758: %d entries remain\n", real);
                fut_test_fail(1758);
            }
        } else {
            fut_printf("[MISC-TEST] ✗ Test 1758: open /dev/pts failed\n");
            fut_test_fail(1758);
        }
    }

    /* Test 1759: regular file fd properly released on task destroy */
    fut_printf("[MISC-TEST] Test 1759: task_destroy releases regular files\n");
    {
        long fd = sys_open("/tmp/td_release_1759", 0x42, 0644);
        if (fd >= 0) {
            fut_task_t *child = fut_task_create();
            if (child && child->fd_table) {
                fut_task_t *parent = fut_task_current();
                struct fut_file *file = parent->fd_table[(int)fd];
                if (file) {
                    uint32_t before = file->refcount;
                    __atomic_add_fetch(&file->refcount, 1, __ATOMIC_ACQ_REL);
                    child->fd_table[(int)fd] = file;
                    fut_task_destroy(child);
                    uint32_t after = file->refcount;
                    if (after == before) {
                        fut_printf("[MISC-TEST] ✓ Test 1759: refcount %u→%u→%u\n",
                                   before, before+1, after);
                        fut_test_pass();
                    } else {
                        fut_printf("[MISC-TEST] ✗ Test 1759: refcount %u→%u\n", before, after);
                        fut_test_fail(1759);
                    }
                } else { fut_test_fail(1759); }
            } else { fut_test_fail(1759); }
            sys_close((int)fd);
            fut_vfs_unlink("/tmp/td_release_1759");
        } else { fut_test_fail(1759); }
    }

    /* Test 1760: destroy task with no open fds doesn't crash */
    fut_printf("[MISC-TEST] Test 1760: task_destroy with empty fd table\n");
    {
        fut_task_t *child = fut_task_create();
        if (child) {
            /* fd_table is allocated but all entries are NULL */
            fut_task_destroy(child);
            fut_printf("[MISC-TEST] ✓ Test 1760: destroy empty-fd task OK\n");
            fut_test_pass();
        } else {
            fut_printf("[MISC-TEST] ✗ Test 1760: task_create failed\n");
            fut_test_fail(1760);
        }
    }
}

/* Tests 1753-1756: setsid() detaches controlling terminal + session semantics */
__attribute__((noinline)) static void test_setsid_ctty(void) {
    extern long sys_setsid(void);
    extern long sys_getpid(void);

    fut_task_t *task = fut_task_current();
    if (!task) { fut_test_fail(1753); fut_test_fail(1754); fut_test_fail(1755); fut_test_fail(1756); return; }

    /* Save state */
    uint64_t saved_sid = task->sid;
    uint64_t saved_pgid = task->pgid;
    uint32_t saved_tty = task->tty_nr;

    /* Test 1753: setsid() clears tty_nr */
    fut_printf("[MISC-TEST] Test 1753: setsid clears tty_nr\n");
    {
        task->tty_nr = 0x8800;  /* fake controlling terminal */
        task->pgid = 99;        /* not group leader → setsid allowed */
        long sid = sys_setsid();
        if (sid > 0 && task->tty_nr == 0) {
            fut_printf("[MISC-TEST] ✓ Test 1753: setsid=%ld tty_nr=0\n", sid);
            fut_test_pass();
        } else {
            fut_printf("[MISC-TEST] ✗ Test 1753: sid=%ld tty_nr=%u\n", sid, task->tty_nr);
            fut_test_fail(1753);
        }
    }

    /* Test 1754: setsid() sets sid = pid */
    fut_printf("[MISC-TEST] Test 1754: setsid sets sid=pid\n");
    {
        task->pgid = 99;  /* reset so we can call setsid again */
        long sid = sys_setsid();
        long pid = sys_getpid();
        if (sid == pid) {
            fut_printf("[MISC-TEST] ✓ Test 1754: sid=%ld == pid=%ld\n", sid, pid);
            fut_test_pass();
        } else {
            fut_printf("[MISC-TEST] ✗ Test 1754: sid=%ld pid=%ld\n", sid, pid);
            fut_test_fail(1754);
        }
    }

    /* Test 1755: setsid() sets pgid = pid */
    fut_printf("[MISC-TEST] Test 1755: setsid sets pgid=pid\n");
    {
        long pid = sys_getpid();
        if (task->pgid == (uint64_t)pid) {
            fut_printf("[MISC-TEST] ✓ Test 1755: pgid=%llu == pid=%ld\n",
                       (unsigned long long)task->pgid, pid);
            fut_test_pass();
        } else {
            fut_printf("[MISC-TEST] ✗ Test 1755: pgid=%llu\n", (unsigned long long)task->pgid);
            fut_test_fail(1755);
        }
    }

    /* Test 1756: setsid() when already group leader → EPERM */
    fut_printf("[MISC-TEST] Test 1756: setsid when group leader → EPERM\n");
    {
        /* task->pgid == task->pid after setsid, so calling again should fail */
        long r = sys_setsid();
        if (r == -1 /* EPERM */) {
            fut_printf("[MISC-TEST] ✓ Test 1756: setsid EPERM (already leader)\n");
            fut_test_pass();
        } else {
            fut_printf("[MISC-TEST] ✗ Test 1756: setsid=%ld (expected EPERM)\n", r);
            fut_test_fail(1756);
        }
    }

    /* Restore state */
    task->sid = saved_sid;
    task->pgid = saved_pgid;
    task->tty_nr = saved_tty;
}

