    /* ================================================================
     * Tests 1629-1630: faccessat AT_EACCESS uses effective UID
     *
     * AT_EACCESS tells faccessat to check using effective IDs instead
     * of real IDs.  Verify that when euid differs from ruid, AT_EACCESS
     * uses the effective UID for permission checks.
     * ================================================================ */
    {
        fut_printf("[MISC-TEST] Tests 1629-1630: faccessat AT_EACCESS uses effective UID\n");

        extern long sys_faccessat(int dirfd, const char *pathname, int mode, int flags);
        #define TEST_AT_EACCESS 0x200

        /* Test 1629: faccessat(AT_EACCESS) F_OK on /proc succeeds (basic sanity) */
        long ret = sys_faccessat(-100 /* AT_FDCWD */, "/proc", 0 /* F_OK */, TEST_AT_EACCESS);
        if (ret == 0) {
            fut_printf("[MISC-TEST] ✓ Test 1629: faccessat(AT_EACCESS, /proc, F_OK) → 0\n");
            fut_test_pass();
        } else {
            fut_printf("[MISC-TEST] ✗ Test 1629: faccessat(AT_EACCESS, /proc, F_OK) → %ld\n", ret);
            fut_test_fail(1629);
        }

        /* Test 1630: faccessat(AT_EACCESS) with euid=1000 on root-only file
         * Create a file owned by root (uid=0), then switch euid to 1000 and
         * verify that AT_EACCESS correctly uses the effective UID (1000) which
         * should NOT have write access to a mode-0700 root-owned file. */
        {
            fut_task_t *t = fut_task_current();
            /* Save original */
            uint32_t saved_euid = t->uid;
            uint32_t saved_ruid = t->ruid;

            /* Create a test file owned by root with mode 0700 */
            extern long sys_openat(int dirfd, const char *pathname, int flags, int mode);
            extern long sys_close(int fd);
            extern long sys_chmod(const char *path, uint32_t mode);
            long fd = sys_openat(-100, "/eaccess_test", 0102 /* O_CREAT|O_RDWR */, 0700);
            if (fd >= 0) sys_close((int)fd);
            sys_chmod("/eaccess_test", 0700);

            /* Set euid=1000 (non-root), keep ruid=0 (root) */
            t->uid = 1000;
            t->ruid = 0;

            /* AT_EACCESS should use euid=1000 → EACCES for W_OK on root-owned 0700 */
            ret = sys_faccessat(-100, "/eaccess_test", 2 /* W_OK */, TEST_AT_EACCESS);
            int at_eaccess_result = (int)ret;

            /* Without AT_EACCESS should use ruid=0 → success (root) */
            long ret2 = sys_faccessat(-100, "/eaccess_test", 2 /* W_OK */, 0);
            int no_eaccess_result = (int)ret2;

            /* Restore */
            t->uid = saved_euid;
            t->ruid = saved_ruid;

            if (at_eaccess_result == -EACCES && no_eaccess_result == 0) {
                fut_printf("[MISC-TEST] ✓ Test 1630: AT_EACCESS uses euid (EACCES), no flag uses ruid (OK)\n");
                fut_test_pass();
            } else {
                fut_printf("[MISC-TEST] ✗ Test 1630: AT_EACCESS=%d (exp -EACCES), no_flag=%d (exp 0)\n",
                           at_eaccess_result, no_eaccess_result);
                fut_test_fail(1630);
            }
        }
    }

    /* ============================================================
     * Tests 1631-1632: WNOWAIT leaves stopped/continued children waitable
     * ============================================================ */
    {
        fut_printf("[MISC-TEST] Tests 1631-1632: WNOWAIT preserves waitable state\n");
        extern int fut_task_waitpid_ex(int pid, int *status_out, int flags, uint32_t *uid_out);
        extern long sys_waitpid(int pid, int *status, int flags);
        extern fut_task_t *fut_task_create(void);
        extern void fut_task_do_cont(fut_task_t *task);

        /* WNOWAIT=0x01000000, WUNTRACED=2, WCONTINUED=8, WNOHANG=1 */
        #define TEST_WNOWAIT 0x01000000

        fut_task_t *child = fut_task_create();
        if (!child) {
            fut_printf("[MISC-TEST] ✗ WNOWAIT test: fut_task_create failed\n");
            fut_test_fail(1631);
            fut_test_fail(1632);
        } else {
            int cpid = (int)child->pid;

            /* Test 1631: WNOWAIT with WUNTRACED: peek at stopped child,
             * then wait again without WNOWAIT to confirm it's still waitable */
            child->state = FUT_TASK_STOPPED;
            child->stop_signal = 19; /* SIGSTOP */
            child->stop_reported = 0;

            int status = 0;
            uint32_t uid = 0;
            /* Use fut_task_waitpid_ex directly since sys_waitpid rejects WNOWAIT */
            int rc = fut_task_waitpid_ex(cpid, &status, TEST_WNOWAIT | 2 | 1, &uid);
            if (rc != cpid || !WIFSTOPPED(status)) {
                fut_printf("[MISC-TEST] ✗ Test 1631: WNOWAIT peek failed rc=%d status=0x%x\n", rc, status);
                child->state = FUT_TASK_ZOMBIE;
                child->exit_code = 0;
                child->term_signal = 0;
                sys_waitpid(cpid, &status, 0);
                fut_test_fail(1631);
            } else {
                /* Key check: stop_reported should still be 0 after WNOWAIT */
                if (child->stop_reported != 0) {
                    fut_printf("[MISC-TEST] ✗ Test 1631: WNOWAIT set stop_reported (should be 0)\n");
                    child->state = FUT_TASK_ZOMBIE;
                    child->exit_code = 0;
                    child->term_signal = 0;
                    sys_waitpid(cpid, &status, 0);
                    fut_test_fail(1631);
                } else {
                    /* Second wait without WNOWAIT should also succeed */
                    status = 0;
                    int rc2 = fut_task_waitpid_ex(cpid, &status, 2 | 1, &uid);
                    if (rc2 != cpid || !WIFSTOPPED(status)) {
                        fut_printf("[MISC-TEST] ✗ Test 1631: second wait after WNOWAIT failed rc=%d\n", rc2);
                        child->state = FUT_TASK_ZOMBIE;
                        child->exit_code = 0;
                        child->term_signal = 0;
                        sys_waitpid(cpid, &status, 0);
                        fut_test_fail(1631);
                    } else {
                        fut_printf("[MISC-TEST] ✓ Test 1631: WNOWAIT preserves stopped child waitable state\n");
                        fut_test_pass();
                    }
                }
            }

            /* Test 1632: WNOWAIT with WCONTINUED: peek at continued child */
            child->stop_reported = 0;
            child->state = FUT_TASK_STOPPED;
            child->stop_signal = 19;
            fut_task_do_cont(child);
            /* After cont: state=RUNNING, stop_signal=-1 */

            status = 0;
            rc = fut_task_waitpid_ex(cpid, &status, TEST_WNOWAIT | 8 | 1, &uid);
            if (rc != cpid || !WIFCONTINUED(status)) {
                fut_printf("[MISC-TEST] ✗ Test 1632: WNOWAIT continued peek failed rc=%d status=0x%x\n", rc, status);
                child->state = FUT_TASK_ZOMBIE;
                child->exit_code = 0;
                child->term_signal = 0;
                sys_waitpid(cpid, &status, 0);
                fut_test_fail(1632);
            } else {
                /* Key check: stop_signal should still be -1 (not cleared) */
                if (child->stop_signal != -1) {
                    fut_printf("[MISC-TEST] ✗ Test 1632: WNOWAIT cleared stop_signal (should be -1)\n");
                    child->state = FUT_TASK_ZOMBIE;
                    child->exit_code = 0;
                    child->term_signal = 0;
                    sys_waitpid(cpid, &status, 0);
                    fut_test_fail(1632);
                } else {
                    /* Second wait without WNOWAIT should also succeed */
                    status = 0;
                    int rc2 = fut_task_waitpid_ex(cpid, &status, 8 | 1, &uid);
                    if (rc2 != cpid || !WIFCONTINUED(status)) {
                        fut_printf("[MISC-TEST] ✗ Test 1632: second wait after WNOWAIT failed rc=%d\n", rc2);
                        child->state = FUT_TASK_ZOMBIE;
                        child->exit_code = 0;
                        child->term_signal = 0;
                        sys_waitpid(cpid, &status, 0);
                        fut_test_fail(1632);
                    } else {
                        fut_printf("[MISC-TEST] ✓ Test 1632: WNOWAIT preserves continued child waitable state\n");
                        fut_test_pass();
                    }
                }
            }

            /* Clean up: reap child */
            child->state = FUT_TASK_ZOMBIE;
            child->exit_code = 0;
            child->term_signal = 0;
            status = 0;
            sys_waitpid(cpid, &status, 0);
        }

        #undef TEST_WNOWAIT
    }

    /* ============================================================
     * Test 1633: mremap rejects old_size spanning VMA boundary
     * ============================================================ */
    {
        fut_printf("[MISC-TEST] Test 1633: mremap rejects region spanning VMA boundary\n");
        extern long sys_mmap(void *addr, size_t length, int prot, int flags, int fd, long offset);
        extern long sys_mremap(void *old_address, size_t old_size, size_t new_size,
                               int flags, void *new_address);
        extern long sys_munmap(void *addr, size_t length);

        /* Map two separate 4KB pages with a gap between them */
        long p1 = sys_mmap(NULL, 4096, 3 /* PROT_READ|PROT_WRITE */,
                           0x22 /* MAP_PRIVATE|MAP_ANONYMOUS */, -1, 0);
        if (p1 < 0) {
            fut_printf("[MISC-TEST] ✗ Test 1633: mmap p1 failed %ld\n", p1);
            fut_test_fail(1633);
        } else {
            /* Try to mremap with old_size=8192 on a 4096-byte mapping.
             * This should fail because the region extends beyond the VMA. */
            long ret = sys_mremap((void *)(uintptr_t)p1, 8192, 4096, 0, NULL);
            sys_munmap((void *)(uintptr_t)p1, 4096);
            if (ret == -EFAULT) {
                fut_printf("[MISC-TEST] ✓ Test 1633: mremap rejects oversized old_size (EFAULT)\n");
                fut_test_pass();
            } else {
                fut_printf("[MISC-TEST] ✗ Test 1633: mremap oversized old_size returned %ld (expected -EFAULT)\n", ret);
                if (ret > 0) sys_munmap((void *)(uintptr_t)ret, 4096);
                fut_test_fail(1633);
            }
        }
    }

    /* ============================================================
     * Tests 1634-1635: FUTEX_WAIT_BITSET / FUTEX_WAKE_BITSET reject bitset=0
     * ============================================================ */
    {
        fut_printf("[MISC-TEST] Tests 1634-1635: futex bitset=0 returns EINVAL\n");
        extern long sys_futex(uint32_t *uaddr, int futex_op, uint32_t val,
                              const void *timeout, uint32_t *uaddr2, uint32_t val3);

        uint32_t futex_var = 42;

        /* Test 1634: FUTEX_WAIT_BITSET with bitset=0 → EINVAL */
        /* FUTEX_WAIT_BITSET=9, FUTEX_PRIVATE_FLAG=128 */
        long ret = sys_futex(&futex_var, 9 | 128, 42, NULL, NULL, 0);
        if (ret == -EINVAL) {
            fut_printf("[MISC-TEST] ✓ Test 1634: FUTEX_WAIT_BITSET(bitset=0) → EINVAL\n");
            fut_test_pass();
        } else {
            fut_printf("[MISC-TEST] ✗ Test 1634: FUTEX_WAIT_BITSET(bitset=0) returned %ld\n", ret);
            fut_test_fail(1634);
        }

        /* Test 1635: FUTEX_WAKE_BITSET with bitset=0 → EINVAL */
        /* FUTEX_WAKE_BITSET=10, FUTEX_PRIVATE_FLAG=128 */
        ret = sys_futex(&futex_var, 10 | 128, 1, NULL, NULL, 0);
        if (ret == -EINVAL) {
            fut_printf("[MISC-TEST] ✓ Test 1635: FUTEX_WAKE_BITSET(bitset=0) → EINVAL\n");
            fut_test_pass();
        } else {
            fut_printf("[MISC-TEST] ✗ Test 1635: FUTEX_WAKE_BITSET(bitset=0) returned %ld\n", ret);
            fut_test_fail(1635);
        }
    }

    /*
     * Tests 1636-1638: epoll maxevents and EPOLLERR/EPOLLHUP fixes
     */
    {
        /* Packed epoll_event matching kernel layout */
        typedef struct { uint32_t events; uint64_t data; } __attribute__((packed)) epev_t;

        /* Test 1636: epoll_wait accepts maxevents > MAX_EPOLL_FDS (64).
         * Linux only requires maxevents > 0; Futura was rejecting > 64. */
        long epfd = sys_epoll_create1(0);
        if (epfd >= 0) {
            epev_t ev;
            long ret = sys_epoll_wait((int)epfd, &ev, 128, 0);
            if (ret == 0) {
                fut_printf("[MISC-TEST] ✓ Test 1636: epoll_wait(maxevents=128) accepted\n");
                fut_test_pass();
            } else {
                fut_printf("[MISC-TEST] ✗ Test 1636: epoll_wait(maxevents=128) returned %ld\n", ret);
                fut_test_fail(1636);
            }
            sys_close((int)epfd);
        } else {
            fut_printf("[MISC-TEST] ✗ Test 1636: epoll_create1 failed %ld\n", epfd);
            fut_test_fail(1636);
        }

        /* Test 1637: epoll_wait caps returned events at maxevents.
         * Create 2 pipes, add both read ends, but request maxevents=1.
         * Should return exactly 1 event even though 2 fds are ready. */
        {
            int pipe1[2], pipe2[2];
            extern long sys_pipe2(int pipefd[2], int flags);
            long r1 = sys_pipe2(pipe1, 0);
            long r2 = sys_pipe2(pipe2, 0);
            if (r1 == 0 && r2 == 0) {
                extern long sys_write(int fd, const void *buf, unsigned long count);
                char byte = 'X';
                sys_write(pipe1[1], &byte, 1);
                sys_write(pipe2[1], &byte, 1);

                long ep = sys_epoll_create1(0);
                if (ep >= 0) {
                    epev_t ev1 = { .events = 0x001 /* EPOLLIN */, .data = (uint64_t)pipe1[0] };
                    epev_t ev2 = { .events = 0x001, .data = (uint64_t)pipe2[0] };
                    sys_epoll_ctl((int)ep, 1, pipe1[0], &ev1);
                    sys_epoll_ctl((int)ep, 1, pipe2[0], &ev2);

                    epev_t out[2];
                    long n = sys_epoll_wait((int)ep, out, 1, 0);
                    if (n == 1) {
                        fut_printf("[MISC-TEST] ✓ Test 1637: epoll_wait(maxevents=1) capped at 1\n");
                        fut_test_pass();
                    } else {
                        fut_printf("[MISC-TEST] ✗ Test 1637: returned %ld (expected 1)\n", n);
                        fut_test_fail(1637);
                    }
                    sys_close((int)ep);
                } else {
                    fut_printf("[MISC-TEST] ✗ Test 1637: epoll_create1 failed\n");
                    fut_test_fail(1637);
                }
                sys_close(pipe1[0]); sys_close(pipe1[1]);
                sys_close(pipe2[0]); sys_close(pipe2[1]);
            } else {
                fut_printf("[MISC-TEST] ✗ Test 1637: pipe2 failed\n");
                fut_test_fail(1637);
            }
        }

        /* Test 1638: EPOLLHUP reported even when not in requested events mask.
         * Create a pipe, close write end, watch read end with only EPOLLOUT.
         * Should still get EPOLLHUP in returned events. */
        {
            int pfds[2];
            extern long sys_pipe2(int pipefd[2], int flags);
            long pr = sys_pipe2(pfds, 0);
            if (pr == 0) {
                sys_close(pfds[1]);  /* Close write end → EPOLLHUP on read end */

                long ep = sys_epoll_create1(0);
                if (ep >= 0) {
                    epev_t ev = { .events = 0x004 /* EPOLLOUT */, .data = (uint64_t)pfds[0] };
                    sys_epoll_ctl((int)ep, 1, pfds[0], &ev);

                    epev_t out;
                    long n = sys_epoll_wait((int)ep, &out, 1, 0);
                    if (n == 1 && (out.events & 0x010 /* EPOLLHUP */)) {
                        fut_printf("[MISC-TEST] ✓ Test 1638: EPOLLHUP reported without being in mask\n");
                        fut_test_pass();
                    } else {
                        fut_printf("[MISC-TEST] ✗ Test 1638: n=%ld events=0x%x (expected EPOLLHUP)\n",
                                   n, n > 0 ? out.events : 0);
                        fut_test_fail(1638);
                    }
                    sys_close((int)ep);
                } else {
                    fut_printf("[MISC-TEST] ✗ Test 1638: epoll_create1 failed\n");
                    fut_test_fail(1638);
                }
                sys_close(pfds[0]);
            } else {
                fut_printf("[MISC-TEST] ✗ Test 1638: pipe2 failed\n");
                fut_test_fail(1638);
            }
        }
    }

    /*
     * Test 1639: mprotect rejects range with unmapped gap
     * Map two non-adjacent pages, then mprotect the entire span.
     * The gap in the middle should cause -ENOMEM.
     */
    {
        extern long sys_mmap(void *addr, size_t length, int prot, int flags, int fd, long offset);
        extern long sys_munmap(void *addr, size_t length);
        extern long sys_mprotect(void *addr, size_t len, int prot);

        /* Map 3 contiguous pages, then unmap the middle one to create a gap */
        void *base = (void *)sys_mmap(NULL, 3 * 4096, 3 /* PROT_READ|PROT_WRITE */,
                                       0x22 /* MAP_PRIVATE|MAP_ANONYMOUS */, -1, 0);
        if ((long)base > 0) {
            /* Unmap the middle page to create a gap */
            long ur = sys_munmap((void *)((uintptr_t)base + 4096), 4096);
            if (ur == 0) {
                /* mprotect across the gap: [page0, gap, page2] → should fail */
                long mr = sys_mprotect(base, 3 * 4096, 1 /* PROT_READ */);
                if (mr == -ENOMEM) {
                    fut_printf("[MISC-TEST] ✓ Test 1639: mprotect rejects range with gap (ENOMEM)\n");
                    fut_test_pass();
                } else {
                    fut_printf("[MISC-TEST] ✗ Test 1639: mprotect returned %ld (expected -ENOMEM)\n", mr);
                    fut_test_fail(1639);
                }
            } else {
                fut_printf("[MISC-TEST] ✗ Test 1639: munmap middle page failed %ld\n", ur);
                fut_test_fail(1639);
            }
            /* Clean up remaining pages */
            sys_munmap(base, 4096);
            sys_munmap((void *)((uintptr_t)base + 2 * 4096), 4096);
        } else {
            fut_printf("[MISC-TEST] ✗ Test 1639: mmap failed %ld\n", (long)base);
            fut_test_fail(1639);
        }
    }

    /*
     * Test 1640: signalfd populates ssi_code and ssi_pid from siginfo_t
     * Send SIGUSR1 via kill(), verify ssi_code=SI_USER(0) and ssi_pid=self.
     */
    {
        extern long sys_signalfd4(int ufd, const void *mask, size_t sizemask, int flags);
        extern long sys_kill(int pid, int sig);
        extern long sys_read(int fd, void *buf, size_t count);
        extern long sys_getpid(void);

        uint64_t mask = 1ULL << (10 - 1);  /* SIGUSR1 = 10 */
        int sfd = (int)sys_signalfd4(-1, &mask, sizeof(mask), 0x800 /* SFD_NONBLOCK */);
        if (sfd >= 0) {
            long pid = sys_getpid();
            sys_kill((int)pid, 10);

            struct test_signalfd_siginfo info;
            __builtin_memset(&info, 0, sizeof(info));
            long n = sys_read(sfd, &info, sizeof(info));
            fut_vfs_close(sfd);

            if (n == (long)sizeof(info) &&
                info.ssi_signo == 10 &&
                info.ssi_code == 0 /* SI_USER */ &&
                info.ssi_pid == (unsigned int)pid) {
                fut_printf("[MISC-TEST] ✓ Test 1640: signalfd ssi_code=%d ssi_pid=%u correct\n",
                           info.ssi_code, info.ssi_pid);
                fut_test_pass();
            } else {
                fut_printf("[MISC-TEST] ✗ Test 1640: n=%ld signo=%u code=%d pid=%u (expected code=0 pid=%ld)\n",
                           n, info.ssi_signo, info.ssi_code, info.ssi_pid, pid);
                fut_test_fail(1640);
            }
        } else {
            fut_printf("[MISC-TEST] ✗ Test 1640: signalfd4 failed %d\n", sfd);
            fut_test_fail(1640);
        }
    }

    /*
     * Test 1641: RUSAGE_CHILDREN includes context switches from reaped child.
     * Create a zombie child with known context_switches, reap it, then
     * verify getrusage(RUSAGE_CHILDREN) has non-zero ru_nvcsw.
     */
    {
        /* Full rusage struct — ru_nvcsw is at offset 128 (field 16 counting longs) */
        typedef struct {
            long long utime_sec, utime_usec;   /* ru_utime */
            long long stime_sec, stime_usec;   /* ru_stime */
            long ru_maxrss;
            long ru_ixrss, ru_idrss, ru_isrss;
            long ru_minflt, ru_majflt, ru_nswap;
            long ru_inblock, ru_oublock;
            long ru_msgsnd, ru_msgrcv, ru_nsignals;
            long ru_nvcsw, ru_nivcsw;
        } full_ru_t;

        extern long sys_getrusage(int who, void *rusage);
        extern long sys_waitpid(int pid, int *status, int flags);

        /* Snapshot RUSAGE_CHILDREN before */
        full_ru_t ru_before;
        __builtin_memset(&ru_before, 0, sizeof(ru_before));
        sys_getrusage(-1 /* RUSAGE_CHILDREN */, &ru_before);

        /* Create zombie child with 50 context switches (accumulated from grandchildren) */
        fut_task_t *child = fut_task_create();
        if (child) {
            child->state = FUT_TASK_ZOMBIE;
            child->exit_code = 0;
            child->child_context_switches = 50;  /* as if child already reaped grandchildren */

            int status = 0;
            long pid = sys_waitpid((int)child->pid, &status, 0);
            if (pid > 0) {
                full_ru_t ru_after;
                __builtin_memset(&ru_after, 0, sizeof(ru_after));
                sys_getrusage(-1, &ru_after);

                long delta_nvcsw = ru_after.ru_nvcsw - ru_before.ru_nvcsw;
                if (delta_nvcsw >= 50) {
                    fut_printf("[MISC-TEST] ✓ Test 1641: RUSAGE_CHILDREN nvcsw delta=%ld\n", delta_nvcsw);
                    fut_test_pass();
                } else {
                    fut_printf("[MISC-TEST] ✗ Test 1641: nvcsw delta=%ld (expected >=50)\n", delta_nvcsw);
                    fut_test_fail(1641);
                }
            } else {
                fut_printf("[MISC-TEST] ✗ Test 1641: waitpid failed %ld\n", pid);
                fut_test_fail(1641);
            }
        } else {
            fut_printf("[MISC-TEST] ✗ Test 1641: fut_task_create failed\n");
            fut_test_fail(1641);
        }
    }

    /*
     * Test 1642: brk() enforces RLIMIT_AS (address-space limit).
     * Set a small RLIMIT_AS, attempt to expand brk beyond it, expect ENOMEM.
     */
    {
        extern long sys_brk(uintptr_t new_break);

        /* Save current RLIMIT_AS */
        struct { uint64_t cur; uint64_t max; } old_as, new_as;
        sys_prlimit64(0, 9 /* RLIMIT_AS */, NULL, &old_as);

        /* Query current break */
        long cur_brk = sys_brk(0);

        /* Set RLIMIT_AS to current_vsize + 4096 (barely any room to grow) */
        new_as.cur = (uint64_t)cur_brk + 4096;
        new_as.max = old_as.max;
        sys_prlimit64(0, 9, &new_as, NULL);

        /* Try expanding brk by 1MB — should fail with ENOMEM */
        long big_brk = sys_brk((uintptr_t)cur_brk + 1048576);

        /* Restore original RLIMIT_AS */
        sys_prlimit64(0, 9, &old_as, NULL);

        if (big_brk == -ENOMEM) {
            fut_printf("[MISC-TEST] ✓ Test 1642: brk rejects expansion exceeding RLIMIT_AS\n");
            fut_test_pass();
        } else {
            fut_printf("[MISC-TEST] ✗ Test 1642: brk returned %ld (expected -ENOMEM=%d)\n",
                       big_brk, -ENOMEM);
            fut_test_fail(1642);
            /* Shrink back if brk succeeded */
            if (big_brk > 0)
                sys_brk((uintptr_t)cur_brk);
        }
    }

